export const SUBJECT = "Fizyoloji";
export const QUESTIONS = [{"id":1,"ders":"Fizyoloji","konu":"Hücre Histolojisi ve Fizyolojisi","diff":5,"q":"I-cell (İnklüzyon cisimciği) hastalığında, Golgi aygıtında lizozomal enzimlerin hedeflenmesinden sorumlu olan ve eksikliği hücresel düzeyde enzimlerin lizozom yerine ekstraselüler alana salgılanmasına yol açan enzim aşağıdakilerden hangisidir?","options":["N-asetilglukozaminil-1-fosfotransferaz","Sfingomiyelinaz","Glukoserebrozidaz","Asit alfa-glukozidaz","Hekzozaminidaz A"],"correct":0,"exp":"I-cell hastalığında cis-Golgi'de lizozomal enzimlere mannoz-6-fosfat eklentisini yapan N-asetilglukozaminil-1-fosfotransferaz enzimi eksiktir. Bu spesifik sinyal (M6P) olmaksızın hidrolitik enzimler lizozoma yönlendirilemez ve hücre dışına atılır."},{"id":2,"ders":"Fizyoloji","konu":"Doku Histolojisi ve Fizyolojisi","diff":5,"q":"Böbrek Henle kulbunun çıkan kalın kolunda parasellüler magnezyum ve kalsiyum geçişini düzenleyen; mutasyonu Ailesel Hipomagnezemi ile Hiperkalsiüri (FHHNC) sendromuna yol açan intersellüler bağlantı (zonula okludens) proteini aşağıdakilerden hangisidir?","options":["Klaudin-16","Konneksin-26","Desmoglein-1","İntegrin alfa-6","Okludin"],"correct":0,"exp":"Klaudin-16 (Parasellin-1), tight junction (zonula okludens) yapısına katılan ve böbreklerde parasellüler Mg+2 ve Ca+2 geri emilimini düzenleyen spesifik bir proteindir. Mutasyonunda böbreklerden magnezyum israfı görülür."},{"id":3,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":4,"q":"İskelet kası sarkomerinde ince filamentlerin (aktin) etrafına sarılarak onların tam uzunluğunu belirleyen ve Z çizgisine tutunmasını stabilize eden regülatör/yapısal dev protein aşağıdakilerden hangisidir?","options":["Titin","Nebulin","Distrofin","Tropomiyozin","Troponin T"],"correct":1,"exp":"Nebulin, ince (aktin) filamentlere sarılarak onların uzunluğunu regüle eden, adeta bir moleküler 'cetvel' görevi gören ve Z çizgisine tutunmalarına yardımcı olan yapısal proteindir. Titin (kalın filamentleri regüle eden) ile karıştırılmamalıdır."},{"id":4,"ders":"Fizyoloji","konu":"Genital Sistem HistoFizyolojisi","diff":5,"q":"Testiste kan-testis bariyerini oluşturan Sertoli-Sertoli hücreleri arasındaki sıkı bağlantı kompleksleri (tight junctions), mayoz bölünme sürecindeki hangi germ hücresinin bazal kompartımandan adluminal kompartımana geçişine izin vermek için geçici olarak açılır?","options":["Tip A spermatogonyum","Tip B spermatogonyum","Preleptoten primer spermatosit","Sekonder spermatosit","Geç spermatid"],"correct":2,"exp":"Kan-testis bariyeri dinamik bir yapıdır. Mayoz I'e yeni girecek olan 'preleptoten evresindeki primer spermatositlerin' adluminal bölgeye güvenle geçmesi için Sertoli hücre bağlantıları aşağıdan açılıp, hücre geçtikten sonra yukarıdan kapanır."},{"id":5,"ders":"Fizyoloji","konu":"Genel Embriyoloji","diff":4,"q":"Embriyolojik gelişim sürecinde epiblast hücrelerinin primitif çizgi boyunca invajinasyonu ile oluşan; ektoderm, mezoderm ve endodermin (3 germ yaprağının) farklılaşmasıyla karakterize gastrulasyon evresi embriyonik gelişimin kaçıncı haftasında başlar?","options":["1. hafta","2. hafta","3. hafta","4. hafta","5. hafta"],"correct":2,"exp":"Gastrulasyon (primitif çizginin oluşumu ve üçlü embriyonik diskin meydana gelmesi) embriyolojik gelişimin 3. haftasının en karakteristik ve kritik olayıdır."},{"id":6,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":5,"q":"Lenf düğümü parakortikal bölgesinde yer alan ve naif T lenfositlerin dolaşımdan diapedez ile lenf düğümüne geçişini (homing) sağlayan yüksek endotelli venüller (HEV), lenfositlerdeki L-Selektin'e bağlanmak için yüzeylerinde hangi spesifik adezyon molekülünü eksprese eder?","options":["PNAd (Periferal Nod Adressin)","E-Kaderin","İntegrin alfa-4-beta-7","CD31 (PECAM-1)","VCAM-1"],"correct":0,"exp":"HEV endotel hücreleri L-Selektin ligandı olan PNAd (Periferal Nod Adressin) adı verilen karbonhidrat zengini proteinleri eksprese eder. Bu molekül dolaşımdaki naif T hücrelerinin L-selektini tarafından tanınarak spesifik homing işlemini başlatır."},{"id":7,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":4,"q":"Mide fundus bezlerinde yerleşmiş olan, gastrin ve vagal uyarı sonrası parakrin yolla histamin salgılayarak paryetal hücrelerin asit sekresyonunu (H2 reseptörleri üzerinden) güçlü bir şekilde stimüle eden hücre tipi aşağıdakilerden hangisidir?","options":["G hücreleri","D hücreleri","Enterokromafin-benzeri (ECL) hücreler","Paneth hücreleri","Şef hücreleri"],"correct":2,"exp":"ECL (Enterokromafin-benzeri) hücreler, midenin oksintik (fundik) bezlerinde bulunur ve histamin deposudurlar. Asit sekresyonunun ana stimülatör aksı Gastrin -> ECL hücresi -> Histamin -> Paryetal hücre (H2 reseptörü) şeklindedir."},{"id":8,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"Ventriküler miyositlerde aksiyon potansiyelinde plato fazının (Faz 2) oluşumundan ve eksitasyon-kontraksiyon eşleşmesini başlatarak sarkoplazmik retikulumdan 'kalsiyumun tetiklediği kalsiyum salınımını' sağlayan iyon kanalı aşağıdakilerden hangisidir?","options":["T-tipi Kalsiyum kanalı","L-tipi Kalsiyum kanalı (DHP reseptörü)","KATP kanalı","HCN (Funny) kanalı","Na-Ca değiştirici (NCX)"],"correct":1,"exp":"Faz 2'de hücre dışından yavaş kalsiyum girişini sağlayan kanallar L-tipi (Long-lasting) kalsiyum kanallarıdır (Dihidropiridin reseptörleri). Bu yavaş Ca+2 girişi, hücre içindeki ryanodin reseptörlerini aktive ederek kontraksiyonu başlatır."},{"id":9,"ders":"Fizyoloji","konu":"Endokrin ve Genital Sistem HistoFizyolojisi","diff":4,"q":"Adrenal kortekste en kalın tabaka olan zona fasikülata'da yer alan, steroidogenez (glukokortikoid sentezi) için bol miktarda lipid (kolesterol damlacıkları) içerdiği için rutin histolojik preparasyonlarda hücre sitoplazması köpüksü-süngerimsi görünen hücrelere ne ad verilir?","options":["Kromafin hücreler","Spongiyositler","Pituasitler","Parafolliküler hücreler","Leydig hücreleri"],"correct":1,"exp":"Zona fasikülata hücreleri lipitten çok zengin olduğu için doku takibi sırasında lipidler eridiğinde hücreler açık renkli ve sünger gibi görünür. Bu nedenle bu hücrelere spesifik olarak 'Spongiyosit' adı verilir."},{"id":10,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"Terminal ve respiratuar bronşiyol epitelinde yer alan, silikapsız, apikal yüzeyleri kubbe şeklinde olan; glikozaminoglikan, sörfaktan apoproteinleri ve anti-enflamatuar CC16 proteini salgılayıp sitokrom P450 enzimleri ile detoksifikasyon yapan hücre hangisidir?","options":["Tip 1 Pnömosit","Goblet hücresi","Kulçitski (K) hücresi","Club (Clara) hücresi","Fırçamsı (Brush) hücre"],"correct":3,"exp":"Club (eski adıyla Clara) hücreleri, bronşiyollerin karakteristik hücreleridir. Klor sekresyonu yaparlar, kök hücre potansiyelleri vardır, CC16 salgılarlar ve CYP450 enzimleri aracılığıyla solunan toksinleri nötralize ederler."},{"id":11,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"Merkezi sinir sisteminde doku hasarı veya demiyelinizan hastalıklar sonrasında hipertrofiye/hiperplaziye uğrayarak skar dokusu (gliozis) oluşturan ve perivasküler ayakçıkları (pedikül) ile kan-beyin bariyerini destekleyen nöroglial hücre aşağıdakilerden hangisidir?","options":["Oligodendrosit","Mikroglia","Astrosit","Ependim hücresi","Schwann hücresi"],"correct":2,"exp":"Astrositler, MSS'nin yapısal destek hücreleridir. Kapillerleri saran ayakçıkları ile kan-beyin bariyerinin hücresel kılıfını oluştururlar ve nöronal hasar sonrası çoğalarak astrositik skar (reaktif gliozis) meydana getirirler."},{"id":12,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":5,"q":"Böbrekte glomerüler filtrasyon bariyerini oluşturan podositlerin ayakçıkları (pediseller) arasında yer alan filtrasyon yarıklarında bulunan ve mutasyonu masif proteinüri ile seyreden Fin Tipi Konjenital Nefrotik Sendroma yol açan transmembran protein hangisidir?","options":["Nefrin","Podoksin","Aktinin-4","Kollajen Tip IV","Heparan sülfat proteoglikan"],"correct":0,"exp":"Nefrin (NPHS1 geni tarafından kodlanır), filtrasyon slit diyaframının iskeletini oluşturan en önemli hücresel adezyon molekülüdür. Mutasyonlarında filtrasyon bariyeri bozulur ve in utero dönemden itibaren ağır proteinüri (Fin tipi nefrotik sendrom) ortaya çıkar."},{"id":13,"ders":"Fizyoloji","konu":"Baş Boyun Embriyolojisi","diff":5,"q":"Farengeal (brankiyal) aparat gelişiminde, 3. farengeal cebin (pouch) ventral kanadından köken alan; gelişim bozukluğunda (DiGeorge Sendromu - 22q11.2 delesyonu) organın agenezisi nedeniyle sekonder lenfoid dokularda parakortikal alanların boş kaldığı ve şiddetli hücresel immün yetmezlik görülen yapı aşağıdakilerden hangisidir?","options":["Tiroid bezi","Superior paratiroid bezi","Timus","Tonsilla palatina","İnferior paratiroid bezi"],"correct":2,"exp":"3. farengeal cebin dorsal kanadından inferior paratiroid bezleri, ventral kanadından ise timus primordiyumu gelişir. DiGeorge sendromunda timus gelişemediği için T hücre maturasyonu bozulur ve T lenfositlerin yerleştiği lenf düğümü parakortikal bölgeleri (timusa bağımlı alanlar) atrofik kalır."},{"id":565,"ders":"Fizyoloji","konu":"Hücre Histolojisi ve Fizyolojisi","diff":4,"q":"Konjestif kalp yetmezliği tedavisi için Digoksin (bir kardiyak glikozid) kullanan hastada miyokardiyal kasılma gücünün (inotropi) artması amaçlanmaktadır. Digoksinin hücre zarındaki 'Na+/K+ ATPaz' pompasını inhibe etmesinin ardından, miyokard hücresi içinde kalsiyum (Ca+2) artışını sağlayan SEKONDER mekanizma aşağıdakilerden hangisidir?","options":["Hücre içinde biriken sodyumun (Na+), 'Na+/Ca+2 değiştirici (NCX)' pompasının çalışma yönünü tersine çevirerek kalsiyumu hücre içine alması","Sodyumun doğrudan sarkoplazmik retikulumdaki Ryanodin reseptörlerini uyarması","Hücre dışında biriken potasyumun (K+) L-tipi kalsiyum kanallarını kalıcı olarak açık tutması","Azalan ATP tüketiminin, Ca+2 ATPaz (SERCA) pompasını aşırı aktifleştirmesi","İnhibe olan pompanın hücre zarında depolarizasyon yaparak voltaj kapılı kalsiyum kanallarını tetiklemesi"],"correct":0,"exp":"Na+/K+ ATPaz pompası normalde 3 Na'yı dışarı atar, 2 K'yı içeri alır. Ouabain veya Digoksin bu pompanın potasyum bağlanan bölgesine yapışarak onu bloke eder. Pompa durunca hücre içindeki Na+ dışarı atılamaz ve sitoplazmada birikir. Miyokard zarında bulunan ve normalde kalsiyumu dışarı atıp sodyumu içeri alan 'Na+/Ca+2 Değiştirici (NCX)' adlı sekonder aktif taşıma pompası, içeride sodyumun çok arttığını (gradyentin bozulduğunu) görünce ÇALIŞMA YÖNÜNÜ TERSİNE ÇEVİRİR. Fazla sodyumu dışarı atmak için karşılığında dışarıdan Kalsiyumu (Ca+2) hücre içine çekmeye başlar. Hücrede kalsiyum artar ve kasılma gücü (pozitif inotropi) şiddetlenir."},{"id":566,"ders":"Fizyoloji","konu":"Hücre Histolojisi ve Fizyolojisi","diff":4,"q":"Hücre içi veziküler transport mekanizmalarını araştıran bir çalışmada, proteinlerin Golgi aygıtından (cis-Golgi) Granüllü Endoplazmik Retikuluma (RER) doğru 'retrograd (geriye doğru)' taşınmasından sorumlu olan vezikül örtü proteini incelenmektedir. Bu retrograd taşımayı sağlayan ve özellikle 'KDEL' aminoasit dizisine sahip ER proteinlerini geri kurtaran örtü proteini aşağıdakilerden hangisidir?","options":["Klatrin (Clathrin)","COP I (Coatomer I)","COP II (Coatomer II)","Kaveolin","Dinamin"],"correct":1,"exp":"Hücre içi vezikül trafiğinde kaplayıcı (coat) proteinler rotayı belirler. 1) COP II (İleri/Anterograd): Proteinleri Granüllü ER'den alır, Golgi'ye (cis) taşır (Step 2 = COP II = İleri). 2) COP I (Geri/Retrograd): Golgi'den ER'ye geri taşır (Step 1 = COP I = Geri). Yanlışlıkla Golgi'ye kaçmış olan ve üzerinde 'KDEL' (ER tutunma sinyali) şifresi bulunan demirbaş ER proteinlerini COP I yakalar ve evine (ER'ye) geri getirir. 3) Klatrin: Golgi'den lizozoma gidenleri (M6P işaretli) veya hücre zarından reseptör aracılı endositozla (LDL gibi) içeri girenleri kaplar."},{"id":567,"ders":"Fizyoloji","konu":"Hücre Histolojisi ve Fizyolojisi","diff":4,"q":"Kırk beş yaşında kadın hasta, cildinde kolayca patlayan ve içi sıvı dolu gevşek büllerle (Pemphigus Vulgaris) başvuruyor. Yapılan immünfloresan incelemede, epidermal hücreleri birbirine bağlayan bağlantı komplekslerine karşı gelişmiş (Anti-Desmoglein) IgG tipi otoantikorlar saptanıyor. Bu hastada fonksiyonu bozulan ve hücreleri 'perçin (punto)' şeklinde birbirine bağlayarak mekanik strese karşı koruyan hücreler arası bağlantı yapısı aşağıdakilerden hangisidir?","options":["Zonula occludens (Sıkı bağlantılar / Tight junctions)","Zonula adherens (Kemer bağlantıları)","Macula adherens (Desmozomlar)","Hemidesmozomlar","Neksus (Oluklu bağlantılar / Gap junctions)"],"correct":2,"exp":"Epitel dokusunda hücreleri bir arada tutan yapılar klinik için çok önemlidir. Pemphigus Vulgaris'te otoantikorların hedefi 'Desmoglein 1 ve 3' adlı kaderin ailesi proteinlerdir. Desmoglein, hücreleri birbirine adeta bir perçin gibi sıkıca bağlayan 'Macula Adherens (Desmozom)'lerin ana yapısıdır. Desmozomlar hücre içindeki keratin (ara) filamanlarına tutunarak deriye mekanik dayanıklılık verir. Bunlar yıkılınca epidermis hücreleri birbirinden kopar (akantoliz) ve büller oluşur. (Not: Hemidesmozomlar ise hücreyi bazal membrana bağlar ve Bullöz Pemfigoid hastalığında yıkılırlar)."},{"id":568,"ders":"Fizyoloji","konu":"Hücre Histolojisi ve Fizyolojisi","diff":5,"q":"Sempatik sinir sistemi aktivasyonu sırasında, nörotransmitter olan Noradrenalin, damar düz kas hücrelerindeki Alfa-1 (α1) adrenerjik reseptörlere bağlanır. Bu reseptör bir G-protein kenetli reseptördür (Gq). Alfa-1 reseptörünün aktivasyonu ile başlayıp düz kas kasılmasıyla sonuçlanan hücre içi ikinci haberci yolağındaki SIRA aşağıdakilerden hangisinde doğru verilmiştir?","options":["Fosfolipaz C aktivasyonu → PIP2'nin yıkılması → IP3 ve DAG oluşumu → IP3'ün endoplazmik retikulumdan kalsiyum salgılatması","Adenilat Siklaz aktivasyonu → cAMP artışı → Protein Kinaz A aktivasyonu → Miyozin hafif zincir kinaz inhibisyonu","Fosfolipaz A2 aktivasyonu → Araşidonik asit salınımı → Lökotrien sentezi","Guanilat Siklaz aktivasyonu → cGMP artışı → Protein Kinaz G aktivasyonu → Düz kas gevşemesi","Tirozin Kinaz aktivasyonu → STAT proteinlerinin fosforilasyonu → Çekirdekte transkripsiyon"],"correct":0,"exp":"Otonom sinir sistemi reseptörlerinin hücre içi sinyal yolakları TUS/USMLE'nin vazgeçilmezidir. QISS ve QIQ (Kıs-kik) kuralını hatırlayalım. Alfa-1 reseptörü 'Gq' kenetlidir. Gq proteinleri daima 'Fosfolipaz C' enzimini aktive eder. Fosfolipaz C, hücre zarındaki PIP2'yi ikiye böler: IP3 ve DAG. İkincil habercilerden DAG zarda kalarak Protein Kinaz C'yi (PKC) uyarır. IP3 ise sitoplazmaya geçip Sarkoplazmik/Endoplazmik Retikulumun kalsiyum kapılarını açar. Hücreye dolan Kalsiyum, damar düz kasını kasar. (Not: Adenilat Siklaz / cAMP yolağını Gs proteinleri - Beta-1, Beta-2 - kullanır)."},{"id":569,"ders":"Fizyoloji","konu":"Hücre Histolojisi ve Fizyolojisi","diff":4,"q":"İstirahat halindeki tipik bir memeli nöronunun hücre zarı potansiyeli (Resting Membrane Potential - RMP) yaklaşık -70 mV civarındadır. Bu potansiyelin oluşmasında hücre zarının belirli iyonlara karşı seçici geçirgenliği rol oynar. Nöronun istirahat zar potansiyelini KENDİ denge (Nernst) potansiyeline en çok yaklaştıran (ve zarın istirahatte en geçirgen olduğu) iyon aşağıdakilerden hangisidir?","options":["Sodyum (Na+)","Kalsiyum (Ca+2)","Klor (Cl-)","Potasyum (K+)","Magnezyum (Mg+2)"],"correct":3,"exp":"Hücre zarının İstirahat Potansiyelinin (RMP) ana sorumlusu 'Potasyum (K+)' iyonudur. Çünkü hücre zarı, istirahat halindeyken (hiçbir uyarı yokken) sızma kanalları (leak channels) aracılığıyla Potasyuma karşı diğer iyonlardan çok daha fazla (yaklaşık 50-100 kat) geçirgendir. Sodyum için denge potansiyeli +60 mV, Potasyum için -90 mV'dur. Zar potasyuma aşırı geçirgen olduğu için, istirahat potansiyeli (-70 mV) mecburen potasyumun denge potansiyeline doğru çekilir (Nernst denklemi ve Goldman-Hodgkin-Katz eşitliği). Sodyum içeri sızarak bu değeri -90'dan -70'e getirir."},{"id":570,"ders":"Fizyoloji","konu":"Doku Histolojisi ve Fizyolojisi","diff":4,"q":"Çocukluk çağından beri tekrarlayan sinüzit, bronşektazi ve otitis media atakları olan 25 yaşındaki erkek hasta, infertilite (kısırlık) şikayetiyle başvuruyor. Çekilen akciğer grafisinde kalbin sağ tarafta yerleştiği (Dextrocardia) ve tam situs inversus olduğu görülüyor. Kartagener Sendromu tanısı alan bu hastada, solunum epiteli ve sperm kuyruğundaki (kamçı) hareketliliği bozarak bu klinik tabloya yol açan ultrastrüktürel hücre iskeleti defekti aşağıdakilerden hangisidir?","options":["Aktin mikrofilamanlarında polimerizasyon kusuru","Konneksin proteinlerindeki mutasyon","Mikrotübüllerin 'Dinein (Dynein)' kollarındaki yapısal eksiklik","Mikrovillus yapısındaki miyozin-1 eksikliği","Kollajen tip IV sentez defekti"],"correct":2,"exp":"Kartagener Sendromu (Primer Siliyer Diskinezi), 'Silya (Tüy)' ve 'Flagella (Kamçı)' yapısının genetik defektidir. Solunum yolunda silyalar mukusu itemez (bronşektazi, sinüzit). Sperm kamçısı hareket edemez (infertilite). Fallop tüpü silyaları embriyoyu itemez (ektopik gebelik). Anne karnında embriyonun organ yerleşimini belirleyen silyalar çalışmazsa organlar ters yerleşir (Situs Inversus). Silya ve kamçının temel yapısı mikrotübüllerdir (9+2 dizilimi). Bu mikrotübüllerin birbiri üzerinde kaymasını (hareketini) sağlayan motor protein ise 'Dinein (Dynein)' kollarıdır. Dinein kollarının eksikliği tüm bu siliyer hareketi felç eder."},{"id":571,"ders":"Fizyoloji","konu":"Doku Histolojisi ve Fizyolojisi","diff":4,"q":"Sık kemik kırıkları, işitme kaybı ve göz aklarında mavimsi renk değişikliği (mavi sklera) ile karakterize Osteogenezis İmperfekta (Cam Kemik Hastalığı) hastası bir çocuk değerlendiriliyor. Bu hastalıkta, bağ dokusunun en bol bulunan proteini olan 'Tip 1 Kollajen'in sentez basamaklarından hangisi ve nerede bozulmuştur?","options":["Hücre dışında propeptidaz enzimleriyle tropokollajen oluşumu","Granüllü Endoplazmik Retikulum (RER) lümeninde, üç adet alfa zincirinin birleşerek (glisin mutasyonu nedeniyle) 'Üçlü Sarmal (Triple Helix)' yapısını oluşturamaması","Golgi aygıtında kollajenin ekzositoz veziküllerine paketlenememesi","Hücre dışında Lizil oksidaz enzimi ile kollajen lifleri arasında çapraz bağ (cross-link) kurulamaması","RER'de prolin ve lizin kalıntılarının C vitamini eksikliği nedeniyle hidroksillenememesi"],"correct":1,"exp":"Osteogenezis İmperfekta (Oİ), genellikle Tip 1 Kollajeni kodlayan (COL1A1 veya COL1A2) genlerdeki otozomal dominant bir mutasyondur. Sıklıkla kollajen zincirindeki en küçük aminoasit olan 'Glisin'in yerine başka (daha büyük) bir aminoasit geçer. Kollajenin çok sıkı olan 'Üçlü Sarmal (Triple Helix)' yapısının oluşabilmesi için her 3 aminoasitten birinin mutlaka Glisin olması ŞARTTIR. Glisin mutasyona uğrayınca, RER (Granüllü ER) lümeninde üçlü sarmal düzgün kıvrılamaz ve hatalı kollajen üretilir (veya yıkılır). Bu da kemiği, dişi ve sklerayı dayanıksız hale getirir. (Not: Lizil oksidaz/çapraz bağ defekti Ehlers-Danlos veya Menkes'te; hidroksilasyon defekti ise C vitamini eksikliği Skorbüt'te görülür)."},{"id":572,"ders":"Fizyoloji","konu":"Doku Histolojisi ve Fizyolojisi","diff":4,"q":"Kısa kollar ve bacaklar (rizomelik cücelik), belirgin bir alın ve normal boyutta bir gövde ile karakterize Akondroplazi hastası bir çocuk inceleniyor. Hastalığın temelinde Fibroblast Büyüme Faktörü Reseptörü-3 (FGFR3) geninde otozomal dominant 'kazanç (gain-of-function)' mutasyonu saptanıyor. FGFR3 reseptörünün sürekli aktif kalması, epifiz kıkırdağında (büyüme plağında) endokondral kemikleşmeyi nasıl etkileyerek cüceliğe yol açar?","options":["Kondrosit proliferasyonunu (çoğalmasını) sürekli ve aşırı şekilde uyararak büyüme plağını hızla kapatır.","Kondrositlerin proliferasyonunu ve hipertrofisini SÜREKLİ OLARAK İNHİBE EDER (baskılar), böylece kıkırdak dokusu çoğalamaz ve kemik uzayamaz.","Osteoblastların kemik matriks sentezlemesini bloke ederek sadece kıkırdak kalmasına neden olur.","Epifiz plağındaki osteoklastik aktiviteyi artırarak yeni oluşan kemiği anında eritir.","Kollajen tip X sentezini bozarak kıkırdağın kireçlenmesini engeller."],"correct":1,"exp":"Akondroplazi, cüceliğin en sık nedenidir (Endokondral kemikleşme bozukluğudur). Membranöz kemikleşme (kafatası, köprücük kemiği) normal olduğu için baş büyüktür, kol ve bacaklar kısadır. İnsan vücudunda FGFR3 reseptörünün normal (fizyolojik) görevi, epifiz plağındaki kondrositlerin (kıkırdak hücrelerinin) büyümesini 'FRENLEMEK' (inhibe etmek) tir. Mutasyon bir 'Gain-of-Function (işlev kazancı)' mutasyonudur. Yani fren pedalı takılı kalır (sürekli aktiftir). Kondrositler sürekli inhibe edilir, çoğalamazlar ve uzun kemiklerin büyüme plakları çalışamadığı için kemikler uzayamaz."},{"id":573,"ders":"Fizyoloji","konu":"Doku Histolojisi ve Fizyolojisi","diff":4,"q":"Yenidoğan bebeklerde üşümeye karşı vücut sıcaklığını korumak için titremesiz termojenez (non-shivering thermogenesis) çok önemlidir. Bu ısı üretimi, özellikle boyun, sırt ve böbrek çevresinde bulunan 'Kahverengi Yağ Dokusu (Brown Adipose Tissue)' tarafından sağlanır. Kahverengi yağ dokusunun mitokondrilerinde ısı üretimini sağlayan ve oksidatif fosforilasyonu ayırarak ATP yerine ısı açığa çıkaran spesifik protein aşağıdakilerden hangisidir?","options":["Sitokrom c oksidaz","Leptin","Termogenin (UCP-1)","Adiponektin","ATP Sentaz"],"correct":2,"exp":"Beyaz yağ dokusu tek bir büyük yağ damlacığı içerir (enerji deposudur). Kahverengi yağ dokusu ise bol miktarda küçük yağ damlacığı ve devasa miktarda demir içeren mitokondri içerir (rengi bu yüzden kahverengidir). Yenidoğanlarda titreme refleksi gelişmediği için soğuğa karşı Kahverengi Yağ dokusunu kullanırlar. Bu dokunun mitokondri iç zarında 'Termogenin (Uncoupling Protein 1 - UCP-1)' adı verilen özel bir kanal vardır. Bu kanal, solunum zincirinde zarlar arasına pompalanan protonların (H+) ATP sentazdan geçerek ATP yapmasını engeller (Ayırıcı/Uncoupler). Protonlar UCP-1'den içeri sızdıkça enerji ATP yerine 'Isı' olarak açığa çıkar ve bebeği ısıtır."},{"id":574,"ders":"Fizyoloji","konu":"Doku Histolojisi ve Fizyolojisi","diff":4,"q":"Ergenlik döneminde artan androjenlerin etkisiyle yüzde ve sırtta sivilce (Akne Vulgaris) oluşumu hızlanmaktadır. Akne patogenezinde kilit rol oynayan 'Sebase (yağ) bezleri', salgılarını kıl folikülüne boşaltırken hücrenin tümünün parçalanarak salgının bir parçası haline geldiği bir yöntem kullanırlar. Epitel hücrelerinde görülen bu spesifik salgılama (sekresyon) tipi aşağıdakilerden hangisidir?","options":["Merokrin sekresyon","Apokrin sekresyon","Holokrin sekresyon","Parakrin sekresyon","Endokrin sekresyon"],"correct":2,"exp":"Glandüler (bez) epitelinin salgılama yöntemleri histolojide 3'e ayrılır: 1) Merokrin (Ekrin): Salgı sadece ekzositozla atılır, hücre hiç zarar görmez (Ter bezleri, pankreas, tükürük bezleri). 2) Apokrin: Hücrenin tepe (apikal) kısmı salgıyla birlikte kopar ve atılır (Koltuk altı koku bezleri, Meme bezi lipid salgısı). 3) Holokrin: Tüm hücre (holo=bütün) salgıyla dolar, çekirdeği parçalanır, hücre ÖLÜR ve tamamı salgının kendisi haline gelir. Sebase (yağ) bezlerinin salgılama şekli her zaman HOLOKRİN'dir."},{"id":575,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":4,"q":"Ölümden birkaç saat sonra tüm iskelet kaslarının kaskatı kesilmesi durumuna 'Rigor Mortis (Ölüm Katılığı)' adı verilir. Çapraz köprü (cross-bridge) döngüsü göz önüne alındığında, kasların gevşeyemeyip sürekli kasılı kalmasına neden olan biyokimyasal eksiklik ve bu eksikliğin kasılma döngüsündeki karşılığı aşağıdakilerden hangisidir?","options":["Kalsiyum eksikliği / Tropomiyozinin aktin üzerinden çekilememesi","Asetilkolin eksikliği / Motor uç plakta aksiyon potansiyelinin durması","ATP eksikliği / Miyozin başının aktin flamanından KOPAMAMASI (ayrılamaması)","Kreatin fosfat eksikliği / Z çizgilerinin birbirinden uzaklaşamaması","Magnezyum eksikliği / Miyozin hafif zincir kinazın aktive olamaması"],"correct":2,"exp":"İskelet kası kasılmasında miyozin başı aktine bağlanarak (power stroke) kası büzer. Ancak bu kasılmanın bitmesi ve miyozin başının aktinden 'kurtulup/ayrılıp' kasın GEVŞEMESİ için ortama YENİ BİR ATP molekülünün gelip miyozin başına bağlanması ŞARTTIR. Kişi öldüğünde hücresel solunum durur ve ATP üretimi biter. Ortamda yeni ATP kalmadığı için, miyozin başları aktin flamanlarına sıkıca kenetli kalır ve asla ayrılamaz. Tüm kaslar kaskatı kesilir (Rigor Mortis). Katılık, kas proteinleri lizozomal enzimlerle otolize uğrayıp çürüyene kadar (15-25 saat) devam eder."},{"id":576,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":4,"q":"Gastrointestinal kanal, kan damarları ve solunum yollarında bulunan Düz Kas hücrelerinin kasılma fizyolojisi iskelet kasından farklıdır. Düz kasta çizgilenme (sarkomer) yoktur ve troponin kompleksi BULUNMAZ. Düz kasta kalsiyumun (Ca+2) hücre içine girdikten sonra kasılmayı başlatmak için bağlandığı spesifik protein ve aktive ettiği yolak aşağıdakilerden hangisidir?","options":["Kalsiyum Tropomiyozin'e bağlanır ve aktin bölgelerini açar","Kalsiyum 'Kalmodulin' proteinine bağlanır, bu kompleks 'Miyozin Hafif Zincir Kinazı (MLCK)' aktive ederek miyozin başını fosforiller.","Kalsiyum doğrudan Miyozin fosfataz enzimini aktive ederek kasılmayı başlatır","Kalsiyum Troponin C'ye bağlanarak yapısal değişikliğe neden olur","Kalsiyum Kaldesmon'a bağlanarak miyozin başının ATPase aktivitesini durdurur"],"correct":1,"exp":"İskelet ve Kalp kasında kalsiyumun hedefi Troponin C'dir. Ancak Düz Kasta troponin YOKTUR. Düz kasta hücre içine giren kalsiyum, 'Kalmodulin' adı verilen özel bir proteine bağlanır (Ca-Kalmodulin kompleksi). Bu kompleks gider, hücredeki 'Miyozin Hafif Zincir Kinaz (MLCK)' enzimini uyarır. Adı üzerinde, bu kinaz enzimi miyozinin boynundaki hafif zincire bir fosfat (P) takar. Düz kasta miyozinin aktine bağlanabilmesi (kasılabilmesi) için P ile fosforillenmesi şarttır. Gevşemek için ise bu fosfatı koparan 'Miyozin Fosfataz' enzimi devreye girer."},{"id":577,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":4,"q":"Kardiyak ventrikül kas hücresinin (miyosit) aksiyon potansiyeli grafiği incelendiğinde, iskelet kasından farklı olarak çok uzun süren bir 'Plato Fazı (Faz 2)' olduğu görülür. Bu plato fazı, kalp kasının tetaniye (krampa) girmesini engelleyen uzun bir refrakter periyot sağlar. Plato fazının oluşmasını ve hücrenin o sürede pozitif kalmasını sağlayan, birbirini dengeleyen iki ana iyon akımı aşağıdakilerden hangisidir?","options":["Hücre içine Sodyum (Na+) girişi ve Hücre içine Kalsiyum (Ca+2) girişi","Hücre içine yavaş Kalsiyum (L-tipi Ca+2) girişi ile Hücre DIŞINA Potasyum (K+) çıkışı","Hücre dışına Sodyum (Na+) çıkışı ile Hücre içine Klor (Cl-) girişi","Hücre içine Kalsiyum (T-tipi Ca+2) girişi ile Hücre DIŞINA Sodyum (Na+) çıkışı","Hücre dışına Potasyum (K+) çıkışı ile Hücre dışına Kalsiyum (Ca+2) çıkışı"],"correct":1,"exp":"Kalp ventrikül kasının aksiyon potansiyeli 5 fazdır: Faz 0 (Hızlı depolarizasyon): Sodyum (Na) içeri girer. Faz 1 (Erken repolarizasyon): Sodyum kanalı kapanır, Potasyum (K) dışarı çıkmaya başlar. **Faz 2 (Plato):** Repolarizasyon (voltajın düşmesi) aniden durur ve düz bir çizgi (plato) oluşur. Bunun nedeni, hücre zarındaki yavaş 'L-Tipi Kalsiyum kanalları'nın açılmasıdır. Pozitif Kalsiyum içeri girerken, pozitif Potasyum dışarı çıkmaktadır. İki artı yük birbiriyle inatlaşır ve voltaj dengede (plato) kalır. Kalsiyum kanalları kapanınca (Faz 3), Potasyum dışarı akmaya devam eder ve hücre hızla eksiye döner (Repolarizasyon). Faz 4 istirahat potansiyelidir."},{"id":578,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":5,"q":"Ağır bir yük kaldırmaya çalışan haltercide, kas tendonu kopma sınırına geldiği anda refleks olarak tüm iskelet kasları aniden gevşer ve yük elinden düşer (Uzama / Gevşeme refleksi). Aşırı kasılma gücü (gerilim/tansiyon) durumunda kası korumak amacıyla alfa motor nöronları İNHİBE ederek bu refleks gevşemeyi başlatan duyusal reseptör ve bağlı olduğu sinir lifi tipi aşağıdakilerden hangisidir?","options":["Kas iğciği (Muscle spindle) / Ia afferent lifler","Pacini cisimciği / A-beta lifleri","Golgi Tendon Organı (GTO) / Ib afferent lifler","Ruffini sonlanmaları / C lifleri","Eklem kapsül reseptörleri / Grup III lifler"],"correct":2,"exp":"İskelet kaslarında iki önemli propriyoseptör (koruyucu sensör) vardır: Kas İğciği ve Golgi Tendon Organı. 1) Kas İğciği (Kasın ortasındadır): Kasın UZUNLUĞUNU (boyunu) algılar. Kas aniden gerilirse/uzarsa, iğcik Ia lifleriyle uyarılır ve kasın kopmasını önlemek için kası KASTIRIR (Patella germe refleksi budur). 2) Golgi Tendon Organı (GTO - Kasın tendonundadır): Kasın uyguladığı GERİLİMİ (Tansiyonu/Gücü) algılar. Eğer kas tendonu kopartacak kadar aşırı kasılırsa, GTO Ib lifleriyle uyarılır, inhibitör ara nöronlar üzerinden kasın motor sinirini felç eder ve kası aniden GEVŞETİR (Ters miyotatik refleks). Haltercinin yükü düşürmesi budur."},{"id":579,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":4,"q":"Uluslararası bir maraton koşucusunun bacak kaslarından alınan biyopside, ağırlıklı olarak Tip 1 iskelet kası liflerinin hakim olduğu görülüyor. Yavaş kasılan ve yorulmaya karşı son derece dirençli olan Tip 1 kas liflerinin (kırmızı kas) bu dayanıklılığını sağlayan temel metabolik ve hücresel özellikler aşağıdakilerden hangisidir?","options":["Çok yüksek glikojen depoları, zengin glikolitik enzimler ve devasa çap","Çok yüksek miyoglobin içeriği, bol kapiller ağ, zengin mitokondri ve yüksek oksidatif kapasite","Düşük miyoglobin, az mitokondri ve anaerobik glikoliz kapasitesi","Yüksek miyozin ATPaz aktivitesi ve hızlı kalsiyum pompalanması","Sadece yağ asitlerini değil, ağırlıklı olarak laktik asidi kullanabilme yeteneği"],"correct":1,"exp":"İskelet kası lifleri temel olarak Tip 1 ve Tip 2 olarak ayrılır. Tip 1 lifler (Yavaş Oksidatif / Kırmızı kas): Maraton koşucuları ve sırt/postür kaslarında hakimdir. Renkleri kırmızıdır çünkü oksijen taşıyan 'Miyoglobin'leri çok fazladır. Çapları küçüktür, etrafları çok zengin kılcal damarlarla çevrilidir. Bol mitokondrileri vardır ve enerjiyi Aerobik Oksidatif fosforilasyonla üretirler. Çok yavaş yorulurlar. Tip 2b lifler (Hızlı Glikolitik / Beyaz kas): Sprint koşucuları (100 metre) ve göz kaslarında bulunur. Beyazdır (miyoglobini azdır). Mitokondrisi az, 'Glikojen' deposu ve glikoliz enzimleri çoktur. Hızlı kasılır ama saniyeler içinde laktik asit biriktirip yorulurlar."},{"id":580,"ders":"Fizyoloji","konu":"Genital Sistem HistoFizyolojisi","diff":4,"q":"İnfertilite (kısırlık) şikayetiyle başvuran 28 yaşındaki erkek hastanın testis biyopsisinde, seminifer tübüllerde otoimmün bir inflamasyon saptanıyor ve hastanın kendi spermlerine karşı antikor ürettiği (Anti-sperm antikorları) tespit ediliyor. Normal fizyolojide bağışıklık sisteminin, genetik olarak farklılaşmış olan (haploid) sperm hücrelerini tanımasını ve onlara saldırmasını engelleyen 'Kan-Testis Bariyeri'ni oluşturan hücreler arası bağlantı kompleksi aşağıdakilerden hangisidir?","options":["Leydig hücreleri arasındaki neksuslar (Gap junctions)","Sertoli hücreleri arasındaki sıkı bağlantılar (Zonula occludens)","Miyoid hücreler ile bazal membran arasındaki hemidesmozomlar","Spermatogoniumlar arasındaki desmozomlar (Macula adherens)","Sertoli hücreleri ile spermatidler arasındaki adezyon plakları"],"correct":1,"exp":"Kan-Testis bariyeri, puberteden sonra mayoz bölünme geçirerek 'yabancı (haploid)' hale gelen spermleri, vücudun kendi bağışıklık sisteminden koruyan hayati bir duvardır. Bu bariyer, seminifer tübülün destek hücreleri olan 'Sertoli hücreleri'nin birbirlerine sıkıca bağlanmasıyla (Zonula occludens / Tight junctions) oluşur. Bariyer, tübülü bazal (immün sisteme açık) ve adluminal (immün sistemden izole) olarak iki kompartmana ayırır. Bariyer yıkılırsa vücut spermlere antikor üretir ve infertilite gelişir."},{"id":581,"ders":"Fizyoloji","konu":"Genital Sistem HistoFizyolojisi","diff":4,"q":"Erkek üreme sisteminin hormonal kontrolü incelendiğinde, ön hipofizden salgılanan Luteinleştirici Hormonun (LH), testislerde spesifik bir hücre grubunu uyararak androjen sentezini (özellikle testosteron) başlattığı bilinmektedir. LH'nin bağlandığı bu hücrelerin histolojik incelemesinde, steroid hormon sentezinden sorumlu oldukları için sitoplazmalarında aşırı derecede gelişmiş (baskın) olarak bulunan organel aşağıdakilerden hangisidir?","options":["Granüllü Endoplazmik Retikulum (RER)","Golgi Aygıtı","Düz (Granülsüz) Endoplazmik Retikulum (SER)","Lizozomlar","Peroksizomlar"],"correct":2,"exp":"Erkeklerde LH'nin hedefi testis interstisyumunda bulunan 'Leydig hücreleri'dir (L-L kuralı). Leydig hücreleri testosteron (steroid) üretir. Protein ve peptit yapılı hormon (örn: insülin, büyüme hormonu) üreten hücrelerde Granüllü ER (RER) ve Golgi çok gelişmişken; kolesterolden 'Steroid' hormon (testosteron, östrojen, kortizol vb.) üreten tüm hücrelerde (Leydig hücreleri, adrenal korteks hücreleri, korpus luteum) 'Düz Endoplazmik Retikulum (SER)' ve tübüler kristalı mitokondriler aşırı gelişmiştir. Çünkü steroid sentez enzimleri SER zarlarında yer alır."},{"id":582,"ders":"Fizyoloji","konu":"Genital Sistem HistoFizyolojisi","diff":5,"q":"Otuz yaşında sağlıklı bir kadının 28 günlük düzenli menstrüel döngüsünün 21. gününde (Luteal Faz) endometrium biyopsisi yapılıyor. Biyopside endometrial bezlerin kıvrımlı ve salgıyla dolu olduğu (sekretuvar faz) izleniyor. Endometriumu bu evrede tutarak embriyonun tutunması için hazırlayan ve esas olarak 'Progesteron' salgılayan overyan yapı (Korpus Luteum), ovülasyon (yumurtlama) öncesi folikülün hangi hücrelerinin hipertrofisi ve luteinizasyonu ile oluşur?","options":["Sadece Oosit ve korona radiata hücreleri","Sadece Granüloza hücreleri","Granüloza ve Teka İnterna hücreleri","Teka Eksterna hücreleri ve over stroma hücreleri","Primordiyal folikülün yassı epitel hücreleri"],"correct":2,"exp":"Ovülasyon (LH piki) gerçekleştikten sonra, çatlayan (yırtılan) folikülün geride kalan duvarları hızla değişime uğrar ve 'Korpus Luteum (Sarı cisim)' adını alır. Korpus luteumu oluşturan ana hücreler, ovülasyon öncesi folikülü döşeyen 'Granüloza hücreleri' (Granüloza lutein hücrelerine dönüşür) ve 'Teka İnterna hücreleri'dir (Teka lutein hücrelerine dönüşür). Bu iki hücre grubu da LH etkisiyle sitoplazmalarında lipid (kolesterol) biriktirerek (sarı renk) hızla hipertrofiye uğrar ve bol miktarda Progesteron (ve az miktarda östrojen) sentezleyerek rahmi gebeliğe hazırlar."},{"id":583,"ders":"Fizyoloji","konu":"Genital Sistem HistoFizyolojisi","diff":4,"q":"Yirmi beş yaşındaki sağlıklı bir kadında gebelik gerçekleşmediği için korpus luteum gerilemiş (korpus albikansa dönüşmüş) ve kandaki progesteron ile östrojen seviyeleri aniden düşmüştür. Bu hormonal çekilme (withdrawal) sonucunda, endometriumda iskemi ve nekroz gelişerek menstrüel kanama (adet kanaması) başlamıştır. Menstrüasyon sırasında endometriumun fonksiyonel tabakasının (Stratum functionale) dökülmesini sağlayan şiddetli vazospazm (kasılma), spesifik olarak hangi damarlarda gerçekleşir?","options":["Arkuad arterler","Düz (Straight) arterler","Spiral (Helikozal) arterler","Radyal arterler","Uterin venöz pleksus"],"correct":2,"exp":"Endometrium histolojik olarak iki tabakadan oluşur: Altta kalıcı olan 'Stratum basale' (Düz arterler besler) ve her ay dökülüp yeniden yapılan 'Stratum functionale' (Spiral arterler besler). Gebelik olmazsa düşen progesteron seviyesi, prostaglandin (PGF2-alfa) salınımını tetikler. Prostaglandinler, fonksiyonel tabakayı besleyen kıvrımlı 'Spiral Arterler'de saatlerce süren çok şiddetli bir vazospazm (kasılma) yapar. Kan gitmeyen fonksiyonel tabaka iskemiden ölür (nekroz) ve damarlar tekrar gevşediğinde kan basıncıyla koparak adet kanaması şeklinde vajinadan atılır."},{"id":584,"ders":"Fizyoloji","konu":"Genital Sistem HistoFizyolojisi","diff":4,"q":"Tubal ektopik gebelik (dış gebelik) geçiren bir hastanın Fallop tüpü (Tuba uterina) cerrahi olarak çıkarılıyor. Tüp mukozasının histolojik incelemesinde tek katlı prizmatik (silindirik) epitel izleniyor. Bu epitelde, döllenmiş ovumu uterusa doğru süpüren silyalı hücrelerin yanı sıra, embriyoyu beslemek ve spermi kapasitasyona uğratmak için gerekli besleyici sıvıyı salgılayan, apikal yüzeyleri silyasız ve kubbe şeklinde lümene taşan spesifik hücreler saptanıyor. Tuba uterinada bu salgı fonksiyonunu üstlenen hücre aşağıdakilerden hangisidir?","options":["Goblet hücreleri","Peg (Çivi) hücreleri","Paneth hücreleri","Klara (Clara) hücreleri","M hücreleri"],"correct":1,"exp":"Tuba uterina (Fallop tüpü) epiteli iki ana hücre tipinden oluşur: 1) Silyalı hücreler: Östrojen etkisiyle sayıları artar ve yumurtayı rahme doğru süpürürler. 2) Peg (Çivi/Sekretuvar) hücreleri: Progesteron etkisiyle sayıları/salgıları artar. Apikal kısımları silyasızdır, bir kubbe veya çivi gibi lümene taşarlar. Görevleri, yumurtanın, spermin ve döllenmiş embriyonun tüpteki yolculuğu (3-4 gün sürer) boyunca beslenmesini sağlayacak glikoprotein ve lipidden zengin besleyici sıvıyı salgılamaktır. (Not: Goblet bağırsağın, Clara solunum yolunun, Paneth ince bağırsağın dibindeki antimikrobiyal hücredir)."},{"id":585,"ders":"Fizyoloji","konu":"Genel Embriyoloji","diff":4,"q":"Fertilizasyon (döllenme) sırasında, kapasitasyona uğramış bir sperm hücresi oositin etrafındaki Zona Pellucida'yı (ZP3 reseptörleri aracılığıyla) delip oosit zarına ulaştığında ve kaynaştığında, oositin içinde ani bir hücre içi kalsiyum (Ca+2) dalgası oluşur. Bu kalsiyum dalgası, oosit zarının hemen altındaki kortikal granüllerin ekzositozla dışarı boşalmasına (Kortikal Reaksiyon) neden olur. Kortikal reaksiyonun embriyolojik açıdan en kritik fizyolojik işlevi aşağıdakilerden hangisidir?","options":["Oositin 2. mayoz bölünmesini tamamlamasını başlatmak","Zona Pellucida'nın yapısını (ZP3 reseptörlerini) değiştirerek ve sertleştirerek polispermiyi (birden fazla spermin girmesini) engellemek","Erkek ve dişi pronükleuslarının birleşmesini (singami) kolaylaştırmak","Zigotun mitoz bölünmelerini (klivaj) tetikleyecek ATP sentezini başlatmak","Embriyonun endometriyuma tutunması için gerekli enzimleri serbest bırakmak"],"correct":1,"exp":"Fertilizasyonda en büyük risk 'Polispermi'dir (bir yumurtaya iki sperm girerse 69 kromozomlu, yaşamaz bir triploidi oluşur). İlk sperm yumurta zarına dokunduğu anda, yumurta içindeki kalsiyum fırlar ve zardaki kortikal granüller dışarı kusulur (Kortikal reaksiyon). Bu granüllerin içindeki enzimler, yumurtayı saran jölemsi kılıf olan 'Zona Pellucida'yı anında sertleştirir ve üzerindeki sperm bağlayıcı ZP3 reseptörlerini yıkar. Buna 'Zona Reaksiyonu' denir. Böylece arkadan gelen diğer spermlerin yumurtaya girmesi mekanik olarak engellenir ve polispermi önlenir."},{"id":586,"ders":"Fizyoloji","konu":"Genel Embriyoloji","diff":4,"q":"Döllenmeden yaklaşık 6-7 gün sonra, blastosist aşamasındaki embriyo uterus (rahim) endometriumuna tutunmaya (implantasyon) başlar. Blastosistin dış tabakası olan trofoblastlar iki farklı hücre tabakasına farklılaşır. Bu tabakalardan biri hücre sınırlarını kaybederek anne dokusunun içine doğru agresif bir şekilde invaze olan ve aynı zamanda gebelik testi için kullanılan Human Koryonik Gonadotropin (hCG) hormonunu sentezleyen çok çekirdekli dev bir kitle oluşturur. Bu agresif ve hormon sentezleyen embriyolojik doku aşağıdakilerden hangisidir?","options":["Sitotrofoblast","Embriyoblast (İç hücre kitlesi)","Sinsityotrofoblast","Ekstraembriyonik mezoderm","Hipoblast"],"correct":2,"exp":"İmplantasyon sırasında embriyonun dış zarı olan Trofoblastlar ikiye ayrılır: İçte tek çekirdekli, düzgün sınırlı 'Sitotrofoblastlar' (hücre fabrikasıdır, sürekli bölünürler) ve dışta bu hücrelerin birleşerek oluşturduğu, hücre zarlarının eridiği, çok çekirdekli dev bir süngerimsi doku olan 'Sinsityotrofoblastlar'. Sinsityotrofoblastlar, annenin kan damarlarını ve dokusunu eriterek embriyoyu rahme gömen agresif parmakçuklardır. Aynı zamanda kana 'hCG (Human Koryonik Gonadotropin)' salgılayarak annenin overindeki Korpus Luteum'a 'Ben geldim, progesteron üretmeye devam et, adet kanaması yapma' mesajını iletirler."},{"id":587,"ders":"Fizyoloji","konu":"Genel Embriyoloji","diff":5,"q":"Gelişimin 3. haftasında (Gastrulasyon evresi), epiblast hücreleri primitif çizgi (primitive streak) boyunca göç ederek üç temel germ yaprağını (Ektoderm, Mezoderm ve Endoderm) oluştururlar. Aynı dönemde primitif düğümden başa doğru (kraniyal yönde) uzanan silindirik bir hücre kordonu olan 'Notokord' gelişir. Notokordun embriyolojik gelişimdeki (organogenez) en önemli BİRİNCİL indükleyici (uyarıcı) görevi aşağıdakilerden hangisidir?","options":["Altındaki endodermi uyararak sindirim kanalını oluşturmak","Üzerindeki ektodermi indükleyerek Nöral Plağın (dolayısıyla santral sinir sisteminin) gelişmesini başlatmak","Yanlarındaki paraksiyal mezodermi uyararak somitlerin parçalanmasını sağlamak","İlkel kalp tüpünün birleşmesi için kılavuzluk etmek","Gelecekteki göbek kordonunun kan damarlarını oluşturmak"],"correct":1,"exp":"Gastrulasyonun en kritik olayı Notokordun oluşumudur (Notokord mezoderm kökenlidir). Notokord, embriyonun ilkel omurgası gibidir. Organogenezde 'İndüksiyon (bir dokunun diğerine emir vermesi)' kavramının en meşhur örneği Notokord'dur. Notokord, hemen kendi ÜZERİNDE bulunan yüzey ektodermi hücrelerine moleküler sinyaller (Sonic Hedgehog / SHH vb.) göndererek onları kalınlaştırır ve 'Nöral Plak' olmasını sağlar (Nöroektoderm). Nöral plak kıvrılarak nöral tüpü (Beyin ve Omuriliği) oluşturur. Yani Notokord olmasaydı sinir sistemimiz gelişemezdi. İlerleyen yaşlarda notokord kalıntısı intervertebral disklerin ortasındaki 'Nucleus pulposus' olarak hayatına devam eder."},{"id":588,"ders":"Fizyoloji","konu":"Genel Embriyoloji","diff":4,"q":"Gelişimin 3. ve 4. haftalarında notokordun her iki yanında yer alan 'Paraksiyal Mezoderm', baş-kuyruk ekseni boyunca parçalara ayrılarak 'Somit' adı verilen kübik blokları oluşturur. Somitler daha sonra üç farklı embriyolojik taslağa farklılaşır. Bu somitlerin medial ve ventral kısmında yer alan ve göç ederek notokord ile nöral tüpün etrafını sarıp gelecekteki 'Vertebraları (Omurları)' ve kaburgaları oluşturacak olan embriyolojik doku taslağı aşağıdakilerden hangisidir?","options":["Dermatom","Miyotom","Sklerotom","Ara (İntermediate) mezoderm","Somatoplevrik mezoderm"],"correct":2,"exp":"Somitler (Paraksiyal mezoderm kökenli), insan vücudunun segmental (bölmeli) yapısını oluşturur. Her bir somit 3 parçaya ayrılır: 1) Sklerotom: En içte ve alttadır (ventromedial). Göç ederek nöral tüpü sarar ve eksenel iskeleti (Vertebralar/Omurlar ve Kaburgalar) oluşturur (Sklero=Sert/Kemik). 2) Miyotom: Ortadadır, vücudun tüm iskelet kaslarını oluşturur. 3) Dermatom: En dıştadır, sırt bölgesindeki cildin dermis tabakasını oluşturur. (Not: Ara mezoderm ürogenital sistemi, somatoplevrik mezoderm ise parietal zarları ve ekstremite kemiklerini yapar)."},{"id":589,"ders":"Fizyoloji","konu":"Genel Embriyoloji","diff":4,"q":"Nöral tüpün kapanması sırasında, nöral katlantıların tepe kısmında yer alan özel bir hücre grubu, ektodermal bağlantılarını kopararak embriyonun dört bir yanına göç etmeye başlar. 'Dördüncü germ yaprağı' olarak da adlandırılan bu Nöral Krest (Neural Crest) hücreleri birçok farklı organın gelişimine katılır. Aşağıdaki doku veya hücre tiplerinden hangisi Nöral Krest hücrelerinden KÖKEN ALMAZ?","options":["Ciltteki melanositler (pigment hücreleri)","Adrenal (Böbrek üstü) bezin medullası","Periferik sinir sistemindeki Schwann hücreleri","Yüz ve kafatası kemiklerinin büyük bir kısmı (Fasiyal iskelet)","Santral sinir sistemindeki mikroglialar"],"correct":4,"exp":"Nöral Krest (Krista) hücreleri ektoderm kökenli muazzam göçmen hücrelerdir. Gittikleri yerde şu yapıları oluştururlar: Adrenal medulla (katekolamin üreten kromaffin hücreler), Melanositler (cilde renk verenler), Schwann hücreleri (periferik miyelin), Pia ve Araknoid zarlar, Tiroidin C (kalsitonin) hücreleri, Yüz-çene (fasiyal) kemikleri ve kıkırdakları, Kalpteki aortikopulmoner septum, Otonom ve arka kök ganglionları. ANCAK, santral sinir sisteminin çöpçüleri olan 'Mikroglialar' nöral krestten DEĞİL, kemik iliğindeki makrofajlar gibi 'Mezodermden (Mononükleer fagositik sistem)' köken alırlar."},{"id":590,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":4,"q":"Akut kan kaybı sonrası kemik iliğinde eritropoez (kırmızı kan hücresi yapımı) hızlanan bir hastanın periferik kan yayması supravital boyalarla (örn: Yeni Metilen Mavisi) inceleniyor. Yaymada, olgun eritrositlerden biraz daha büyük olan ve sitoplazmalarında ağsı (retiküler) lacivert iplikçikler içeren hücrelerin sayısında artış saptanıyor. Eritrosit olgunlaşma serisinin kana çıkan en son öncül hücresi olan bu retikülositlerde boyanan ağsı (retiküler) materyalin hücresel kaynağı aşağıdakilerden hangisidir?","options":["Parçalanmış hücre çekirdeği (DNA) kalıntıları","Mitokondriyal krista döküntüleri","Ribozomal RNA (rRNA) ve poliribozom kalıntıları","Golgi aygıtı vezikülleri","Denatüre olmuş hemoglobin çökeltileri"],"correct":2,"exp":"Eritrositler kemik iliğinde olgunlaşırken önce çekirdeklerini atarlar. Çekirdeğini yeni atmış, henüz tam olgunlaşmamış genç alyuvarlara 'Retikülosit' denir. Retikülositler kemik iliğinden çıkıp kanda 1-2 gün dolaştıktan sonra içlerindeki son organelleri de atıp olgun eritrosite dönüşürler. Normal boyalarla polikromatofilik (morumsu) görünürler. Ancak supravital boyalarla (Yeni Metilen Mavisi, Parlak Krezil Mavisi) boyandıklarında sitoplazmalarında bir ağ (retikulum) belirir. Bu ağsı yapı, hücrenin hemoglobin sentezlemek için kullandığı son 'Ribozomal RNA (rRNA)' ve poliribozom kalıntılarıdır. Kanama veya hemoliz durumunda kemik iliğinin çalıştığını (telafi ettiğini) gösteren en iyi bulgu kanda retikülosit artışıdır."},{"id":591,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":4,"q":"Trombopoetin (TPO) hormonunun uyarısıyla kemik iliğinde trombosit üretimi gerçekleşmektedir. Trombositlerin köken aldığı Megakaryositler, vücudun en büyük hücrelerinden biridir ve devasa (poliploid) bir çekirdeğe sahiptirler. Megakaryositlerin, hücre bölünmesi (sitokinez) olmaksızın sadece DNA'larını kopyalayarak devasa çekirdeklere ulaşmasını sağlayan spesifik hücre döngüsü mekanizması (ve trombosit oluşturma yöntemi) aşağıdakilerden hangisinde doğru verilmiştir?","options":["Mayoz bölünme / Ekzositozla protein sekresyonu","Endomitoz (Endoreduplikasyon) / Sitoplazmada demarkasyon kanalları oluşturup sitoplazmanın parçalanması (fragmentasyon)","Amitoz / Pinositoz keseciklerinin atılması","Klivaj / Apoptotik cisimciklerin kana karışması","Şizogoni / Hücre zarının tomurcuklanması"],"correct":1,"exp":"Trombositler bir hücre DEĞİL, kemik iliğindeki devasa bir hücrenin (Megakaryosit) kopan sitoplazma parçacıklarıdır. Megakaryositler büyürken çok ilginç bir yol izlerler: 'Endomitoz (Endoreduplikasyon)'. Yani hücre DNA'sını 2n, 4n, 8n, 16n, 32n, 64n şeklinde sürekli kopyalar ama hücre ve çekirdek ASLA BÖLÜNMEZ. Sonuçta devasa loblu bir çekirdek ve dev bir sitoplazma oluşur. Yeterince büyüyen megakaryosit, sitoplazmasının içine 'Demarkasyon Kanalları' adı verilen zarlar çizer. Bu zarlar birleşerek sitoplazmayı binlerce küçük pulcuğa ayırır. Sonunda megakaryosit parçalanır (fragmentasyon) ve bu pulcuklar kana 'Trombosit' olarak dökülür."},{"id":592,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":4,"q":"X'e bağlı Agammaglobulinemi (Bruton Hastalığı) tanısı alan ve vücudunda hiç B lenfositi (CD19+ hücre) bulunmayan bir erkek çocuğun lenf nodu biyopsisi histolojik olarak inceleniyor. Lenf nodunun yapısında T hücrelerine ait bölgelerin normal olduğu görülürken, spesifik olarak B hücrelerinin yerleştiği ve çoğaldığı bölgelerin tamamen boş (hipoplastik) olduğu gözleniyor. Bu hastanın lenf nodunda gelişmemiş ve boş görünen anatomik bölge aşağıdakilerden hangisidir?","options":["Parakorteks","Yüzeyel (Dış) Korteks (Foliküller ve Germinal Merkezler)","Medüller kordlar","Subkapsüler sinüs","Trabeküler sinüs"],"correct":1,"exp":"Lenf nodları histolojik olarak T ve B lenfositlerin ayrı ayrı yerleştiği mahallelere sahiptir. 1) Yüzeyel (Dış) Korteks: B lenfositlerin mahallesidir. Burada yuvarlak 'Foliküller' ve ortalarında B hücrelerinin antijenle karşılaşıp çoğaldığı 'Germinal Merkezler' bulunur. B hücre eksikliği olan Bruton hastalığında bu bölge tamamen bomboştur. 2) Parakorteks (İç korteks): T lenfositlerin mahallesidir (Timus bağımlı bölge). DiGeorge sendromu gibi T hücre eksikliklerinde Parakorteks boş kalır. 3) Medulla: Plazma hücrelerinin (antikor üreten fabrikalar) ve makrofajların kordonlar halinde bulunduğu en iç kısımdır."},{"id":593,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":5,"q":"Timus bezi, immün sistemin eğitim merkezi olup T lenfositlerinin olgunlaştığı (T hücre toleransının geliştiği) organdır. Timus histolojisi incelendiğinde, medüllada (öz bölgesinde) sadece timusa özgü olan, Tip VI epitelyoretiküler hücrelerin soğan zarı gibi eşmerkezli (konsantrik) olarak dizilmesiyle oluşan ve merkezinde keratinleşme/nekroz görülebilen eozinofilik yapılar saptanır. İlerleyen yaşla birlikte sayısı ve boyutu artan bu spesifik histolojik yapı aşağıdakilerden hangisidir?","options":["Peyer plakları","Hassall cisimcikleri (Hassall korpüskülleri)","Billroth kordonları","Malpighi cisimcikleri","Herring cisimcikleri"],"correct":1,"exp":"Hematopoetik organların kendilerine has (kimlik kartı niteliğinde) histolojik yapıları vardır. Timusun kimlik kartı medüllasında bulunan 'Hassall Cisimcikleri'dir. Bunlar Tip VI (6) epitelyoretiküler hücrelerin kendi etraflarında soğan zarı gibi (konsantrik) sarılıp, merkezlerinde keratinleşmesi veya kireçlenmesiyle oluşur. Kesin görevleri tam bilinmemekle birlikte IL-T (Timik stromal lenfopoetin) salgılayarak T hücrelerinin eğitimine ve dendritik hücre aktivasyonuna katıldıkları düşünülmektedir. (Not: Peyer plakları ileumda, Billroth kordonları dalak kırmızı pulpasında, Malpighi cisimcikleri dalak beyaz pulpasında, Herring cisimcikleri ise nörohipofizde bulunur)."},{"id":594,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":4,"q":"Herediter Sferositoz hastasında eritrositlerin esnekliği (deformabilitesi) kaybolmuş ve küre şeklini (sferosit) almışlardır. Bu anormal alyuvarlar dolaşırken dalağa geldiklerinde, dalağın 'Kırmızı Pulpa'sında bulunan spesifik bir anatomik bariyerden (dar yarıklar) esneyip geçemezler ve dalak kordonlarında hapsolarak makrofajlar tarafından parçalanırlar. Dalak sinüzoidlerinin duvarını döşeyen ve alyuvarların esnekliğini test eden bu uzun, çubuk şeklindeki endotel hücrelerine ne ad verilir?","options":["Kupffer hücreleri","Littoral hücreler","Fıçı hücreleri (Stave cells / Çıtak hücreleri)","Foliküler dendritik hücreler","M (Mikrofold) hücreleri"],"correct":2,"exp":"Dalak, kanın kalite kontrol merkezidir. Kan, dalaktaki Kırmızı Pulpaya (Billroth kordonlarına) dökülür. Buradan tekrar venöz dolaşıma dönebilmek için 'Dalak Sinüzoidleri'nin (venöz sinüslerin) içine girmek zorundadır. Ancak bu sinüzoidlerin duvarı sıva gibi düz değildir; fıçı (varil) tahtaları gibi yan yana dizilmiş uzun, ince endotel hücrelerinden (Fıçı hücreleri / Stave cells / Çıtak hücreler) oluşur. İki fıçı hücresi arasındaki boşluk (yarık) yaklaşık 2-3 mikrometre kadardır. Oysa eritrositin çapı 7-8 mikrometredir. Normal bir eritrosit çok esnek olduğu için katlanarak bu delikten içeri sızar. Ancak Sferositoz gibi hastalıklarda eritrosit katı/sert bir top gibidir, bu yarıktan geçemez, dışarıda (Billroth kordonlarında) takılı kalır ve orada bekleyen makrofajlar tarafından yutulup parçalanır (Ekstravasküler hemoliz)."},{"id":595,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":4,"q":"Mide mukozasında asit salgılanmasından sorumlu olan paryetal (oksintik) hücrelerin histolojik incelemesinde, hücre istirahat halindeyken (asit salgılamıyorken) apikal sitoplazmada yoğun olarak bulunan ancak hücre aktifleştiğinde azalıp kaybolan spesifik membranöz yapı aşağıdakilerden hangisidir?","options":["Golgi sisternaları","Lizozomal granüller","Tübüloveziküler sistem (ağ)","Zymogen (zimojen) granülleri","Kaba Endoplazmik Retikulum (RER) kesecikleri"],"correct":2,"exp":"Paryetal hücreler, midede HCl (asit) ve İntrinsik Faktör salgılayan dev, eozinofilik hücrelerdir. Bu hücrelerin asit salgılayabilmesi için apikal yüzey alanlarının çok geniş olması gerekir. İstirahat halindeki bir paryetal hücrenin apikal sitoplazması, içinde H+/K+ ATPaz (Proton pompası) barındıran 'Tübüloveziküler Sistem' adı verilen sayısız kesecikle (vezikül) doludur. Hücre gastrin, histamin veya asetilkolin ile uyarıldığında, bu tübüloveziküller hızla apikal hücre zarına doğru göç eder ve zarla kaynaşarak derin 'İntraselüler Kanaliküller' oluştururlar. Bu sayede hücrenin yüzey alanı saniyeler içinde devasa boyutlara ulaşır ve asit pompalanmaya başlar. Uyarılma bitince kanaliküller tekrar içeri çekilerek tübüloveziküllere dönüşür."},{"id":596,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":4,"q":"İnce bağırsak mukozasının histolojik kesitleri incelendiğinde, Lieberkühn kriptlerinin en taban (bazal) kısmında yerleşmiş, apikal sitoplazmalarında irili ufaklı, yoğun eozinofilik (pembe-kırmızı boyanan) sekretuvar granüller içeren spesifik hücreler saptanır. Bağırsak florasının düzenlenmesinde rol alan ve alfa-defensin (kriptidin) ile lizozim salgılayan bu hücre aşağıdakilerden hangisidir?","options":["Goblet hücreleri","Paneth hücreleri","Enteroendokrin hücreler","M (Mikrofold) hücreleri","Brunner bez hücreleri"],"correct":1,"exp":"GİS histolojisinin favori hücrelerinden biri Paneth hücreleridir. Sadece ince bağırsakta (özellikle ileumda) Lieberkühn kriptlerinin tam dibinde (bazalinde) bulunurlar. Çok belirgin apikal eozinofilik granülleri vardır (mikroskopta kolayca tanınırlar). Bu granüllerin içinde anti-mikrobiyal peptitler olan 'Lizozim, Alfa-defensin ve Fosfolipaz A2' bulunur. Temel görevleri bağırsağın doğal immünitesini sağlamak ve bağırsak florasını (kök hücreleri koruyarak) kontrol altında tutmaktır. (Not: Goblet mukus salgılar, M hücreleri Peyer plakları üzerinde antijen taşır, Brunner bezleri sadece duodenumda submukozada bulunur ve alkali mukus salgılar)."},{"id":597,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":4,"q":"Mide ve bağırsakların düz kas tabakalarında spontan olarak ortaya çıkan ve aksiyon potansiyellerine zemin hazırlayan elektriksel 'Yavaş Dalgalar (Slow Waves)' mevcuttur. Gastrointestinal sistemin temel ritmini belirleyen bu elektriksel yavaş dalgaları üreten ve GİS'in 'pacemaker (ritim oluşturucu)' hücreleri olarak bilinen yapı aşağıdakilerden hangisidir?","options":["Meissner pleksusu nöronları","Auerbach pleksusu motor nöronları","Cajal'ın interstisyel hücreleri (ICC)","Kupffer hücreleri","Enterokromafin benzeri (ECL) hücreler"],"correct":2,"exp":"Gastrointestinal sistemin kendi kendine kasılmasını (peristaltizm) sağlayan bir ritim üreteci vardır. İnce bağırsakta sirküler ve longitudinal düz kas tabakaları arasında (Auerbach pleksusuna komşu) yerleşmiş olan yıldızsı şekilli hücrelere 'Cajal'ın İnterstisyel Hücreleri (ICC)' denir. ICC'ler GİS'in pacemaker (kalp pili) hücreleridir. Kendi kendilerine 'Yavaş Dalgalar (Slow waves / Bazal elektriksel ritim)' üretirler ve bu elektriği gap junction'lar (neksus) aracılığıyla düz kaslara iletirler. Yavaş dalgalar tek başlarına kasılma yapmaz, ancak eşik değeri aşarlarsa (örneğin gerilme veya asetilkolin uyarısıyla) aksiyon potansiyeli (diken dalgası) doğurur ve kasılma gerçekleşir."},{"id":598,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":4,"q":"Karaciğer histolojisi incelendiğinde, hepatositlerin bazolateral yüzü ile sinüzoid endoteli arasında kalan ve kan plazmasının serbestçe dolaştığı 'Disse mesafesi (Perisinüzoidal alan)' adı verilen bir boşluk bulunur. Normalde A vitamini (retinoid) depolamakla görevli olan, ancak kronik karaciğer hasarında (siroz) aktive olarak Tip I Kollajen sentezleyen miyofibroblastlara dönüşen hücre aşağıdakilerden hangisidir?","options":["Kupffer hücreleri","Hepatik stellat hücreler (İto hücreleri)","Kolanjiyositler","Oval hücreler","Pit hücreleri"],"correct":1,"exp":"Karaciğerin Disse mesafesinde yer alan Hepatik Stellat Hücreler (İto Hücreleri), histolojide ve patolojide çok kritiktir. Sağlıklı bir insanda bu hücreler lipidden çok zengindir ve vücudun 'A Vitamini' deposu olarak görev yaparlar. Ancak hepatit, alkol toksisitesi veya kronik hasar durumunda, Kupffer hücrelerinden salınan TGF-beta ve PDGF gibi sitokinlerin etkisiyle bu İto hücreleri uyanır. A vitamini depolarını kaybederler ve kasılabilen, bolca 'Tip I Kollajen' üreten 'Miyofibroblastlara' dönüşürler. Ürettikleri bu kollajen Disse mesafesini doldurarak kanın hepatositlere ulaşmasını engeller ve sirozun (fibrozis/portal hipertansiyon) temelini oluştururlar."},{"id":599,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":5,"q":"Tükürük bezlerinin asinuslarında üretilen primer tükürük sıvısı (primer sekresyon), kan plazmasına göre izotoniktir. Ancak bu sıvı, bezin kanallarından (özellikle Çizgili/Striated kanallar) geçerek ağız boşluğuna ulaştığında 'hipotonik' bir hal alır. Tükürüğün hipotonik hale gelmesini sağlayan kanallardaki iyon değişimi ve su geçirgenliği özellikleri aşağıdakilerden hangisinde doğru verilmiştir?","options":["Kanallar suya serbestçe geçirgendir; Sodyum ve Klor salgılanırken, Potasyum emilir.","Kanallar suya tamamen geçirgen DEĞİLDİR; Sodyum ve Klor emilirken, Potasyum ve Bikarbonat salgılanır.","Kanallar suya serbestçe geçirgendir; Kalsiyum emilir, Fosfat salgılanır.","Kanallar suya tamamen geçirgen DEĞİLDİR; Potasyum emilir, Sodyum salgılanır.","Kanallar suya serbestçe geçirgendir; tüm iyonlar aktif olarak emilir."],"correct":1,"exp":"Tükürük bezleri, salgılarını ağza iletirken modifiye ederler. Asinüslerde üretilen ilk tükürük kana eşdeğerdir (İzotonik). Bu sıvı 'Çizgili Kanallardan (Striated ducts)' geçerken çok önemli bir işlem olur: Kanal hücreleri aktif olarak 'Sodyum (Na) ve Kloru (Cl)' sıvıdan geri emerken, karşılığında sıvıya 'Potasyum (K) ve Bikarbonat (HCO3)' salgılarlar. Ancak en önemli kural şudur: Bu kanalların duvarı SUYA KARŞI KESİNLİKLE GEÇİRGEN DEĞİLDİR (Su iyonların peşinden gidemez). Sıvının içinden tuzu (Na, Cl) çekip alırsanız ama suyu bırakırsanız, geriye kalan sıvı mecburen seyreltik, yani 'Hipotonik' bir sıvı olur. (Not: Tükürük akım hızı çok artarsa, sıvı bu kanallardan çok hızlı geçer, iyon değişimi için vakit kalmaz ve tükürük izotoniğe yaklaşır)."},{"id":600,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"Kalbin iletim sistemi histolojik olarak incelendiğinde, ventriküllerin subendokardiyal tabakasında yerleşmiş olan özel modifiye kalp kası hücreleri saptanır. Normal kardiyomiyositlere göre çok daha büyük çaplı olan, bol miktarda glikojen içerdikleri için mikroskopta daha soluk boyanan ve hücre çevresine itilmiş az sayıda miyofibril içeren bu hücreler, kalpteki en hızlı elektriksel iletimi sağlamakla görevlidir. Tanımlanan bu hücre grubu aşağıdakilerden hangisidir?","options":["Sinoatriyal (SA) düğüm P hücreleri","Atriyoventriküler (AV) düğüm geçiş hücreleri","Purkinje lifleri","Pektinat kas hücreleri","Korda tendinea fibroblastları"],"correct":2,"exp":"Kalbin histolojik kesitlerinde boyanma farklılıkları önemlidir. Purkinje lifleri, ventriküllerin subendokardiyal tabakasında bulunan modifiye (özelleşmiş) kalp kası hücreleridir. Enerjilerini güvenceye almak için sitoplazmalarında devasa miktarda 'Glikojen' depolarlar. Glikojen boya almadığı için H&E boyamasında hücrenin ortası bomboş, soluk (halo) görünür; kasılma proteinleri (miyofibriller) ise hücrenin zarına doğru (perifere) itilmiştir. Hücre çapları normal miyositlerden çok daha büyüktür ve aralarında bolca 'Gap junction (Neksus)' bulunur. Büyük çapları ve gap junction'ları sayesinde kalbin 'en hızlı (4 m/sn)' iletim yollarıdır; ventriküllerin aynı anda kasılmasını sağlarlar."},{"id":601,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"Büyük arterlerin (örneğin Aort) histolojik yapısı incelendiğinde, duvarlarının çok kalın olması nedeniyle lümenden geçen kanın en dış tabakaları (Tunica media'nın dışı ve Tunica adventitia) beslemede yetersiz kaldığı görülür. Bu nedenle büyük damarlar, kendi duvarlarını beslemek için spesifik küçük kan damarı ağlarına sahiptirler. 'Damarların damarı' olarak adlandırılan bu besleyici yapı aşağıdakilerden hangisidir?","options":["Vasa vasorum","Nervi vascularis","Arteriyovenöz anastomoz","Glomus cisimciği","Sinüzoidal kapiller ağ"],"correct":0,"exp":"Damar duvarları (intima, media, adventitia) oksijen ve besine ihtiyaç duyar. Küçük damarlarda bu ihtiyaç lümenden geçen kandan diffüzyonla karşılanır. Ancak Aort gibi kalın duvarlı 'Elastik Arterler'de veya kalın venlerde (Vena Kava), diffüzyon en dış tabakalara (Tunica media'nın dış 1/3'üne ve Tunica adventitia'ya) ulaşamaz. Bu bölgeler, adventitia tabakası içinde yer alan kendi özel küçük kapiller/arteriyol ağları ile beslenir. Bu yapıya 'Vasa vasorum (Damarların damarı)' denir. (Sifiliz aortitinde bu vasa vasorumlar iltihaplanıp tıkanır -endarteritis obliterans-, damar duvarı beslenemeyip ölür ve aort anevrizması gelişir)."},{"id":602,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"İnsan vücudundaki kapiller (kılcal damar) ağları, geçirgenlik özelliklerine göre üç ana gruba ayrılır. Bunlardan bazılarının endotel hücreleri arasında çok geniş boşluklar bulunur, bazal membranları ya kesintilidir ya da hiç yoktur. Makromoleküllerin, hatta tam kan hücrelerinin (eritrosit/lökosit) damar dışına kolayca çıkmasına (veya girmesine) izin veren bu en geçirgen kapiller tipi (Sinüzoidal / Süreksiz kapiller) aşağıdaki organlardan hangisinde bulunur?","options":["Kan-Beyin Bariyeri (Serebral korteks)","İskelet kası ve Kalp kası","Kemik İliği, Karaciğer ve Dalak","Böbrek glomerülleri","İnce bağırsak villusları ve Endokrin bezler"],"correct":2,"exp":"Kapillerler 3 tiptir: 1) Sürekli (Somatic) Kapillerler: Endotel ve bazal membran kesintisizdir. Sıkı bağlantılar (tight junction) vardır. Kas, beyin, akciğer ve ekzokrin bezlerde bulunur. (Beyindeki en sıkı olanıdır). 2) Fenestralı (Pencereli) Kapillerler: Endotelde delikler (fenestra) vardır ama bazal membran süreklidir. Hızlı madde alışverişi gereken yerlerde (Böbrek glomerülü, bağırsak, endokrin bezler) bulunur. 3) Sinüzoidal (Süreksiz) Kapillerler: Endotel hücreleri arası kocamandır, bazal membran delik deşiktir veya yoktur. Kanın tüm elemanlarının veya dev proteinlerin geçmesi gereken 'Kemik İliği (yeni hücrelerin kana girmesi için), Dalak (yaşlı eritrositlerin çıkması için) ve Karaciğerde (protein/faktörlerin kana girmesi için)' bulunurlar."},{"id":603,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"Kardiyak siklus (Kalp Döngüsü) sırasında, elektrokardiyogramda (EKG) QRS kompleksinin hemen ardından ventriküllerin kasılmaya başlamasıyla ilk kalp sesi (S1) duyulur. S1 sesinin duyulduğu bu an ile aort kapağının açıldığı an arasında geçen çok kısa süreye 'İzovolümetrik Kontraksiyon Fazı' denir. Bu faz sırasında kalpteki mekanik ve hemodinamik durum için aşağıdakilerden hangisi doğrudur?","options":["Atriyoventriküler (Mitral/Triküspit) kapaklar açıktır, aort/pulmoner kapaklar kapalıdır.","Ventrikül içindeki basınç hızla ARTAR ancak ventrikülün içindeki kan hacmi (volümü) DEĞİŞMEZ.","Ventrikül basıncı, aort basıncını aşmıştır ve kan hızla aortaya fırlatılmaktadır.","Tüm kalp kapakları (AV ve Semilunar) ardına kadar açıktır.","Ventrikül içindeki basınç hızla düşerken, atriyumlardan kan emilmektedir."],"correct":1,"exp":"Kalp siklusunun en kritik dönemeçleri basınç/hacim değişimleridir. Ventrikül kanla dolduktan sonra kasılmaya başlar (Sistol başlangıcı). Basınç yükselir yükselmez, kanın geri kaçmaması için Atriyoventriküler (Mitral/Triküspit) kapaklar şiddetle kapanır (Bu kapanma 'S1' sesidir). Ancak ventrikülün basıncı HENÜZ aort basıncını yenip Aort kapağını açacak seviyeye (Örn: 80 mmHg) ulaşmamıştır. İşte bu saniyede (Mitral kapanmış, Aort henüz açılmamış) Kalpteki TÜM KAPAKLAR KAPALIDIR. Kapalı bir kutuda kasılmaya devam eden ventrikülün basıncı hızla fırlar, ancak kapılar kapalı olduğu için içindeki kan bir yere gidemez, hacim (volüm) DEĞİŞMEZ. Bu faza 'İzovolümetrik (Aynı Hacimli) Kontraksiyon' fazı denir. Aort kapağı açıldığı anda bu faz biter ve fırlatma (Ejection) fazı başlar."},{"id":604,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":5,"q":"Sinoatriyal (SA) düğüm hücreleri, kalbin birincil pacemaker'ı (ritim oluşturucusu) olup kendi kendilerine otomatik olarak depolarize olabilme (aksiyon potansiyeli üretme) yeteneğine sahiptirler. SA düğüm hücresinin aksiyon potansiyelinde, zar potansiyelinin en düşük eksi (-) değere inmesinin ardından, yavaş yavaş tekrar eşik değere doğru kendi kendine yükselmesini (Faz 4 Spontan Depolarizasyon) sağlayan asıl elektriksel akım aşağıdakilerden hangisidir?","options":["Hızlı voltaj kapılı Sodyum (Na+) kanallarının açılması","Hücre dışına Potasyum (K+) sızıntısının artması","L-Tipi kalsiyum kanallarından masif Kalsiyum (Ca+2) girişi","Zarın hiperpolarizasyonuyla aktifleşen, içeriye Sodyum (Na+) ve Potasyum (K+) girişini sağlayan 'İf (Funny) akımı'","Na+/K+ ATPaz pompasının tamamen durması"],"correct":3,"exp":"Kalp kası hücreleri dışarıdan uyarı beklerken, Pacemaker (SA, AV) hücreleri hiç beklemez. Pacemaker aksiyon potansiyelinin en önemli sırrı 'Faz 4'tür (İstirahat fazı düz değildir, eğimlidir). Repolarizasyon sonrası hücre eksi (-60 mV) değerlere düştüğünde (Hiperpolarizasyon), bu hücrelerin zarında özel bir kanal açılır. Bu kanal eksi değerlerde çalışmayı sevdiği için fizyologlar ona şakacı/garip (Funny) adını vermiştir. 'İf (Funny) akımı', hücre içine sürekli Sodyum (ve biraz Potasyum) sızdırarak voltajı yavaş yavaş, kendi kendine eşik değere (-40 mV) doğru çeker. Eşiğe ulaşıldığında yavaş Kalsiyum kanalları (Faz 0) açılarak atım gerçekleşir. Sempatik sistem (Adrenalin) bu İf kanallarını daha hızlı açtırarak kalp atışını (nabzı) hızlandırır."},{"id":605,"ders":"Fizyoloji","konu":"Endokrin ve Genital Sistem HistoFizyolojisi","diff":4,"q":"Otuz beş yaşında kadın hasta, görme alanında daralma (bitemporal hemianopsi) ve ellerinde/ayaklarında büyüme (Akromegali) şikayetiyle başvuruyor. Kranial MRG'de hipofiz bezinde makroadenom saptanıyor. Tümör dokusunun histolojik boyanmasında, hücre sitoplazmalarının asidik boyaları (eozin) tutarak pembe-kırmızı renkte boyandığı görülüyor. Adenohipofizdeki (Ön Hipofiz) hücre boyanma paternleri dikkate alındığında, bu 'Asidofilik' boyanan tümör hücrelerinin salgılaması en muhtemel olan iki hormon aşağıdakilerden hangisinde doğru verilmiştir?","options":["ACTH ve TSH","Büyüme Hormonu (GH) ve Prolaktin","FSH ve LH","Melanosit Uyarıcı Hormon (MSH) ve ACTH","Antidiüretik Hormon (ADH) ve Oksitosin"],"correct":1,"exp":"Ön Hipofiz (Adenohipofiz) hücreleri histolojik boyanmalarına göre 3'e ayrılır: Asidofiller (pembe/kırmızı), Bazofiller (mor/mavi) ve Kromofoblar (boyanmayanlar). Hatırlamak için 'B-FLAT' kuralı kullanılır. Bazofiller: FSH, LH, ACTH ve TSH üretirler. Geriye kalan iki majör hormon olan 'Büyüme Hormonu (Somatotrop)' ve 'Prolaktin (Laktotrop)', ASİDOFİLİK hücreler tarafından üretilir. Akromegali hastasındaki büyüme hormonu salgılayan tümör bu nedenle histolojide asidofilik (eozinofilik) bir adenomdur. (Not: ADH ve Oksitosin Arka Hipofizden -nörohipofiz- salınır, sentezleri ise hipotalamustadır)."},{"id":606,"ders":"Fizyoloji","konu":"Endokrin ve Genital Sistem HistoFizyolojisi","diff":4,"q":"Tiroid bezinin histolojik kesitleri incelendiğinde, kanda kalsiyum seviyesini düşürmekle görevli 'Kalsitonin' hormonunu sentezleyen 'Parafoliküler (C) hücreleri' gözlenmektedir. Bu hücrelerin embriyolojik kökeni ve tiroid dokusu içindeki anatomik yerleşimi aşağıdakilerden hangisinde doğru ifade edilmiştir?","options":["Endoderm kökenlidirler / Folikül lümeni (kolloid) ile doğrudan temas halindedirler","Nöral Krest hücrelerinden köken alırlar / Folikül epiteli ile bazal lamina arasında (veya foliküller arası bağ dokuda) yer alırlar, lümene (koloide) ASLA temas etmezler","Yüzey Ektodermi kökenlidirler / Folikül epitelinin tam ortasında silyalı hücre olarak bulunurlar","Mezoderm kökenlidirler / Tiroid kapsülünün dışında, paratiroid bezine yapışık bulunurlar","Nöral Tüp kökenlidirler / Doğrudan kan damarlarının lümenine bakarlar"],"correct":1,"exp":"Tiroid bezi iki farklı hormon üreten iki farklı hücre popülasyonuna sahiptir. 1) Foliküler hücreler: Endoderm kökenlidir (dil kökünden inerler), T3/T4 üretirler ve ortadaki göle (Kolloid) doğrudan temas ederler. 2) Parafoliküler C hücreleri: Embriyolojik olarak 4. yutak cebinden göç eden 'Nöral Krest (Krista)' hücrelerinden köken alırlar. Kalsitonin üretirler. Histolojik yerleşimleri çok spesifiktir: Folikülü saran bazal membranın (lamina bazalis) İÇİNDE, epitel hücrelerinin arasında veya foliküller arası bağ dokuda bulunurlar ancak APİKAL YÜZEYLERİ ASLA KOLLOİDE (Lümene) DEĞMEZ. Bu yüzden onlara para-foliküler (folikül yanı) denir. Medüller Tiroid Kanseri bu hücrelerden gelişir."},{"id":607,"ders":"Fizyoloji","konu":"Endokrin ve Genital Sistem HistoFizyolojisi","diff":4,"q":"Böbrek üstü bezinin (Adrenal Gland) korteks tabakası dıştan içe doğru üç ayrı zondur: Zona Glomeruloza, Zona Fasikülata ve Zona Retikülaris. Renin-Anjiyotensin sisteminin ürünü olan Anjiyotensin II ve kanda artan Potasyum (K+) iyonları, adrenal korteksin hangi tabakasını spesifik olarak uyararak ilgili steroid hormonun salınımını tetikler?","options":["Zona Fasikülata'yı uyararak Kortizol salınımı","Zona Retikülaris'i uyararak DHEA (Androjen) salınımı","Zona Glomeruloza'yı uyararak Aldosteron salınımı","Adrenal Medulla'yı uyararak Adrenalin salınımı","Kromaffin hücreleri uyararak Noradrenalin salınımı"],"correct":2,"exp":"Adrenal korteksin 3 tabakası vardır ve her birinin uyarılma mekanizması (patronu) farklıdır. (Dıştan içe: G-F-R). 1) Zona Glomeruloza (En dış tabaka): Mineralokortikoid olan 'Aldosteron' (Tuz hormonu) üretir. Bu tabakanın patronu (uyarıcısı) Hipofizdeki ACTH DEĞİLDİR; patron 'Anjiyotensin II' ve 'Hiperkalemi (Artmış K+)'dir. 2) Zona Fasikülata (Orta/Kalın tabaka): Glukokortikoid olan 'Kortizol' (Şeker hormonu) üretir. Patronu %100 hipofizden gelen ACTH'dır. 3) Zona Retikülaris (İç tabaka): Seks hormonları (DHEA/Androjen) üretir. Patronu yine ACTH'dır. (GFR -> Salt, Sugar, Sex)."},{"id":608,"ders":"Fizyoloji","konu":"Endokrin ve Genital Sistem HistoFizyolojisi","diff":4,"q":"Hipoglisemi atakları ile araştırılan bir hastada kanda yüksek İnsülin düzeyleri tespit ediliyor. Bu durumun hastanın dışarıdan gizlice insülin iğnesi yapmasından (yapay/faktisyoz hipoglisemi) mı, yoksa hastanın kendi pankreasında bir insülinoma (tümör) olmasından mı kaynaklandığını anlamak için 'C-peptid' seviyesi ölçülüyor. Sağlıklı bir endokrin pankreasta (Langerhans adacıklarındaki Beta hücrelerinde) İnsülin sentezi sırasında C-peptid'in oluşum aşaması aşağıdakilerden hangisidir?","options":["Ribozomlarda mRNA okunurken Preproinsülinden sinyal peptidinin kesilmesiyle oluşur.","Golgi aygıtında veya salgı veziküllerinin içinde, paketlenmiş olan 'Proinsülin' molekülünün spesifik proteazlarla kesilerek İnsülin ve C-peptid'e ayrılmasıyla oluşur.","İnsülinin kanda dolaşırken albümine bağlanması için gerekli olan ve karaciğerde eklenen bir taşıyıcı proteindir.","Alfa hücrelerinde glukagon yıkımı sırasında yan ürün olarak ortaya çıkar.","İnsülin reseptörüne bağlandıktan sonra hücre içinde yıkılmasıyla kana karışan bir metabolittir."],"correct":1,"exp":"Endojen (vücudun kendi ürettiği) insülinin marker'ı C-peptid'dir. Pankreas beta hücresi insülini sıfırdan yaparken şu yolları izler: Ribozomda üretilen ilk koca molekül 'Preproinsülin'dir. ER lümeninde başındaki sinyal dizisi kesilip atılır ve 'Proinsülin' adını alır. Proinsülin, katlanmış ve A, B, C zincirlerinden oluşan tek parça bir iptir. Bu proinsülin, Golgi'ye gelip sekretuvar granüllere (veziküllere) hapsedildiğinde içindeki enzimler (proteazlar) makasla aradaki bağı keser. Ortaya A ve B zincirinin birleşmesiyle oluşan gerçek 'İnsülin' ile, aradan koparılıp atılan 'C-Peptid (Connecting peptide)' çıkar. Hücre vezikülü boşalttığında kana İnsülin ve C-Peptid 1:1 (eşit molekül) oranında salınır. Dışarıdan eczane iğnesiyle vurulan insülinde sadece saf insülin vardır, C-peptid yoktur. Eğer hastada insülin yüksek ama C-peptid düşükse hasta iğne vuruyordur; ikisi de yüksekse tümör (insülinoma) vardır."},{"id":609,"ders":"Fizyoloji","konu":"Endokrin ve Genital Sistem HistoFizyolojisi","diff":4,"q":"Karanlık ortamda Melatonin hormonu salgılayarak sirkadiyen ritmimizi (uyku-uyanıklık döngüsünü) düzenleyen Pineal Bez (Epifiz Bezi), histolojik olarak incelendiğinde yaşla birlikte artış gösteren çok spesifik radyolojik/histolojik yapılara sahiptir. Çoğunlukla kalsiyum fosfat ve kalsiyum karbonat birikimlerinden oluşan, beynin tam orta hattında yer aldığı için radyolojik görüntülerde (BT/Röntgen) 'orta hat kaymasını' değerlendirmekte işaretçi (marker) olarak kullanılan bu yapılar aşağıdakilerden hangisidir?","options":["Negri cisimcikleri","Corpora amylacea (Amiloid cisimcikler)","Corpora arenacea (Beyin kumu / Acervuli cerebri)","Lewy cisimcikleri","Psammoma cisimcikleri"],"correct":2,"exp":"Pineal bez (Epifiz), diensefalonda yer alan ve karanlıkta Melatonin üreten nöroendokrin bir organdır. Bu bezin histolojisinin en büyük özelliği, parankimi içinde yaş ilerledikçe artan kalsifiye (kireçlenmiş) kalsiyum fosfat çökeltileridir. Bu yapılara 'Corpora arenacea', 'Acervuli cerebri' veya Türkçe adıyla 'Beyin Kumu (Brain sand)' denir. Klinik/Radyolojik önemi çok büyüktür: Pineal bez beynin tam geometrik merkezindedir ve bu beyin kumları kireçli olduğu için tomografide (BT) veya röntgende bembeyaz parlar. Acile kafa travmasıyla gelen bir hastanın filmine bakıldığında, bu beyaz nokta (beyin kumu) tam ortada değil de sağa/sola kaymışsa (Shift), beynin bir tarafında kanama veya tümör olduğu ve beyni ittiği şipşak anlaşılır."},{"id":610,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"Otuzuncu gebelik haftasında doğan prematüre bir bebek, doğumdan kısa süre sonra şiddetli solunum sıkıntısı (Respiratuar Distres Sendromu) geliştiriyor. Bebeğin akciğerlerinde Tip II pnömositlerden salgılanan 'Sürfaktan' maddesinin yetersiz olduğu saptanıyor. Fizyolojik olarak sürfaktanın temel görevi olan 'alveollerin sönmesini (kollabe olmasını) engelleme' mekanizmasını açıklayan fiziksel yasa (yüzey gerilimi ile basınç ve yarıçap ilişkisi) aşağıdakilerden hangisidir?","options":["Boyle-Mariotte Yasası","Laplace Yasası","Poiseuille Yasası","Henry Yasası","Fick Difüzyon Yasası"],"correct":1,"exp":"Sürfaktanın fizyolojisi 'Laplace Yasası' ile açıklanır (P = 2T / r). Bu yasaya göre; içi sıvı ile kaplı küresel bir yapının (alveol) büzülmesini (çökmesini) sağlayan basınç (P), yüzey gerilimi (T) ile doğru, alveolün yarıçapı (r) ile ters orantılıdır. Yani küçük alveollerin büzülme eğilimi, büyük olanlara göre çok daha fazladır ve hava küçükten büyüğe kaçmak ister. Sürfaktan (Dipalmitoilfosfatidilkolin), alveol küçüldükçe molekülleri birbirine yaklaşarak yüzey gerilimini (T) dramatik şekilde DÜŞÜRÜR. Böylece küçük alveollerin içindeki çökme basıncı azalır ve nefes verirken sönmeleri (atelektazi) engellenir."},{"id":611,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"Solunum yollarının histolojik incelenmesinde, kıkırdak ve bez içermeyen, çapı 1 mm'den küçük olan terminal bronşiyollerin epiteline gelindiğinde Goblet hücrelerinin kaybolduğu görülür. Goblet hücrelerinin yerini, apikal kısımları lümene kubbe şeklinde taşan, silyasız ve sekretuvar granüller içeren spesifik hücreler alır. Solunan havadaki toksinleri (Sitokrom P450 enzimleri aracılığıyla) detoksifiye eden ve CC16 (Clara Hücre Proteini) salgılayan bu hücre aşağıdakilerden hangisidir?","options":["Tip I Pnömosit","Kulchitsky (Nöroendokrin) hücreleri","Fırçamsı (Brush) hücreler","Klara (Club / Clara) hücreleri","Alveoler makrofajlar"],"correct":3,"exp":"Solunum ağacı aşağıya doğru indikçe (Terminal bronşiyollere gelindiğinde) yapı değişir. Kıkırdak, bez ve Goblet (mukus) hücreleri kaybolur. (Çünkü o derinlikte mukus olsaydı hava yollarını tıkar ve atılamazdı). Goblet hücrelerinin yerini 'Klara (yeni adıyla Club) Hücreleri' alır. Silyasız, kubbe şeklindeki bu hücrelerin 3 önemli görevi vardır: 1) Sürfaktan benzeri bir madde salgılayarak bronşiyollerin yapışmasını önlemek. 2) İçerdikleri zengin Düz ER ve Sitokrom P450 enzimleri sayesinde havayla gelen toksinleri parçalamak (detoksifikasyon). 3) Kök hücre görevi görerek hasarlanan silyalı hücreleri yenilemek. Salgıladıkları CC16 proteini kanda akciğer hasar belirteci olarak kullanılır."},{"id":612,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"Alveol lümenindeki oksijenin kana, kandaki karbondioksitin ise alveol lümenine geçişi 'Kan-Gaz Bariyeri (Solunum Membranı)' üzerinden basit difüzyonla gerçekleşir. Gaz alışverişinin en optimum seviyede yapıldığı, solunum membranının EN İNCE (yaklaşık 0.2 mikrometre) bölgesini oluşturan histolojik katmanlar dıştan içe (alveolden kana doğru) hangi sırayla dizilmiştir?","options":["Tip II Pnömosit sitoplazması → İnterstisyel bağ dokusu → Endotel","Sürfaktan tabakası → Tip I Pnömosit sitoplazması → Ortak (kaynaşmış) bazal lamina → Kapiller Endotel sitoplazması","Alveoler makrofaj → Tip I Pnömosit → Fenestralı endotel","Sürfaktan tabakası → Tip II Pnömosit → Ayrı ayrı iki bazal lamina → Sinüzoidal endotel","Tip I Pnömosit → Elastik lif ağı → Kapiller Endotel"],"correct":1,"exp":"Kan-Gaz bariyeri akciğerin kalbidir ve Fick yasasına göre difüzyon hızını maksimize etmek için mükemmel incelikte tasarlanmıştır. En ince yerinde bağ dokusu YOKTUR. Sıralama alveol havasından kana doğru şöyledir: 1) Alveol yüzeyini döşeyen ince Sürfaktan sıvı tabakası. 2) Alveol duvarının %95'ini kaplayan yassı 'Tip I Pnömosit' hücresinin ince sitoplazması. 3) Hem epitelin hem de endotelin bazal laminalarının birbiriyle birleştiği 'Kaynaşmış (Fused) Bazal Lamina'. 4) Sürekli (fenestrasız) 'Kapiller Endotel' hücresinin ince sitoplazması. Bu dört katmanı aşan O2 doğrudan eritrositin içine girer."},{"id":613,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":5,"q":"Metabolizması yüksek olan periferik dokularda (örneğin egzersiz yapan kasta) üretilen bol miktardaki Karbondioksit (CO2), kapiller damarlara geçer ve eritrositlerin içine girer. Eritrosit içinde Karbonik Anhidraz enzimi CO2'yi suyla birleştirerek Bikarbonat (HCO3-) ve Hidrojen (H+) iyonlarına ayırır. Bikarbonatın eritrositten kan plazmasına çıkabilmesi için hücre zarı potansiyelini korumak amacıyla gerçekleşen ve 'Klor Şifti (Hamburger Fenomeni)' olarak bilinen olayda, eritrosit zarındaki 'Band 3' proteini (Anyon Değiştirici 1) hangi değişimi yapar?","options":["Bikarbonatı (HCO3-) dışarı atarken, karşılığında Klor (Cl-) iyonunu eritrosit İÇİNE alır.","Karbondioksiti (CO2) içeri alırken, Sodyum (Na+) iyonunu dışarı atar.","Bikarbonatı (HCO3-) içeri alırken, Klor (Cl-) iyonunu dışarı atar.","Hidrojen (H+) iyonunu dışarı atarken, Potasyum (K+) iyonunu içeri alır.","Klor (Cl-) iyonunu ve Suyu (H2O) eş zamanlı olarak dışarı atar."],"correct":0,"exp":"Karbondioksitin kanda taşınmasının en büyük (%70) yolu plazmada 'Bikarbonat (HCO3-)' formudur. Ancak bikarbonat eritrositin İÇİNDE üretilir. Üretilen eksi (-) yüklü bikarbonatın plazmaya çıkabilmesi için (hücre zarının elektriksel dengesinin bozulmaması adına) karşılığında dışarıdan içeriye bir başka eksi (-) yüklü iyon alınması gerekir. Bu görevi eritrosit zarındaki 'Band 3 (Anyon Değiştirici 1 - AE1)' proteini üstlenir. Bikarbonatı DIŞARI (plazmaya) atarken, plazmadaki Kloru (Cl-) eritrosit İÇİNE çeker. Buna Klor Kayması (Hamburger Fenomeni) denir. Bu nedenle venöz kandaki eritrositlerin içi, arteriyel kandakilere göre klor ve su çektiği için biraz daha şişkindir (Hematokrit venöz kanda hafifçe yüksektir)."},{"id":614,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"Ağır KOAH hastasında arteriyel kanda oksijen parsiyel basıncının (PaO2) 50 mmHg'ye (Hipoksemi) düşmesi, solunum merkezini uyararak hiperventilasyon başlatır. Oksijen düşüklüğünü (hipoksiyi) algılayan ve beyin sapına vagus/glossofaringeal sinirler aracılığıyla sinyal gönderen Periferik Kemoreseptörlerin (Örn: Glomus Caroticum / Karotis Cisimciği) içindeki Tip I Glomus hücrelerinin hipoksiye yanıt olarak verdikleri ilk hücresel/elektriksel tepki aşağıdakilerden hangisidir?","options":["Voltaj kapılı Sodyum (Na+) kanallarının açılması","Oksijene duyarlı Potasyum (K+) kanallarının KAPANMASI sonucu hücrenin depolarize olması","Hücre içi kalsiyum depolarının doğrudan tükenmesi","Adenilat siklaz aktivasyonuyla cAMP'nin düşmesi","Asetilkolin reseptörlerinin down-regülasyonu"],"correct":1,"exp":"Kan oksijeninin (PaO2) düşüklüğünü beyindeki santral kemoreseptörler ALGILAYAMAZ. Oksijen düşüklüğünü (<60 mmHg) algılayan TEK yer 'Periferik Kemoreseptörler'dir (Karotis cisimciği ve Aort cisimciği). Bu organların içindeki sensör hücrelere 'Tip I Glomus Hücreleri' denir. Oksijen basıncı 60 mmHg'nin altına düştüğünde, glomus hücresi zarında bulunan oksijene duyarlı özel 'Potasyum (K+) kanalları KAPANIR'. Potasyum dışarı çıkamayınca hücrenin içi pozitifleşir (Depolarizasyon). Depolarizasyon, Voltaj kapılı Kalsiyum (Ca+2) kanallarını açar. İçeri giren kalsiyum, nörotransmitter (Dopamin, ATP vb.) dolu vezikülleri ekzositozla sinaps boşluğuna döker ve solunum merkezine (DRG'ye) 'nefes al' sinyali gider."},{"id":615,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"Santral sinir sisteminde (MSS) nöronlara mekanik ve metabolik destek sağlayan nöroglia hücreleri bulunur. Kan damarları ile nöronlar arasında köprü kurarak nöronlara glukoz/laktat sağlayan, hücre dışı sıvıdaki fazla potasyumu (K+) temizleyen ve embriyolojik kökeni ektoderm (nöral tüp) olan bu glia hücresi; hasar durumunda çoğalarak skar dokusu (gliozis) oluşturur. Spesifik ara filaman belirteci GFAP (Glial Fibriler Asidik Protein) olan bu hücre aşağıdakilerden hangisidir?","options":["Oligodendrosit","Ependim hücresi","Astrosit","Mikroglia","Schwann hücresi"],"correct":2,"exp":"Santral sinir sisteminin en kalabalık ve en çok yönlü destek hücresi 'Astrositler'dir. Yıldız şeklindedirler. Uzantılarıyla (pediküller / ayaklar) kan damarlarını sararak Kan-Beyin Bariyerinin (BBB) bütünlüğünü sağlarlar. Kandaki glukozu alıp laktata çevirerek nöronu beslerler. Sinaptik aralığa dökülen nörotransmitterleri (Glutamat, GABA) ve fazla potasyumu (Spatial buffering) temizleyerek nöronun toksisiteye girmesini (eksitotoksisite) önlerler. Beyinde bir hasar (enfarkt vs.) olduğunda fibroblastlar gibi skar dokusu (Gliozis) oluştururlar. En önemli kimlik kartları (immünhistokimyasal marker) 'GFAP' proteinidir."},{"id":616,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"Sinir sisteminde aksiyon potansiyelinin sıçrayıcı (saltatorik) ve çok hızlı bir şekilde iletilmesini sağlayan yapı, aksonların etrafını saran lipidden zengin Miyelin Kılıftır. Santral Sinir Sisteminde (MSS) miyelin kılıfı üreten glia hücresi ile Periferik Sinir Sisteminde (PSS) miyelin kılıfı üreten glia hücresi arasındaki temel morfolojik / fonksiyonel fark aşağıdakilerden hangisinde doğru ifade edilmiştir?","options":["MSS'de Mikroglialar miyelin üretirken, PSS'de Satellit hücreler üretir.","MSS'de bir Astrosit sadece bir aksonu miyelinlerken, PSS'de bir Schwann hücresi birden fazla aksonu miyelinler.","MSS'de bir Oligodendrosit kendi uzantılarıyla aynı anda BİRDEN FAZLA (bazen 50'ye kadar) aksonun etrafına miyelin sarabilirken; PSS'de bir Schwann hücresi sadece TEK bir aksonun tek bir internod bölgesini miyelinleyebilir.","MSS'deki miyelin yapısında Ranvier boğumları bulunmazken, PSS'dekilerde bulunur.","MSS miyelini nöral krestten köken alırken, PSS miyelini mezodermden köken alır."],"correct":2,"exp":"Miyelinizasyon MSS ve PSS'de farklı hücreler tarafından yapılır. Santral Sinir Sisteminde (Beyin, Omurilik) miyelini 'Oligodendrositler' yapar. Bir Oligodendrosit ahtapot gibidir; kolları (uzantıları) ile çevresinden geçen 30-50 farklı aksonu aynı anda sarabilir (Bu nedenle Multipl Skleroz gibi otoimmün bir hastalıkta bir oligodendrosit ölünce onlarca akson çıplak kalır). Periferik Sinir Sisteminde (Kraniyal/Spinal sinirler) ise miyelini 'Schwann Hücreleri' yapar. Schwann hücresi tembeldir; gövdesiyle birlikte gidip sadece TEK BİR aksonun, küçücük bir parçasına (tek bir internoda) sarılır (Bir aksonu miyelinlemek için binlerce Schwann hücresi yan yana dizilmelidir)."},{"id":617,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"Presinaptik nöronun uç kısmına (terminal buton) bir aksiyon potansiyeli ulaştığında, hücre zarı depolarize olur. Bu depolarizasyon, nörotransmitter dolu veziküllerin sinaptik boşluğa ekzositozla dökülmesini tetikler. Ekzositoz olayının (vezikül füzyonunun) gerçekleşebilmesi için presinaptik terminale GİRMESİ ZORUNLU olan iyon ve vezikül zarında bu iyonu algılayıp SNARE proteinlerini tetikleyen 'kalsiyum sensörü' protein aşağıdakilerden hangisidir?","options":["Sodyum (Na+) / Sinapsin","Klor (Cl-) / Sinaptobrevin","Kalsiyum (Ca+2) / Sinaptotagmin","Potasyum (K+) / Sintaksin","Magnezyum (Mg+2) / SNAP-25"],"correct":2,"exp":"Sinapslarda kimyasal iletim (nörotransmitter salınımı) Kalsiyum (Ca+2) bağımlıdır. Aksiyon potansiyeli (elektrik) akson ucuna gelince, uçtaki 'Voltaj Kapılı Kalsiyum (N veya P/Q tipi) kanalları' açılır. Hücre içine giren Kalsiyum, nörotransmitter vezikülünün zarında bulunan 'Sinaptotagmin' adlı proteine bağlanır. Sinaptotagmin bir kalsiyum sensörüdür; kalsiyumu bağlayınca şekil değiştirir ve vezikülü hücre zarına zımbalayan 'SNARE kompleksi' proteinlerini (Sinaptobrevin, Sintaksin, SNAP-25) kopararak vezikülün zardan dışarı fışkırmasını (ekzositoz) sağlar. (Not: Botulinum ve Tetanus toksinleri işte bu SNARE proteinlerini parçalayarak felç yaparlar)."},{"id":618,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"Santral sinir sisteminin ana inhibitör nörotransmitteri olan GABA (Gama-Aminobütirik Asit), post-sinaptik nöronun zarında bulunan GABAA reseptörlerine bağlandığında İnhibitör Post-Sinaptik Potansiyel (IPSP) oluşturur. GABAA reseptörünün uyarılmasıyla post-sinaptik nöronda inhibisyonu (hiperpolarizasyonu) sağlayan elektriksel/iyonsal değişim aşağıdakilerden hangisidir?","options":["Hücre içine Sodyum (Na+) kanallarının açılması","Hücre içine Klor (Cl-) kanallarının açılarak negatif iyonların içeri girmesi","Hücre dışına Kalsiyum (Ca+2) pompalanması","Hücre içine Kalsiyum (Ca+2) kanallarının açılması","Sodyum-Potasyum pompasının durdurulması"],"correct":1,"exp":"Sinapslarda iki tür yanıt oluşur: Eksitatör (EPSP - uyarıcı) ve İnhibitör (IPSP - baskılayıcı). Glutamat gibi uyarıcılar Sodyum (Na) kanallarını açarak hücreyi pozitifleştirir (depolarizasyon). Beynin en büyük freni olan GABA ise 'İnhibitör'dür. GABA, ligand kapılı bir iyon kanalı olan GABAA reseptörüne bağlandığında ortasındaki kapı açılır ve dışarıdaki eksi (-) yüklü 'Klor (Cl-)' iyonları hücre içine hücum eder. Hücre içi normalden daha da eksi/negatif (örneğin -70'den -80 mV'ye) hale gelir. Buna Hiperpolarizasyon (IPSP) denir. Hücre negatife gömüldüğü için artık uyarılması (aksiyon potansiyeli oluşturması) çok zorlaşır. (Benzodiazepinler ve Barbitüratlar bu klor kanalını daha çok açık tutarak sakinleştirici/uyku yapıcı etki gösterirler)."},{"id":619,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"Kan-Beyin Bariyeri (BBB), beyin dokusunu kandaki toksinlerden koruyan, endoteller arası 'Sıkı Bağlantılar (Tight junctions)' ve astrosit ayaklarından oluşan sıkı bir duvardır. Ancak beynin bazı özel bölgelerinde (Sirkümventriküler organlar) bu bariyer kasten YER ALMAZ. Kandaki hormonları, toksinleri ve osmolariteyi anında algılayabilmek için pencereli (fenestralı) kapillerlere sahip olan ve kandaki toksik maddeleri algılayarak KUSMA refleksini (Kemoreseptör Tetikleyici Zon - CTZ) başlatan sirkümventriküler organ aşağıdakilerden hangisidir?","options":["Pineal bez (Epifiz)","Nörohipofiz (Arka hipofiz)","Subfornikal organ","Area postrema","Organum vasculosum of lamina terminalis (OVLT)"],"correct":3,"exp":"Beyinde Kan-Beyin Bariyerinin OLMADIĞI 7 bölge (Sirkümventriküler organlar) vardır. Bu organlar kanın tadına bakmak veya kana hormon salgılamak için bilerek bariyere dahil edilmemişlerdir (Kapillerleri deliklidir). Dördüncü ventrikülün tabanında yer alan 'Area Postrema', beynin toksin dedektörüdür. Kan-beyin bariyeri olmadığı için kana karışan herhangi bir zehri, ilacı (örn: kemoterapi, apomorfin, digoksin zehirlenmesi) veya üremiyi anında algılar. Burası Kemoreseptör Tetikleyici Zon (CTZ) olarak bilinir. Toksini algıladığı anda beyin sapındaki kusma merkezini (nucleus tractus solitarius) uyararak hastayı KUSTURUR (Vücudu toksinden arındırma refleksi)."},{"id":620,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"Böbrekte kanın süzüldüğü 'Glomerüler Filtrasyon Bariyeri' üç tabakadan oluşur: Fenestralı endotel, Glomerüler Bazal Membran (GBM) ve Podosit ayakçıkları (Pediseller). Podosit ayakçıkları arasındaki boşlukları kapatarak süzülen proteinlere karşı en son (boyut ve yük) bariyerini oluşturan, NPHS1 geni tarafından kodlanan ve doğumsal eksikliğinde 'Fin Tipi Konjenital Nefrotik Sendrom'a yol açan kritik transmembran proteini aşağıdakilerden hangisidir?","options":["Podokalin","Tip IV Kollajen","Nefrin","Laminin","Fibronektin"],"correct":2,"exp":"Glomerül filtrasyon bariyerinin en dış ve en önemli elemanı Viseral Epitel Hücreleridir (Podositler). Podositlerin ayakçıkları (pediselleri) bazal membran üzerinde tıpkı fermuar dişleri gibi birbirine geçer. İki ayakçık arasındaki dar boşluğa (Slit por) bir zar gerilir: 'Yarık Diyaframı (Slit Diaphragm)'. Bu diyafram sıradan bir zar değildir; hücre iskeletine tutunan ve gözenekli bir yapı oluşturan devasa proteinlerden yapılmıştır. Bu yapının iskeletini ve ana omurgasını 'NEFRİN' proteini (NPHS1 geni kodlar) oluşturur. Nefrin yoksa, podositler süzgeci kuramaz ve anne karnından itibaren masif (ölümcül) protein kaçağı (Fin Tipi Konjenital Nefrotik Sendrom) gelişir."},{"id":621,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"Kan basıncı aniden yükseldiğinde böbreğe (glomerüle) gelen kan akımı (RBF) ve süzme hızı (GFR) artar. GFR arttığı için Henle kulbuna daha fazla sıvı ve sodyum-klorür (NaCl) yükü gelir. Distal tübülün başlangıcında yer alan özelleşmiş hücre grubu, lümenden geçen bu artmış NaCl yükünü algılar ve glomerüle 'Çok sıvı geliyor, akımı kıs' sinyali (Adenozin) göndererek afferent arteriyolü DARALTIR. 'Tübüloglomerüler Geribildirim (Feedback)' adı verilen bu oto-regülasyon mekanizmasının sensörü (algılayıcısı) olan Jukstaglomerüler Aparat hücresi aşağıdakilerden hangisidir?","options":["Ekstraglomerüler mezangial hücreler (Lacis hücreleri)","Makula Densa hücreleri","Jukstaglomerüler (Granüler) hücreler","Podositler","İnterkale hücreler"],"correct":1,"exp":"Böbreğin kendini koruma sistemi (Oto-regülasyon) Jukstaglomerüler Aparat (JGA) üzerinden yürür. JGA 3 hücreden oluşur: 1) Makula Densa: Distal tübül duvarındaki dar/uzun epitel hücreleridir. Görevi lümenden geçen idrarın 'NaCl (Tuz)' tadına bakmaktır (Sensör/Dedektör). 2) Jukstaglomerüler (JG) Granüler Hücreler: Afferent arteriyol duvarındaki düz kaslardır, 'Renin' salgılarlar. Eğer tansiyon artar, GFR fırlar ve tübüle çok tuzlu (NaCl) su gelirse; 'Makula Densa' bunu (NKCC2 pompasıyla içine alarak) algılar. Hücre şişer ve dışarıya 'Adenozin' salgılar. Adenozin, hemen yanındaki Afferent Arteriyolü kasar, böbreğe giren kanı azaltır ve GFR normale (aşağıya) çekilir."},{"id":622,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"Glomerülden süzülen ultrafiltratın içindeki organik besinlerin tamamına yakını (özellikle glukoz ve amino asitler) Proksimal Tübül'de geri emilir. Proksimal tübül hücrelerinin lümene bakan apikal zarında glukozun hücre içine alınmasını sağlayan spesifik taşıyıcı protein ve bu işlemin enerji/termodinamik mekanizması aşağıdakilerden hangisinde doğru verilmiştir?","options":["GLUT-1 taşıyıcısı ile kolaylaştırılmış difüzyon (Enerji harcamadan)","SGLT-2 (Sodyum-Glukoz Ko-transporter 2) taşıyıcısı ile Sekonder Aktif Taşıma (Na+ gradyenti kullanılarak)","Na+/K+ ATPaz pompası ile Primer Aktif Taşıma","GLUT-4 taşıyıcısı ile İnsülin bağımlı endositoz","H+/Glukoz antiportu ile zıt yönlü transport"],"correct":1,"exp":"Proksimal tübül histolojik olarak devasa fırçamsı kenarlara (mikrovilluslara) sahiptir. Sağlıklı bir insanda idrarda şeker (glukoz) SIFIRDIR, çünkü %100'ü proksimal tübülde geri emilir. Bu emilim hücrenin apikal zarında (lümene bakan yüzünde) bulunan SGLT-2 (Sodium-Glucose Linked Transporter 2) pompasıyla olur. Bu pompa 'Sekonder Aktif Taşıma' yapar: Kendi ATP'sini harcamaz; hücrenin arka kapısındaki (bazolateral zardaki) Na/K ATPaz'ın yarattığı 'Sodyum (Na) eksikliği/gradyentini' enerji olarak kullanır. Na idrardan hücreye girmek isterken, SGLT-2 'Eğer yanına bir glukoz alırsan geçmene izin veririm' der. Sodyum ve Glukoz el ele (symport) hücreye girer. (Not: Hücre içine giren bu glukoz, arka kapıdan kana GLUT-2 aracılığıyla kolaylaştırılmış difüzyonla geçer)."},{"id":623,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":5,"q":"Böbrek medullasında (öz bölgesinde) hiperozmolar (çok tuzlu) bir interstisyel alan yaratmak, idrarın konsantre edilebilmesi (suyun tutulabilmesi) için şarttır. Bu hiperozmolariteyi yaratan ve 'Zıt Akımlar Çoğaltıcı (Countercurrent Multiplier)' sisteminin ana motoru olan, SUYA TAMAMEN GEÇİRGENSİZ OLUP lümendeki tuzu (Na-K-2Cl) aktif olarak dokuya pompalayan Henle kulbu segmenti aşağıdakilerden hangisidir?","options":["Proksimal kıvrımlı tübül","Henle kulbunun inen ince kolu","Henle kulbunun çıkan kalın kolu (TAL)","Kortikal toplayıcı kanallar","Distal kıvrımlı tübül"],"correct":2,"exp":"Henle kulbunun iki kolu birbirinden tamamen zıt çalışır (Asimetri). 1) İnen İnce Kol: Sadece 'Suya' geçirgendir, tuza geçirgen değildir. Su medullaya kaçar, içindeki idrar yoğunlaşır/tuzlanır. 2) Çıkan Kalın Kol (Thick Ascending Limb - TAL): Burası idrar yoğunlaştırma mekanizmasının MOTORUDUR. En önemli özelliği SUYA KESİNLİKLE GEÇİRGENSİZ olmasıdır. Duvarında meşhur 'NKCC2 (Na-K-2Cl)' pompası vardır (Furosemid/Lasix'in vurduğu yer). Bu pompa lümendeki tüm tuzu (iyonları) çekip böbrek dokusuna (interstisyuma) atar. Suyu bırakıp tuzu çektiği için içindeki idrar giderek seyreltik (dilüe) hale gelirken, böbrek dokusu (medulla) muazzam tuzlu/hiperozmolar hale gelir. Bu tuzlu doku, daha sonra toplayıcı kanallardan ADH yardımıyla suyu geri emmek için kullanılacaktır."},{"id":624,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"İdrar yollarının (renal pelvis, üreter, mesane ve üretra başlangıcı) iç yüzeyini döşeyen Çok Katlı Değişici (Transizyonel) Epitelin (Üroepitel) en üst tabakasında bulunan devasa hücreler vardır. Bu hücrelerin apikal membranlarında 'Uroplakin' adı verilen özel protein plakları bulunur. İdrarın dokulara sızmasını (toksisitesini) %100 engelleyen sızdırmaz bir bariyer oluşturan ve mesane dolduğunda esneyerek yassılaşan (çift çekirdekli olabilen) bu yüzeyel hücre grubuna ne ad verilir?","options":["Kadeh hücreleri","Şemsiye (Umbrella) hücreleri","Bazal (Kök) hücreler","Klara (Club) hücreleri","Glogi hücreleri"],"correct":1,"exp":"Üroepitel (Transizyonel epitel), idrar yollarına özgü eşsiz bir epiteldir. Mesane boşken 5-6 katlı görünür, dolduğunda esneyerek 2-3 katlı ince bir zar haline gelir. Bu esnemeyi ve korumayı sağlayan, epitelin en üstündeki devasa 'Şemsiye (Umbrella / Dome)' hücreleridir. Şemsiye hücreleri altlarındaki hücreleri bir şemsiye gibi örterler (sıklıkla iki çekirdeklidirler). Asidik ve zehirli olan idrarın kana sızmasını önleyen mükemmel bir sızdırmazlıkları vardır. Bu sızdırmazlığı, apikal hücre zarlarında bulunan asimetrik kalınlıktaki 'Uroplakin' plakları ve aralarındaki çok sıkı bağlantılar (tight junctions) ile sağlarlar. (Mesane dolduğunda bu plaklar menteşe gibi açılarak yüzeyi genişletir)."},{"id":625,"ders":"Fizyoloji","konu":"Baş Boyun Embriyolojisi","diff":4,"q":"Yenidoğan muayenesinde belirgin mikrognati (küçük çene), dilin geriye kaçması (glossopitozis) ve U şeklinde yarık damak saptanıyor. Çekilen radyolojik görüntülemede orta kulak kemikçiklerinden malleus (çekiç) ve inkus (örs) kemiklerinin gelişmediği görülüyor. Pierre Robin sekansı/sendromu ile uyumlu bu konjenital anomalide, gelişim kusuru olan embriyolojik yapı ve bu yapıdan köken alan kasları inerve eden kranial sinir aşağıdakilerden hangisinde doğru verilmiştir?","options":["1. Faringeal Arkus / Nervus Trigeminus (CN V)","2. Faringeal Arkus / Nervus Facialis (CN VII)","3. Faringeal Arkus / Nervus Glossopharyngeus (CN IX)","1. Faringeal Cep (Pouch) / Nervus Vagus (CN X)","4. Faringeal Arkus / Nervus Vagus (CN X)"],"correct":0,"exp":"Baş ve boyun gelişiminin temel taşları Faringeal (Brankial) Arkuslardır. 1. Faringeal Arkus (Mandibular Arkus); kıkırdak yapısı olarak Meckel kıkırdağını içerir. Mandibula (alt çene), maksilla (üst çene), malleus ve inkus kemikleri bu arkustan gelişir. Çiğneme kaslarını (M. masseter, temporalis vb.) oluşturur ve siniri Nervus Trigeminus'tur (V3 - Mandibular dal). Pierre Robin veya Treacher Collins sendromlarında 1. arkus nöral krest hücrelerinin göç kusuru vardır; bu nedenle alt çene gelişemez (mikrognati) ve orta kulak kemikçikleri eksik kalır."},{"id":626,"ders":"Fizyoloji","konu":"Baş Boyun Embriyolojisi","diff":4,"q":"Beş yaşında erkek çocuk, boynunun tam orta hattında, tiroid kıkırdağının hemen üzerinde yer alan ve yutkunmakla (veya dilini dışarı çıkarmakla) yukarı doğru hareket eden ağrısız, kistik bir kitle nedeniyle getiriliyor. Tiroglossal kanal kisti (Duktus tiroglossus kisti) tanısı alan bu lezyonun embriyolojik olarak oluşumuna neden olan ve tiroid bezinin göç etmeye başladığı İLK anatomik başlangıç noktası (orijini) neresidir?","options":["3. faringeal cep (pouch)","Rathke kesesi","Dil kökündeki Foramen Çekum (Foramen caecum)","2. faringeal yarık (cleft)","Ultimobrankial cisim"],"correct":2,"exp":"Tiroid bezi, embriyolojik hayatta boynun altında (trakea önünde) oluşmaz. Tiroid, gelişimin 24. gününde ilkel yutağın tabanında, dil kökünde yer alan 'Foramen Çekum (Foramen caecum)' adı verilen bir noktadan epitelin kalınlaşmasıyla başlar. Buradan aşağıya, boyna doğru bir tüp (Duktus Tiroglossus) aracılığıyla göç eder. Normalde bu kanal tiroid yerine ulaştığında kaybolur. Ancak kapanmazsa, kanalın içinde sıvı birikerek boynun TAM ORTA HATTINDA 'Tiroglossal Kist' oluşur. Dil köküne hala bağlı olduğu için, hasta dilini çıkardığında veya yutkunduğunda kist yukarı doğru hareket eder."},{"id":627,"ders":"Fizyoloji","konu":"Baş Boyun Embriyolojisi","diff":5,"q":"Doğumda boynunun yan tarafında, sternokleidomastoid (SKM) kasının ön kenarında akıntılı bir delik saptanan yenidoğana 'Brankial Fistül (Servikal Fistül)' tanısı konuyor. Normal embriyolojik gelişim sırasında, 2., 3. ve 4. faringeal yarıkların (cleft) üzerini bir örtü gibi kapatarak bu boşlukları yok etmesi gereken, ancak bu hastada kapanmayıp kist/fistül oluşumuna neden olan embriyolojik doku hareketi aşağıdakilerden hangisidir?","options":["1. Faringeal Arkus mezenşiminin arkaya doğru büyümesi","2. Faringeal Arkusun mezenşiminin aşağıya doğru aşırı büyüyerek diğer yarıkları örtmesi","3. Faringeal Cepin (Pouch) dışarıya doğru fıtıklaşması","Maksiller çıkıntının orta hatta frontonazal çıkıntı ile birleşmesi","Nöral tüp ektoderminin boyun bölgesinde invajinasyonu"],"correct":1,"exp":"Boynun dış yüzeyini faringeal yarıklar (cleftler - ektoderm kökenli) oluşturur. 1. Yarık açık kalarak 'Dış Kulak Yolunu' oluşturur. Diğer yarıklar (2, 3 ve 4) ise boyunda açık KALMAMALIDIR. Gelişim sırasında '2. Faringeal Arkus' hızla aşağıya doğru büyür ve tıpkı bir şemsiye gibi 2., 3. ve 4. yarıkların üzerini örter. İçeride hapsolan bu boşluğa 'Sinüs Servikalis' denir ve kısa sürede tamamen kaybolur. Eğer 2. arkus bu yarıkları düzgün örtemezse veya sinüs kaybolmazsa, boynun yan tarafında (SKM önünde) lateral boyun kitleleri olan 'Brankial Kistler veya Fistüller' ortaya çıkar."},{"id":628,"ders":"Fizyoloji","konu":"Baş Boyun Embriyolojisi","diff":4,"q":"Tiroidektomi ameliyatı sonrası ses kısıklığı ve yutma güçlüğü gelişen hastada sol rekürren laringeal sinir felci saptanıyor. Larinks (gırtlak) kaslarını inerve eden bu sinirin embriyolojik kökeni incelendiğinde, bu sinirin ve uyardığı intrinsik larinks kaslarının (krikotiroid kas hariç) hangi faringeal arkustan (yutak kavsinden) köken aldığı bilinmektedir?","options":["1. Arkus","2. Arkus","3. Arkus","4. ve 6. Arkuslar","Sadece 3. Arkus"],"correct":3,"exp":"Faringeal arkusların kranial sinir eşleşmeleri çok klasiktir. 1. Arkus = CN V (Trigeminal, çiğneme). 2. Arkus = CN VII (Fasiyal, mimik kasları). 3. Arkus = CN IX (Glossofaringeal, M. stylopharyngeus). Larinksin (gırtlağın) tüm kıkırdakları ve kasları ise '4. ve 6. Faringeal Arkuslardan' köken alır (5. arkus insanda kaybolur). Bu arkusların siniri 'Nervus Vagus (CN X)'tur. Vagusun Superior Laringeal dalı 4. arkusu (M. krikotiroideus'u uyarır), Rekürren Laringeal dalı ise 6. arkusu (diğer tüm intrinsik larinks kaslarını) uyarır."},{"id":629,"ders":"Fizyoloji","konu":"Baş Boyun Embriyolojisi","diff":4,"q":"Yarık dudak ve yarık damak (Cleft lip and palate) anomalisi ile doğan bir bebeğin embriyolojik öyküsü inceleniyor. Yüz gelişiminin 5. ve 6. haftalarında gerçekleşen birleşme (füzyon) kusurları bu anomalilere yol açar. İzole 'Yarık Dudak' (Tavşan dudak) anomalisinin temelinde, üst dudağın bütünlüğünü sağlamak için hangi iki yüz çıkıntısının orta hatta birleşememesi yatmaktadır?","options":["Lateral nazal çıkıntılar ile Maksiller çıkıntılar","Medial nazal çıkıntılar ile Maksiller çıkıntılar","Her iki Mandibular çıkıntının tam ortada birleşememesi","Maksiller çıkıntılar ile Palatin (damak) raflarının birleşememesi","Frontonazal çıkıntı ile Lateral nazal çıkıntılar"],"correct":1,"exp":"Yüz embriyolojisinde üst dudağın oluşumu spesifik çıkıntıların birleşmesine bağlıdır. Üst dudağın orta kısmını (filtrum) 'Medial Nazal Çıkıntılar' oluştururken, üst dudağın sağ ve sol yan kısımlarını 'Maksiller Çıkıntılar' oluşturur. Normal gelişimde bu iki yapı (Medial Nazal + Maksiller) karşılıklı gelerek sıkıca kaynaşır. Eğer mezenşim hücreleri bu bölgeye göç edemez ve bu yapılar birleşemezse, üst dudakta bir yarık kalır (Yarık Dudak / Cleft lip). Damak yarığı (Cleft palate) ise daha arkada, maksiller çıkıntılardan uzanan 'Palatin rafların (çıkıntıların)' orta hatta birleşememesi sonucu oluşur."},{"id":2338,"ders":"Fizyoloji","konu":"Hücre Histolojisi ve Fizyolojisi","diff":4,"q":"Yoğun bakımda hiperkalemi gelişen bir hastanın EKG'sinde QRS genişlemesi ve iletim yavaşlaması izleniyor. Bu tablonun hücre düzeyinde en iyi açıklaması aşağıdakilerden hangisidir?","options":["Hücre dışı potasyum artışı istirahat membran potansiyelini daha negatif hale getirir","Hücre dışı potasyum artışı membranı kısmen depolarize ederek voltaj kapılı sodyum kanallarının bir kısmını inaktive eder","Potasyum artışı sodyum-potasyum pompasını tamamen durdurur ve tüm hücreler hiperpolarize olur","Potasyum artışı kalsiyum kanallarını kapatarak aksiyon potansiyeli süresini uzatır","Potasyum artışı klor girişini artırarak membranı stabilize eder"],"correct":1,"exp":"Ekstrasellüler K+ artışı istirahat membran potansiyelini daha az negatif yapar. Sürekli kısmi depolarizasyon hızlı Na+ kanallarını inaktive eder; özellikle kalpte iletim yavaşlar ve QRS genişleyebilir."},{"id":2339,"ders":"Fizyoloji","konu":"Hücre Histolojisi ve Fizyolojisi","diff":3,"q":"Hipotonik sıvı verilen bir eritrosit süspansiyonunda eritrositlerin şişerek hemolize olduğu görülüyor. Bu olayda suyun hücre içine geçişini belirleyen temel fiziksel güç hangisidir?","options":["Proteinlerin aktif olarak su pompalaması","Hücre içi ve dışı partikül yoğunluğu farkına bağlı ozmotik gradyan","Eritrosit membranındaki hemoglobinin suyu bağlaması","Sodyumun hemoglobine kovalent bağlanması","Plazma pH'sının eritrosit membranını eritmesi"],"correct":1,"exp":"Su, yarı geçirgen membran boyunca ozmotik olarak daha yoğun partikül içeren tarafa hareket eder. Hipotonik ortamda hücre dışı ozmolalite düşük olduğu için su eritrosite girer ve hemoliz oluşabilir."},{"id":2340,"ders":"Fizyoloji","konu":"Hücre Histolojisi ve Fizyolojisi","diff":4,"q":"Tip 1 diyabetli bir hastada insülin eksikliği nedeniyle kas ve yağ dokusuna glukoz girişi azalıyor. Aynı glukoz düzeyinde nöronların glukoz kullanımı ise belirgin şekilde korunuyor. Bu fark en iyi hangi taşıyıcı özelliğiyle açıklanır?","options":["Kas hücresinde GLUT1'in sadece hipoglisemide çalışması","Adipoz ve iskelet kasında GLUT4 translokasyonunun insüline bağımlı olması","Nöronlarda glukozun yalnızca sodyumla birlikte taşınması","Karaciğerde GLUT4'ün insülin olmadan aktive olması","Eritrositte glukoz girişinin ATP gerektirmesi"],"correct":1,"exp":"GLUT4 iskelet kası ve yağ dokusunda insülinle membrana taşınır. Beyin gibi bazı dokularda glukoz alımı insülinden büyük ölçüde bağımsız GLUT taşıyıcılarıyla sürer."},{"id":2341,"ders":"Fizyoloji","konu":"Hücre Histolojisi ve Fizyolojisi","diff":4,"q":"Primer siliyer diskinezi düşünülen çocukta kronik sinüzit, bronşiektazi ve infertilite öyküsü dikkat çekiyor. Bu hastada solunum yollarındaki mukus temizliğinin bozulmasına en doğrudan yol açan defekt hangisidir?","options":["Aktin filamentlerinin Z çizgisine tutunamaması","Mikrotübül çiftlerinde dinein kol fonksiyonunun bozulması","Keratinin bazal membrana bağlanamaması","Kollajen tip IV sentezinin azalması","Elastinin fibrillin üzerinden düzenlenememesi"],"correct":1,"exp":"Hareketli silyaların vuru hareketi mikrotübül-dinein sistemiyle sağlanır. Dinein kol defekti mukosiliyer klirensi ve sperm motilitesini bozar; Kartagener fenotipi görülebilir."},{"id":2342,"ders":"Fizyoloji","konu":"Hücre Histolojisi ve Fizyolojisi","diff":4,"q":"Hipoglisemi sonrası glukagon düzeyi artan hastada hepatositlerde kısa sürede glikojen yıkımı başlıyor. Aynı reseptör ailesi üzerinden kalp hızını artıran katekolamin etkisi de oluşabiliyor. Bu yanıtta baskın ikinci haberci hangisidir?","options":["cGMP","cAMP","IP3 olmadan doğrudan nükleer reseptör aktivasyonu","Tirozin kinaz otofosforilasyonu","JAK-STAT aktivasyonu"],"correct":1,"exp":"Glukagon ve beta-adrenerjik uyarı Gs üzerinden adenilat siklazı aktive eder; cAMP artar ve PKA aracılığıyla glikojenoliz gibi yanıtlar gelişir."},{"id":2343,"ders":"Fizyoloji","konu":"Hücre Histolojisi ve Fizyolojisi","diff":4,"q":"Parathormon etkisiyle hedef hücre içinde kalsiyum sinyalinin arttığı ve protein kinaz C yolunun aktive olduğu bir yanıt izleniyor. Bu hücre içi olaylar en çok hangi sinyal yolu ile uyumludur?","options":["Gi aracılı adenilat siklaz inhibisyonu","Gq aracılı fosfolipaz C aktivasyonu ve IP3-DAG oluşumu","Ligand kapılı klor kanalı açılması","Steroid hormon reseptörünün DNA'ya bağlanması","Reseptör tirozin kinazın GLUT4'ü membrana taşıması"],"correct":1,"exp":"Gq proteinleri fosfolipaz C'yi aktive eder. PIP2'den IP3 ve DAG oluşur; IP3 hücre içi Ca2+ artışını, DAG ise PKC aktivasyonunu sağlar."},{"id":2344,"ders":"Fizyoloji","konu":"Hücre Histolojisi ve Fizyolojisi","diff":3,"q":"Viral enfeksiyon sonrası gereksiz inflamasyon gelişmeden, tek tek hücrelerin küçülerek parçalandığı ve makrofajlarca temizlendiği görülüyor. Bu hücresel ölüm şekli için en tipik özellik hangisidir?","options":["Membran bütünlüğünün erken kaybı ve yaygın nötrofil yanıtı","Kaspaz aktivasyonu ile programlı hücre ölümü","Lizozomal enzimlerin tüm dokuya yayılması","Sadece ATP tamamen bittikten sonra başlaması","Kompleman aktivasyonu olmadan gerçekleşememesi"],"correct":1,"exp":"Apoptoz programlı hücre ölümüdür; kaspaz aktivasyonu, hücre büzüşmesi ve apoptotik cisimcikler görülür. Membran bütünlüğü korunduğu için inflamasyon belirgin değildir."},{"id":2345,"ders":"Fizyoloji","konu":"Hücre Histolojisi ve Fizyolojisi","diff":5,"q":"Kalp kasında komşu hücrelerin senkron kasılmasını sağlayan elektriksel bağlantı bozulduğunda iletim yavaşlıyor. Bu işlevi sağlayan hücre bağlantısı aşağıdakilerden hangisidir?","options":["Desmozom","Hemidesmozom","Gap junction","Tight junction","Fokal adezyon"],"correct":2,"exp":"Gap junctionlar iyonların hücreler arasında doğrudan geçişine izin verir. Kalp kasında interkale disklerdeki gap junctionlar elektriksel eşleşmeyi sağlar."},{"id":2346,"ders":"Fizyoloji","konu":"Doku Histolojisi ve Fizyolojisi","diff":3,"q":"İnce bağırsak epitelinde lümen içeriğinin hücreler arasından serbest geçişi engelleniyor. Bu bariyerin bozulması durumunda paracellular geçirgenliğin artması beklenir. İlgili bağlantı kompleksi hangisidir?","options":["Desmozom","Zonula occludens","Hemidesmozom","Gap junction","Fokal adezyon"],"correct":1,"exp":"Zonula occludens, yani tight junction, epitel hücreleri arasında paracellular geçişi sınırlar ve hücre polaritesinin korunmasına katkı verir."},{"id":2347,"ders":"Fizyoloji","konu":"Doku Histolojisi ve Fizyolojisi","diff":4,"q":"Osteogenezis imperfekta tanılı çocukta tekrarlayan kırıklar ve mavi sklera var. Bu hastada en çok etkilenen bağ dokusu proteini hangisidir?","options":["Tip I kollajen","Tip II kollajen","Tip IV kollajen","Elastin","Fibronektin"],"correct":0,"exp":"Kemik, tendon, dermis ve sklerada başlıca tip I kollajen bulunur. Osteogenezis imperfektada tip I kollajen kusuru kırık eğilimi ve mavi skleraya yol açar."},{"id":2348,"ders":"Fizyoloji","konu":"Doku Histolojisi ve Fizyolojisi","diff":3,"q":"Eklem kıkırdağı hasarı olan hastada iyileşmenin oldukça sınırlı olduğu belirtiliyor. Bu dokunun yavaş iyileşmesini en iyi açıklayan özellik hangisidir?","options":["Kıkırdak dokunun yüksek damar yoğunluğuna sahip olması","Kondrositlerin kanla doğrudan temas etmesi","Kıkırdak dokunun avasküler olması ve beslenmenin difüzyonla sağlanması","Kıkırdakta tip I kollajenin hiç bulunmaması","Sinovyal sıvının mitozu tamamen durdurması"],"correct":2,"exp":"Kıkırdak avasküler bir dokudur. Kondrositler matriks içinde difüzyonla beslenir; bu nedenle rejenerasyon kapasitesi sınırlıdır."},{"id":2349,"ders":"Fizyoloji","konu":"Doku Histolojisi ve Fizyolojisi","diff":4,"q":"Yanık sonrası iyileşen dokuda başlangıçta zayıf granülasyon dokusu oluşuyor, zamanla skar dokusunun dayanıklılığı artıyor. Bu süreçte erken dönemde daha fazla olup sonradan yerini daha güçlü kollajene bırakan tip hangisidir?","options":["Tip I kollajen","Tip II kollajen","Tip III kollajen","Tip IV kollajen","Tip VII kollajen"],"correct":2,"exp":"Yara iyileşmesinin erken döneminde granülasyon dokusunda tip III kollajen artar. Zamanla tip I kollajen birikimi artar ve skar dayanıklılığı yükselir."},{"id":2350,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":4,"q":"Yoğun egzersizde iskelet kası lifinde aksiyon potansiyeli T-tübül boyunca ilerliyor ve kasılma başlıyor. Aktin-miyozin etkileşimini doğrudan başlatan olay hangisidir?","options":["Kalsiyumun troponin C'ye bağlanarak tropomiyozin blokajını kaldırması","Asetilkolinin doğrudan miyozin başını fosforile etmesi","Sodyumun sarkoplazmik retikuluma bağlanması","ATP'nin aktine kalıcı bağlanması","Klorun T-tübülden hücre dışına çıkması"],"correct":0,"exp":"İskelet kasında SR'den salınan Ca2+ troponin C'ye bağlanır. Tropomiyozin aktin üzerindeki miyozin bağlanma bölgelerinden çekilir ve çapraz köprü döngüsü başlar."},{"id":2351,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":4,"q":"Bağırsak düz kasında parasempatik uyarı sonrası tonus artıyor. Bu kasılmada kalsiyumun bağlandığı ve miyozin hafif zincir kinazını aktive eden protein hangisidir?","options":["Troponin C","Kalmodulin","Distrofin","Nebulin","Titin"],"correct":1,"exp":"Düz kasta troponin yoktur. Ca2+ kalmoduline bağlanır; Ca-kalmodulin kompleksi MLCK'yi aktive eder ve miyozin hafif zinciri fosforile edilerek kasılma başlar."},{"id":2352,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":5,"q":"Malign hipertermi yatkınlığı olan hastada halotan sonrası hızla kas rijiditesi, hipertermi ve metabolik asidoz gelişiyor. Bu tabloda iskelet kası içinde kontrolsüz artan iyon hangisidir?","options":["Sodyum","Potasyum","Kalsiyum","Klor","Magnezyum"],"correct":2,"exp":"Malign hipertermide ryanodin reseptörüyle ilişkili kontrolsüz SR kalsiyum salınımı olur. Sürekli kas kontraksiyonu, ATP tüketimi, ısı artışı ve asidoz gelişir."},{"id":2353,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":4,"q":"Ölümden birkaç saat sonra kaslarda rijidite gelişiyor. ATP üretiminin durmasıyla çapraz köprü döngüsünde hangi basamak aksar?","options":["Miyozinin aktinden ayrılması","Kalsiyumun troponine bağlanması","Aksiyon potansiyelinin T-tübüle ulaşması","Asetilkolinin sinaptik aralığa salınması","Tropomiyozinin aktini örtmesi"],"correct":0,"exp":"ATP, miyozin başının aktinden ayrılması için gereklidir. ATP yokluğunda aktin-miyozin köprüleri ayrılamaz ve rigor mortis gelişir."},{"id":2354,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":4,"q":"Myastenia gravisli bir hastada tekrarlayan bakış yukarı testinde pitoz belirginleşiyor. Bu bulgunun temel nedeni aşağıdakilerden hangisidir?","options":["Motor nöronların tamamen kaybı","Nöromüsküler kavşakta güvenlik faktörünün azalması","Kas hücresinde distrofın sentezinin artması","Presinaptik asetilkolin sentezinin kalıcı olarak durması","Kas iğciğinde Ia afferent aktivitesinin artması"],"correct":1,"exp":"Myastenia graviste postsinaptik nikotinik ACh reseptörleri azalır. Tekrarlayan kullanımda uç plak potansiyeli eşik altına düşer ve fatigabilite ortaya çıkar."},{"id":2355,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":3,"q":"Botulinum toksini maruziyeti sonrası diplopi, disfaji ve simetrik güçsüzlük gelişen hastada refleksler azalıyor. Nöromüsküler kavşakta beklenen temel bozukluk hangisidir?","options":["Asetilkolin reseptörlerinin aşırı uyarılması","Presinaptik veziküllerden asetilkolin salınımının engellenmesi","Asetilkolinesterazın geri dönüşsüz inhibisyonu","Miyozin ATPaz aktivitesinin artması","Kas sarkolemmasında potasyum kanallarının kapanması"],"correct":1,"exp":"Botulinum toksini SNARE proteinlerini etkileyerek presinaptik ACh salınımını engeller. Sonuçta flask paralizi gelişir."},{"id":2356,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":4,"q":"Bir kas lifinde ardışık uyarılar gevşeme tamamlanmadan verildiğinde kasılma kuvveti giderek artıyor ve sürekli kasılmaya yaklaşıyor. Bu durum iskelet kasında hangi özellikle açıklanır?","options":["Aksiyon potansiyelinin çok uzun plato fazına sahip olması","Sarkoplazmada kalsiyumun tam uzaklaştırılamadan yeniden artması","Troponinin yalnızca tek uyarıda çalışması","Kas lifinin refrakter döneminin tüm kasılma süresinden uzun olması","Miyozin başlarının ATP'den bağımsız çalışması"],"correct":1,"exp":"İskelet kasında aksiyon potansiyeli kısa, kasılma süresi daha uzundur. Ardışık uyarılarda Ca2+ birikimi olur, summasyon ve tetanus gelişebilir."},{"id":2357,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":4,"q":"Kalp kasında kasılma kuvveti hücre dışı kalsiyum değişikliklerinden iskelet kasına göre daha fazla etkileniyor. Bu farkın en önemli nedeni hangisidir?","options":["Kalp kasında troponin bulunmaması","Kalp kasında kalsiyumun önemli bölümünün L tipi kanallardan hücre içine girmesi ve SR salınımını tetiklemesi","Kalp kasında T-tübüllerin hiç bulunmaması","Kalp kasında aktin-miyozin etkileşiminin ATP gerektirmemesi","Kalp kasında sarkoplazmik retikulumun aşırı geniş olması"],"correct":1,"exp":"Kalp kasında L tipi Ca2+ kanallarından hücre içine giren kalsiyum, ryanodin reseptörleri üzerinden SR'den kalsiyum salınımını tetikler. Bu nedenle ekstrasellüler Ca2+ önemlidir."},{"id":2358,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":3,"q":"Ağır bir yük kaldırılırken önce küçük motor üniteler, ihtiyaç arttıkça daha büyük motor üniteler devreye giriyor. Bu düzenlenmenin temel sonucu hangisidir?","options":["Kas gücünün kademeli ve kontrollü artırılması","Tüm liflerin aynı anda tetanik kasılması","Kasın oksijen kullanımının tamamen durması","Düz kasın iskelet kasına dönüşmesi","Motor nöron aksiyon potansiyelinin kaybolması"],"correct":0,"exp":"Motor ünite recruitment sayesinde kas kuvveti ihtiyaca göre kademeli artırılır. Küçük, dayanıklı ünitelerden büyük ve güçlü ünitelere doğru katılım olur."},{"id":2359,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":5,"q":"İzole kas deneyinde kas çok kısa veya aşırı gerilmiş durumdayken maksimal uyarıya rağmen gerilim düşük ölçülüyor. Orta uzunlukta ise kuvvet en yüksek. Bu gözlem hangi ilişkiyle açıklanır?","options":["Uzunluk-gerilim ilişkisi","Frank-Starling yasasının yalnızca böbrekte görülmesi","Fick difüzyon kanunu","Laplace yasası","Henderson-Hasselbalch ilişkisi"],"correct":0,"exp":"İskelet kasında optimal sarkomer uzunluğunda aktin-miyozin örtüşmesi en uygun olur ve maksimum aktif gerilim gelişir. Çok kısa veya çok uzun sarkomerde kuvvet azalır."},{"id":2360,"ders":"Fizyoloji","konu":"Genital Sistem HistoFizyolojisi","diff":4,"q":"İnfertilite değerlendirmesinde sperm sayısı düşük olan erkekte FSH yüksek, testosteron ise normal sınıra yakın bulunuyor. FSH'nin spermatogenezi destekleyen başlıca hedef hücresi hangisidir?","options":["Leydig hücresi","Sertoli hücresi","Epididim epitel hücresi","Prostat stromal hücresi","Miyoid hücre"],"correct":1,"exp":"FSH Sertoli hücrelerini uyarır; ABP üretimi ve spermatogenezin desteklenmesi bu hücreler üzerinden gerçekleşir. LH ise Leydig hücrelerinden testosteron sentezini artırır."},{"id":2361,"ders":"Fizyoloji","konu":"Genital Sistem HistoFizyolojisi","diff":4,"q":"Puberte sonrası testiste gelişen germ hücrelerini immün sistemden koruyan bariyer bozulursa antisperm antikor gelişebiliyor. Bu bariyeri oluşturan temel hücre bağlantıları hangi hücreler arasındadır?","options":["Leydig hücreleri arasında gap junctionlar","Sertoli hücreleri arasında tight junctionlar","Spermatidler arasında desmozomlar","Epididim hücreleri arasında hemidesmozomlar","Miyoid hücreler arasında zonula adherens"],"correct":1,"exp":"Kan-testis bariyeri Sertoli hücreleri arasındaki tight junctionlarla oluşur. Gelişen germ hücrelerini immün sistemden ayırır."},{"id":2362,"ders":"Fizyoloji","konu":"Genital Sistem HistoFizyolojisi","diff":4,"q":"Ovulasyona yakın dönemde servikal mukus daha bol, berrak ve geçirgen hale geliyor. Aynı dönemde sperm geçişinin kolaylaşması en çok hangi hormonal ortamla uyumludur?","options":["Progesteron baskınlığı","Östrojen baskınlığı","Prolaktin baskınlığı","Kortizol baskınlığı","Aldosteron baskınlığı"],"correct":1,"exp":"Östrojen ovulasyon öncesi servikal mukusu ince ve geçirgen hale getirir. Progesteron baskın olduğunda mukus daha koyu ve geçirgenliği düşük olur."},{"id":2363,"ders":"Fizyoloji","konu":"Genital Sistem HistoFizyolojisi","diff":4,"q":"Düzenli siklusu olan kadında ovulasyon sonrası endometrium bezleri kıvrımlı, sekresyonu artmış ve stromada ödem belirgin görülüyor. Bu histolojik görünüm en çok hangi hormonun etkisini gösterir?","options":["FSH","LH","Progesteron","İnhibin B","GnRH"],"correct":2,"exp":"Ovulasyon sonrası korpus luteumdan salgılanan progesteron endometriumda sekretuar fazı oluşturur. Bezler kıvrımlanır, sekresyon ve stromal ödem artar."},{"id":2364,"ders":"Fizyoloji","konu":"Genital Sistem HistoFizyolojisi","diff":4,"q":"Sperm kadın genital kanalında bir süre kaldıktan sonra zona pellucidaya bağlanma ve akrozomal reaksiyon kapasitesi kazanıyor. Bu işlevsel olgunlaşma en iyi hangi süreçle tanımlanır?","options":["Kapazitasyon","Gastrulasyon","Kortikal reaksiyon","Dekidualizasyon","Segmentasyon"],"correct":0,"exp":"Kapazitasyon, spermin kadın genital kanalında fertilizasyon yeteneğini kazanmasıdır. Membran özellikleri değişir ve akrozomal reaksiyon için uygun hale gelir."},{"id":2365,"ders":"Fizyoloji","konu":"Genital Sistem HistoFizyolojisi","diff":3,"q":"Doğum sonrası emzirme sırasında bebek memeyi emdiğinde süt kanallara doğru itiliyor. Süt üretimi normal olsa da bu refleks bozulursa süt boşalması azalır. Bu refleksi başlatan hormon hangisidir?","options":["Prolaktin","Oksitosin","FSH","Kortizol","Tiroksin"],"correct":1,"exp":"Prolaktin süt üretimini artırır; oksitosin ise meme mioepitelyal hücrelerini kasarak süt ejeksiyonunu sağlar."},{"id":2366,"ders":"Fizyoloji","konu":"Genital Sistem HistoFizyolojisi","diff":5,"q":"Uzun süreli düşük kalorili diyet yapan genç kadında amenore gelişiyor, gonadotropinler düşük bulunuyor. Bu tablo hangi fizyolojik düzenlenmenin baskılanmasıyla en iyi açıklanır?","options":["Sürekli yüksek frekanslı GnRH salınımı","Hipotalamik pulsatil GnRH salınımının azalması","Ovaryan aromataz aktivitesinin aşırı artması","Korpus luteumun kalıcı olarak büyümesi","Endometriumun progesterondan bağımsız sekresyona geçmesi"],"correct":1,"exp":"Enerji yetersizliği ve stres hipotalamik pulsatil GnRH salınımını baskılayabilir. LH/FSH düşer, ovulasyon bozulur ve hipotalamik amenore gelişir."},{"id":2367,"ders":"Fizyoloji","konu":"Genel Embriyoloji","diff":4,"q":"Gebeliğin 5. haftasında yüksek doz teratojen maruziyeti olan gebeye organ gelişimi açısından riskin yüksek olduğu söyleniyor. Bu dönemin özellikle riskli olmasının nedeni aşağıdakilerden hangisidir?","options":["İmplantasyonun henüz hiç başlamamış olması","Organogenez döneminde doku ve organ taslaklarının oluşması","Fetal büyümenin tamamlanmış olması","Plasentanın artık hiçbir maddeyi geçirmemesi","Tüm embriyonik hücrelerin totipotent kalması"],"correct":1,"exp":"Gebeliğin 3-8. haftaları organogenez açısından kritik dönemdir. Teratojen maruziyeti major yapısal anomalilere yol açabilir."},{"id":2368,"ders":"Fizyoloji","konu":"Genel Embriyoloji","diff":4,"q":"Gastrulasyon kusuru olan embriyoda üç germ yaprağının düzenli oluşamadığı belirtiliyor. Bu süreçte embriyo epiblast hücrelerinden hangi temel tabakaları oluşturur?","options":["Sadece ektoderm ve trofoblast","Ektoderm, mezoderm ve endoderm","Amniyon, koryon ve desidua","Sinsityotrofoblast ve sitotrofoblast","Nöral krest ve notokord olmadan yalnız mezoderm"],"correct":1,"exp":"Gastrulasyon epiblast hücrelerinden ektoderm, mezoderm ve endodermin oluştuğu temel süreçtir. Vücut planının ana eksenleri bu dönemde kurulur."},{"id":2369,"ders":"Fizyoloji","konu":"Genel Embriyoloji","diff":4,"q":"Perikonsepsiyonel folat kullanmayan gebede fetüste nöral tüp defekti saptanıyor. Bu tip defektlerin önlenmesi için folatın en kritik olduğu olay hangisidir?","options":["Nöral tüp kapanması","Akciğer surfaktan sentezi","Böbreklerin idrar üretmeye başlaması","Testislerin skrotuma inişi","Süt dişlerinin mineralizasyonu"],"correct":0,"exp":"Folat nöral tüp kapanması döneminde kritik önemdedir. Eksiklik spina bifida ve anensefali gibi nöral tüp defektleri riskini artırır."},{"id":2370,"ders":"Fizyoloji","konu":"Genel Embriyoloji","diff":3,"q":"Ultrasonda aynı plasentayı paylaşan, fakat iki ayrı amniyon kesesi bulunan ikiz gebelik izleniyor. Bu durum en çok hangi ayrılma zamanı ile uyumludur?","options":["Fertilizasyondan önce iki ayrı oositin ovulasyonu","Blastokist döneminde iç hücre kitlesinin ayrılması","Amniyon oluştuktan sonra embriyonik diskin ayrılması","Gastrulasyon tamamlandıktan sonra ayrılma","Plasenta oluşmadan önce iki ayrı spermle tek oosit döllenmesi"],"correct":1,"exp":"Monokoryonik-diamniyotik ikizlik genellikle blastokist döneminde, koryon oluştuktan sonra fakat amniyon oluşmadan önce iç hücre kitlesinin ayrılmasıyla gelişir."},{"id":2371,"ders":"Fizyoloji","konu":"Genel Embriyoloji","diff":4,"q":"Erken gebelik testinin pozitifleşmesini sağlayan hormon implantasyondan sonra trofoblast tarafından salgılanır ve korpus luteumu destekler. Bu hormon hangisidir?","options":["Progesteron","hCG","FSH","Oksitosin","Prolaktin"],"correct":1,"exp":"hCG sinsityotrofoblast tarafından salgılanır. LH benzeri etkiyle korpus luteumu sürdürür ve erken gebelikte progesteron üretiminin devamını sağlar."},{"id":2372,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":4,"q":"Kronik akciğer hastalığı olan hastada hematokrit yüksek, eritropoietin düzeyi artmış bulunuyor. Eritropoietin salgısını en çok uyaran değişiklik hangisidir?","options":["Arteriyel oksijen içeriğinin azalmasına bağlı renal hipoksi sinyali","Serum sodyumunun yükselmesi","Portal ven basıncının artması","Plazma albümininin yükselmesi","Trombosit sayısının azalması"],"correct":0,"exp":"EPO esas olarak böbrekte hipoksiye yanıt olarak artar. Doku oksijenlenmesi azaldığında eritropoez uyarılır ve retikülosit/eritrosit üretimi artar."},{"id":2373,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":4,"q":"Ağır anemisi olan hastanın pulse oksimetresi %98 ölçülüyor; buna rağmen egzersizde çabuk yoruluyor. Bu bulgular birlikte nasıl açıklanır?","options":["Oksijen satürasyonu normal olsa da toplam oksijen içeriği hemoglobin azlığı nedeniyle düşüktür","Pulse oksimetre yalnız karbondioksiti ölçer","Anemide arteriyel PO2 daima sıfıra yaklaşır","Hemoglobin azaldığında oksijen dokulara daha fazla taşınır","Oksijen satürasyonu eritrosit sayısından bağımsız olarak klinik önem taşımaz"],"correct":0,"exp":"Satürasyon mevcut hemoglobinin ne kadarının oksijenle dolu olduğunu gösterir. Anemide Hb miktarı azaldığı için arteriyel oksijen içeriği azalır; satürasyon normal görünebilir."},{"id":2374,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":5,"q":"Yüksek irtifada birkaç gün kalan kişide hemoglobin-oksijen eğrisinin sağa kaydığı ve dokulara oksijen bırakılmasının kolaylaştığı görülüyor. Eritrositte artan hangi madde bu uyuma katkı verir?","options":["2,3-BPG","Ferritin","Haptoglobin","Transferrin","Hepsidin"],"correct":0,"exp":"2,3-BPG deoksihemoglobine bağlanır ve Hb'nin oksijene afinitesini azaltır. Eğri sağa kayar, dokulara oksijen bırakılması kolaylaşır."},{"id":2375,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":4,"q":"Von Willebrand hastalığı olan çocukta mukozal kanama ve uzamış kanama zamanı saptanıyor. Primer hemostazdaki temel kusur hangisidir?","options":["Trombositlerin subendotelyal kollajene adezyonunun azalması","Protrombinin trombine dönüşememesi","Fibrinojenin karaciğerde sentezlenememesi","Antitrombinin aşırı çalışması","Plazminojenin aktive olamaması"],"correct":0,"exp":"vWF trombosit GpIb ile subendotelyal kollajen arasında köprü kurar. Eksikliğinde trombosit adezyonu bozulur ve mukokutanöz kanama eğilimi artar."},{"id":2376,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":4,"q":"Akut inflamasyonu olan hastada eritrosit sedimantasyon hızı artıyor. Bu artışı en iyi açıklayan plazma değişikliği hangisidir?","options":["Fibrinojen artışıyla eritrositlerde rulo formasyonu gelişmesi","Albumin artışıyla eritrositlerin birbirinden uzaklaşması","Sodyum azalmasıyla eritrositlerin parçalanması","Trombosit azalmasıyla eritrositlerin ağırlaşması","Bilirubin artışıyla eritrositlerin yüzeye çıkması"],"correct":0,"exp":"Fibrinojen ve bazı akut faz proteinleri eritrositlerin negatif yüzey yükünü azaltarak rouleaux oluşumunu artırır. Bu durum ESR artışına katkı verir."},{"id":2377,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":3,"q":"Kemik iliği baskılanan hastada nötrofil sayısı hızla düşerken eritrosit sayısındaki azalma daha geç belirginleşiyor. Bu farkı en iyi açıklayan özellik hangisidir?","options":["Nötrofillerin dolaşımdaki yaşam süresinin eritrositlere göre kısa olması","Eritrositlerin çekirdekli olması","Nötrofillerin böbrekte üretilmesi","Eritrositlerin kemik iliğinde üretilmemesi","Nötrofillerin hemoglobin taşıması"],"correct":0,"exp":"Nötrofillerin dolaşımdaki ömrü kısadır; üretim baskılanınca sayı hızlı düşer. Eritrositlerin yaşam süresi yaklaşık 120 gündür, azalma daha geç ortaya çıkar."},{"id":2378,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":4,"q":"Yenidoğan döneminde hematopoez karaciğer ve dalaktan kemik iliğine kaymıştır. Fetal yaşamda hematopoezin ana sıra değişimi en doğru hangisidir?","options":["Kemik iliği → yolk sac → karaciğer","Yolk sac → karaciğer/dalak → kemik iliği","Dalak → böbrek → timus","Akciğer → karaciğer → kemik iliği","Timus → yolk sac → böbrek"],"correct":1,"exp":"Embriyoda hematopoez önce yolk sac'ta başlar, sonra karaciğer ve dalakta devam eder, geç fetal dönemde kemik iliği ana hematopoetik organ haline gelir."},{"id":2379,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":4,"q":"Demir eksikliğinde hem sentezi azalmasına rağmen eritropoietin artışı devam ediyor. Hem sentezi için demirin doğrudan yer aldığı son basamakta demir hangi yapıya eklenir?","options":["Protoporfirin IX","Globin zincirinin amino ucuna","Transferrin reseptörüne","Ferritinin ağır zincirine","Haptoglobinin bağlanma bölgesine"],"correct":0,"exp":"Hemin son basamağında Fe2+ protoporfirin IX'a yerleştirilir. Demir eksikliğinde hem sentezi azalır ve mikrositer hipokromik eritrositler gelişir."},{"id":2380,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":4,"q":"Peptik ülser nedeniyle asit sekresyonu artmış hastada gastrin yüksek saptanıyor. Gastrinin parietal hücre asit salgısını artırmasında en önemli ara hücrelerden biri hangisidir?","options":["D hücresi","ECL hücresi","Goblet hücresi","Paneth hücresi","I hücresi"],"correct":1,"exp":"Gastrin doğrudan parietal hücreyi uyarabilir; ayrıca ECL hücrelerinden histamin salınımını artırır. Histamin H2 reseptörleri üzerinden asit sekresyonunu güçlendirir."},{"id":2381,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":4,"q":"Yağlı yemek sonrası duodenuma geçen içerik safra kesesi kasılmasını ve pankreatik enzim salgısını artırıyor. Bu yanıtın başlıca hormonu hangisidir?","options":["Sekretin","Kolesistokinin","Motilin","Ghrelin","Somatostatin"],"correct":1,"exp":"CCK duodenum ve jejunumdaki I hücrelerinden salgılanır; yağ ve aminoasitlerle artar. Safra kesesini kasar, Oddi sfinkterini gevşetir ve pankreatik enzim salgısını artırır."},{"id":2382,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":4,"q":"Asidik kimus duodenuma geçtiğinde pankreastan bikarbonattan zengin sıvı salgısı artıyor. Bu yanıtı en çok uyaran hormon hangisidir?","options":["Sekretin","Gastrin","Motilin","GIP","VIP"],"correct":0,"exp":"Duodenal S hücrelerinden salgılanan sekretin asidik içeriğe yanıt verir. Pankreas kanal hücrelerinden bikarbonattan zengin sıvı salgısını artırır."},{"id":2383,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":4,"q":"Kısa barsak cerrahisi sonrası terminal ileumu çıkarılan hastada yağlı dışkılama ve safra tuzu kaybı gelişiyor. Safra tuzlarının fizyolojik geri emiliminin ana bölgesi neresidir?","options":["Mide fundusu","Duodenum","Terminal ileum","Çıkan kolon","Rektum"],"correct":2,"exp":"Safra tuzları enterohepatik dolaşım içinde ağırlıklı olarak terminal ileumdan aktif şekilde geri emilir. İleum rezeksiyonunda safra tuzu kaybı ve steatore gelişebilir."},{"id":2384,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":5,"q":"Kolera benzeri sulu ishalde oral rehidratasyon sıvısı verilince bağırsak su emilimi belirgin artıyor. Toksin sekresyonu sürse de bu tedavinin işe yaramasını sağlayan taşıma sistemi hangisidir?","options":["Na+-glukoz kotransportu","H+/K+ ATPaz","Na+/Ca2+ değiştirici","Cl-/HCO3- değişimi olmadan pasif klor geçişi","Sadece akvaporinlerden aktif su pompası"],"correct":0,"exp":"SGLT1 aracılı Na+-glukoz kotransportu kolerada korunur. Sodyum ve glukoz emilimi suyun da emilmesini sağlar; oral rehidratasyonun temeli budur."},{"id":2385,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":4,"q":"Pankreas ekzokrin yetmezliği olan hastada kilo kaybı, kötü kokulu yağlı dışkı ve yağda eriyen vitamin eksikliği gelişiyor. Bu tabloda eksikliği en belirleyici olan salgı hangisidir?","options":["Pepsinojen","Pankreatik lipaz","Tükürük amilazı","Gastrik mukus","Enterokinaz olmadan salgılanan histamin"],"correct":1,"exp":"Yağ sindirimi pankreatik lipaz ve safra tuzlarına bağımlıdır. Ekzokrin pankreas yetmezliğinde lipaz eksikliği steatoreye ve ADEK vitamini eksikliklerine yol açar."},{"id":2386,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":4,"q":"Pernisiyöz anemide gastrik parietal hücre hasarı olan hastada B12 eksikliği gelişiyor. B12'nin ileumdan emilebilmesi için gerekli mide kaynaklı protein hangisidir?","options":["Pepsin","İntrinsik faktör","Gastrin","Tripsinojen","Haptokorrin olmadan parietal lipaz"],"correct":1,"exp":"İntrinsik faktör parietal hücrelerden salgılanır ve B12'nin terminal ileumdan emilimi için gereklidir. Eksikliğinde megaloblastik anemi ve nörolojik bulgular gelişebilir."},{"id":2387,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":4,"q":"Açlık döneminde bağırsakta aralıklı güçlü peristaltik dalgalarla lümen temizliği sağlanıyor. Yemek yenince bu dalgalar baskılanıyor. Bu hareket paterni en çok hangi hormonla ilişkilidir?","options":["Motilin","Sekretin","Kolesistokinin","Gastrin","İnsülin"],"correct":0,"exp":"Motilin açlıkta migrating motor complex'i uyarır. Bu kompleks mide ve ince bağırsak içeriğinin temizlenmesine katkı sağlar."},{"id":2388,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":4,"q":"Yağlı yemek sonrası midenin boşalması belirgin yavaşlıyor. Bu gecikme duodenuma aşırı asit ve yağ geçişini sınırlayan hangi yanıtla en iyi açıklanır?","options":["Enterogastrik inhibisyon","Gastroileal refleksin tamamen durması","Rektosigmoid refleks","Mass hareketlerin artması","Yutma refleksinin kapanması"],"correct":0,"exp":"Duodenumdaki yağ, asit ve hipertonik içerik enterogastrik refleksler ve hormonlar aracılığıyla gastrik boşalmayı yavaşlatır. Böylece duodenum korunur ve sindirim dengelenir."},{"id":2389,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":3,"q":"Süt içtikten sonra şişkinlik, kramp ve sulu ishal gelişen hastanın dışkısında pH düşük bulunuyor. Bu tablo en çok hangi fizyolojik sonuçla uyumludur?","options":["Laktaz eksikliğine bağlı emilemeyen karbonhidratların osmotik yük oluşturması","Safra tuzlarının mide içinde aşırı emilmesi","Parietal hücrelerden lipaz salgısının artması","İnce bağırsakta protein emiliminin tamamen durması","Kolonda suyun aktif olarak lümene pompalanması olmadan hiperozmolalite oluşmaması"],"correct":0,"exp":"Laktaz eksikliğinde laktoz emilemez; lümende osmotik yük oluşturur ve bakteriyel fermantasyonla asidik dışkı, gaz ve ishal gelişir."},{"id":2390,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":4,"q":"Demir eksikliği anemisi olan hastada emilim bozukluğu araştırılıyor. Diyet demirinin en yoğun emildiği gastrointestinal bölge hangisidir?","options":["Mide antrumu","Duodenum ve proksimal jejunum","Terminal ileum","Transvers kolon","Rektum"],"correct":1,"exp":"Demir emilimi ağırlıklı olarak duodenum ve proksimal jejunumda olur. Asidik ortam ve C vitamini non-hem demir emilimini kolaylaştırır."},{"id":2391,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":4,"q":"Uzun zincirli yağ asitlerinden zengin öğün sonrası enterosit içinde trigliserid paketleniyor ve başlangıçta portal ven yerine lenfatik yolla taşınıyor. Bu taşıyıcı parçacık hangisidir?","options":["Şilomikron","VLDL","HDL","Albumine bağlı serbest yağ asidi","IDL"],"correct":0,"exp":"Enterositlerde uzun zincirli yağ asitleri trigliseride çevrilir ve şilomikronlarla paketlenir. Şilomikronlar laktealler üzerinden lenfe geçer."},{"id":2392,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":5,"q":"VIP salgılayan tümörü olan hastada bol sulu ishal, hipokalemi ve aklorhidri gelişiyor. Bu hastada bağırsak lümenine artan ana sekresyon hangisidir?","options":["Klor ve su sekresyonu","Demir emilimi","Safra asidi emilimi","Pepsinojen aktivasyonu","Kolesterol esterifikasyonu"],"correct":0,"exp":"VIP intestinal klor ve su sekresyonunu artırır, gastrik asit sekresyonunu azaltır. VIPoma WDHA sendromuna yol açabilir."},{"id":2393,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":4,"q":"Tükürük bezi kanallarından geçen salgının son hali plazmaya göre hipotonik hale geliyor. Bunun nedeni en iyi nasıl açıklanır?","options":["Duktus hücrelerinin NaCl reabsorbe edip suya görece geçirgen olmaması","Asinus hücrelerinin yalnız saf su salgılaması","Tükürükte potasyumun hiç bulunmaması","Duktusların suyu aktif olarak lümene pompalaması","Amilazın sodyumu bağlayıp lümende tutması"],"correct":0,"exp":"Tükürük primer olarak izotonik salgılanır. Duktuslarda Na+ ve Cl- geri emilir, su geçirgenliği sınırlı olduğu için son salgı hipotonik olur."},{"id":2394,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":4,"q":"Rektuma dışkı dolmasıyla iç anal sfinkter gevşiyor, kişi uygun ortam yoksa dış anal sfinkteri istemli kasılı tutabiliyor. Dış anal sfinkterin kontrolü hangi sinir sistemi bileşenine bağlıdır?","options":["Otonom parasempatik sistem","Somatik pudendal sinir kontrolü","Sadece enterik pleksus","Vagal efferentler","Sempatik splanknik lifler"],"correct":1,"exp":"Dış anal sfinkter çizgili kastır ve pudendal sinir aracılığıyla somatik istemli kontrol altındadır. İç anal sfinkter otonom kontrolle gevşer/kasılır."},{"id":2395,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"Septik olmayan kan kaybı sonrası venöz dönüşü artırmak için sıvı verilen hastada sol ventrikül diyastol sonu hacmi artıyor ve atım hacmi yükseliyor. Bu yanıt en iyi hangi ilkeyle açıklanır?","options":["Frank-Starling ilişkisi","Laplace yasasının alveoldeki etkisi","Bohr etkisi","Gibbs-Donnan dengesi","Hering-Breuer refleksi"],"correct":0,"exp":"Venöz dönüş ve preload arttığında sarkomer uzunluğu optimal aralığa yaklaşır; kasılma kuvveti ve atım hacmi artar. Bu Frank-Starling mekanizmasıdır."},{"id":2396,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"Ayağa kalkınca kısa süreli baş dönmesi olan sağlıklı kişide birkaç saniye içinde kalp hızı ve periferik direnç artıyor. Bu hızlı kompansasyonu başlatan reseptörler nerede bulunur?","options":["Karotis sinüsü ve aort kavsi","Renal medulla","Adrenal korteks","Hipofiz arka lobu","Pulmoner alveol duvarı"],"correct":0,"exp":"Arteriyel baroreseptörler karotis sinüsü ve aort kavsindedir. Basınç düşünce afferent ateşleme azalır; sempatik tonus artar, parasempatik tonus azalır."},{"id":2397,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":5,"q":"Aort darlığı olan hastada sol ventrikül basıncı artmış, atım hacmi azalmış ve sistol süresi uzamış bulunuyor. Basınç-hacim eğrisinde beklenen temel değişiklik hangisidir?","options":["Afterload artışıyla end-sistolik hacmin artması","Preload sıfıra indiği için diyastolik dolumun tamamen durması","İzovolümetrik kontraksiyon fazının kaybolması","Sol ventrikül basıncının hiç yükselmemesi","Atım hacminin afterload artışından bağımsız kalması"],"correct":0,"exp":"Aort darlığında afterload artar. Ventrikül kanı atmakta zorlanır, end-sistolik hacim artar ve atım hacmi azalır."},{"id":2398,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":5,"q":"Mitral yetmezliği olan hastanın basınç-hacim döngüsünde izovolümetrik kontraksiyon ve gevşeme fazlarının belirgin olmadığı görülüyor. Bu durumun nedeni hangisidir?","options":["Sistol ve diyastolde ventrikül hacminin hiç değişmemesi","Sol ventrikülün sistolde atriyuma, diyastolde atriyumdan ventriküle açık kaçak yolu bulması","Aort kapağının hiç açılmaması","Mitral kapağın tüm siklus boyunca kusursuz kapanması","Ventrikülün elektriksel aktivitesinin durması"],"correct":1,"exp":"Mitral yetmezlikte ventrikül sistol sırasında atriyuma kan kaçırır. Hacim sabit kalmadığı için izovolümetrik fazlar kaybolur ya da belirgin azalır."},{"id":2399,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"Derin inspirasyon sırasında sağ kalbe venöz dönüş artıyor ve ikinci kalp sesinde fizyolojik çiftleşme belirginleşiyor. Geciken bileşen hangisidir?","options":["Aort kapağı kapanması","Pulmoner kapak kapanması","Mitral kapak açılması","Triküspit kapak açılması","S1'in mitral bileşeni"],"correct":1,"exp":"İnspirasyonda sağ ventrikül dolumu artar, sağ ventrikül ejeksiyonu uzar ve pulmoner kapak kapanması gecikir. S2 fizyolojik olarak geniş çiftleşir."},{"id":2400,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"Sağlıklı kişide yoğun egzersiz sırasında sistolik basınç artarken diyastolik basınç aynı kalıyor veya hafif düşüyor. Bu tabloyu en iyi açıklayan periferik değişiklik hangisidir?","options":["Çalışan iskelet kasında arterioler vazodilatasyon","Böbrekte tüm arteriollerin tam kapanması","Serebral kan akımının tamamen durması","Koroner arterlerde vazokonstriksiyon","Toplam periferik direncin belirgin artması"],"correct":0,"exp":"Egzersizde çalışan kaslarda metabolik vazodilatasyon olur; toplam periferik direnç azalabilir. Kardiyak debi arttığı için sistolik basınç yükselir, diyastolik basınç genelde belirgin yükselmez."},{"id":2401,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"Kalp yetmezliği olan hastada ventrikül kompliyansı azalmış ve aynı dolum hacminde diyastol sonu basıncı daha yüksek ölçülüyor. Bu durum hangi ilişkiyi yansıtır?","options":["Azalmış ventrikül kompliyansı","Artmış venöz kapasitans","Azalmış afterload","Artmış kapiller onkotik basınç","Tamamen normal diyastolik fonksiyon"],"correct":0,"exp":"Kompliyans, hacim değişiminin basınç değişimine oranıdır. Ventrikül sertleşirse aynı hacimde daha yüksek basınç oluşur; diyastolik dolum bozulur."},{"id":2402,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"Nefrotik sendromlu hastada yaygın ödem var. Kapiller düzeyde interstisyuma sıvı geçişini artıran temel değişiklik hangisidir?","options":["Plazma onkotik basıncının azalması","Kapiller hidrostatik basıncın sıfıra inmesi","Lenf akımının aşırı artması","Eritrosit sayısının artması","Albumin artışına bağlı suyun damar içine çekilmesi"],"correct":0,"exp":"Plazma albumini azalınca kapiller onkotik basınç düşer. Suyun damar içinde tutulması azalır ve ödem eğilimi artar."},{"id":2403,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":5,"q":"Şiddetli kanama geçiren hastada ilk dakikalarda taşikardi, soğuk cilt ve dar nabız basıncı gelişiyor. Bu erken yanıtta baskın otonom değişiklik hangisidir?","options":["Sempatik aktivitenin artması ve venokonstriksiyon","Parasempatik aktivitenin artması ve periferik vazodilatasyon","Sempatik aktivitenin azalması ve bradikardi","Baroreseptör ateşlemesinin artmasıyla vazodilatasyon","Asetilkolin salınımının periferik damarları kasması"],"correct":0,"exp":"Kan kaybında arteriyel basınç ve baroreseptör ateşlemesi azalır. Sempatik aktivite artar; taşikardi, kontraktilite artışı, venokonstriksiyon ve arterioler vazokonstriksiyon gelişir."},{"id":2404,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"Koroner kan akımı özellikle sol ventrikülde sistolde azalır, diyastolde artar. Bunun nedeni en iyi nasıl açıklanır?","options":["Sistolde intramiyokardiyal damarların kasılan miyokard tarafından sıkıştırılması","Diyastolde aort basıncının sıfıra düşmesi","Koroner arterlerin sadece inspirasyonda açık kalması","Sistolde oksijen ihtiyacının tamamen kaybolması","Aort kapağı kapalıyken koroner ostiumların kapanması"],"correct":0,"exp":"Sol ventrikül sistolünde yüksek intramiyokardiyal basınç koroner damarları sıkıştırır. Bu nedenle sol koroner perfüzyonun büyük kısmı diyastolde gerçekleşir."},{"id":2405,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"SA nod hücrelerinde eşik değere doğru kendiliğinden yavaş depolarizasyon gelişmesi kalp otomatisitesini sağlar. Bu fazın en karakteristik akımı hangisidir?","options":["Funny Na+ akımı","Hızlı voltaj kapılı Na+ akımı","Klorun ani hücre içine girişi","Miyozin hafif zincir fosforilasyonu","Sadece potasyum çıkışı"],"correct":0,"exp":"SA nod faz 4 depolarizasyonunda If, yani funny akımı önemlidir. Ayrıca Ca2+ akımları ve K+ iletkenliğinin azalması da pacemaker aktivitesine katkı verir."},{"id":2406,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"Ventrikül kası aksiyon potansiyelinde plato fazı sayesinde kasılma süresi uzar ve tetani gelişmez. Plato fazında baskın olan iyon hareketi hangisidir?","options":["L tipi kalsiyum kanallarından Ca2+ girişi","Hızlı sodyum kanallarından sürekli Na+ girişi","Klorun hücre dışına çıkışı","Magnezyumun aktif pompalanması","Sodyum-potasyum pompasının tek başına durması"],"correct":0,"exp":"Ventrikül kasında faz 2 plato L tipi Ca2+ girişi ve K+ çıkışı arasındaki dengeyle oluşur. Uzun refrakter dönem tetaniyi engeller."},{"id":2407,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"Ağır anemide kardiyak debi artmış, sistemik damar direnci azalmış bulunuyor. Bu yüksek debili dolaşım yanıtına katkı veren temel faktör hangisidir?","options":["Doku hipoksisine bağlı lokal vazodilatasyon ve kan viskozitesinde azalma","Hemoglobin artışına bağlı kan viskozitesinde yükselme","Baroreseptörlerin kalıcı olarak kapanması","Koroner kan akımının sıfırlanması","Venöz dönüşün tamamen durması"],"correct":0,"exp":"Anemide oksijen taşıma kapasitesi azalır; dokularda metabolik vazodilatasyon gelişir. Kan viskozitesi de azalır, kardiyak debi kompansatuvar olarak artabilir."},{"id":2408,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"Fick prensibiyle kardiyak debi hesaplanan hastada oksijen tüketimi biliniyor. Arteriyovenöz oksijen farkı artarsa, oksijen tüketimi sabitken hesaplanan kardiyak debi nasıl değişir?","options":["Azalır","Artar","Değişmez","Sıfır olur","Sadece nabız basıncıyla belirlenir"],"correct":0,"exp":"Fick prensibine göre kardiyak debi = O2 tüketimi / arteriyovenöz O2 farkıdır. O2 tüketimi sabitken A-V fark artarsa hesaplanan debi azalır."},{"id":2409,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":5,"q":"Valsalva manevrasının zorlu ekspirasyon fazında venöz dönüş azalır ve kısa süre sonra arter basıncı düşer. Sağlıklı kişide bu fazda beklenen refleks yanıt hangisidir?","options":["Taşikardi ve sempatik tonus artışı","Bradikardi ve vazodilatasyon","Atrial natriüretik peptid salınımının tek başına artması","Koroner akımın tamamen durması","Baroreseptör ateşlemesinin artması"],"correct":0,"exp":"Valsalva sırasında intratorasik basınç artar, venöz dönüş ve atım hacmi azalır. Arter basıncı düşünce baroreseptör ateşlemesi azalır; refleks taşikardi ve sempatik aktivite artışı olur."},{"id":2410,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"Tam AV blok gelişen hastada atriyum ve ventrikül birbirinden bağımsız hızlarda çalışıyor. Ventrikül kaçış ritminin daha yavaş olmasının nedeni hangisidir?","options":["Distal pacemaker hücrelerinin spontan depolarizasyon hızının SA noddan düşük olması","Purkinje liflerinde hiç otomatisite bulunmaması","AV nodun asetilkolin salgılaması","Atriyal kasın aksiyon potansiyeli üretememesi","Ventrikül kasının kalsiyum kullanmaması"],"correct":0,"exp":"Kalbin pacemaker hiyerarşisinde SA nod en hızlı spontan depolarizasyon hızına sahiptir. Daha distal odakların intrinsik hızı daha düşüktür."},{"id":2411,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"Hipertansiyonu olan hastada uzun süreli basınç yüküne bağlı sol ventrikül konsantrik hipertrofisi gelişiyor. Duvar gerilimini azaltmaya çalışan bu adaptasyon hangi fiziksel ilişkiyle açıklanabilir?","options":["Laplace yasası","Fick difüzyon yasası","Boyle yasası","Gibbs-Donnan dengesi","Michaelis-Menten kinetiği"],"correct":0,"exp":"Laplace ilişkisine göre duvar gerilimi basınç ve yarıçapla artar, duvar kalınlığıyla azalır. Basınç yükünde konsantrik hipertrofi duvar gerilimini azaltmaya yönelik adaptasyondur."},{"id":2412,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"Atrial gerilimi artan hastada sodyum atılımını artıran ve renin-anjiyotensin-aldosteron sistemini baskılayan hormon salınıyor. Bu hormon hangisidir?","options":["ANP","ADH","Eritropoietin","Kortizol","Glukagon"],"correct":0,"exp":"Atriyal natriüretik peptid atriyal gerilmeyle salınır. Natriürez ve diürez yapar, renin ve aldosteron etkilerini baskılar."},{"id":2413,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":5,"q":"Pulmoner kapiller kama basıncı yüksek olan hastada akciğer ödemi gelişiyor. Bu ölçüm klinikte hangi basınca yaklaşık bilgi verir?","options":["Sol atriyum basıncı","Sağ atriyum basıncı","Aort sistolik basıncı","İntrakraniyal basınç","Portal ven basıncı"],"correct":0,"exp":"Pulmoner kapiller wedge basıncı, mitral kapak darlığı gibi engel yoksa sol atriyum basıncını ve sol ventrikül dolum basıncını yaklaşık yansıtır."},{"id":2414,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"Sıcak ortamda uzun süre ayakta kalan kişide cilt damarlarında genişleme ve venöz göllenme sonrası senkop gelişiyor. İlk hemodinamik bozulma en iyi hangisidir?","options":["Venöz dönüş ve preload azalması","Sol ventrikül afterloadının aşırı artması","Pulmoner vasküler direncin sıfırlanması","Koroner perfüzyonun yalnız sistolde artması","Eritrosit oksijen afinitesinin kaybolması"],"correct":0,"exp":"Ayakta durma ve sıcaklık venöz göllenmeyi artırır. Venöz dönüş azalınca preload, atım hacmi ve serebral perfüzyon düşebilir."},{"id":2415,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"Kılcal damarların arteriyel ucunda filtrasyon, venöz ucunda ise geri emilim eğilimi daha fazladır. Arteriyel uçta filtrasyonu artıran ana kuvvet hangisidir?","options":["Kapiller hidrostatik basınç","Plazma onkotik basıncı","İnterstisyel proteinlerin tamamen yokluğu","Lenfatik pompa basıncı","Eritrosit içi ozmotik basınç"],"correct":0,"exp":"Kapiller hidrostatik basınç sıvıyı damar dışına iter. Plazma onkotik basıncı ise sıvıyı damar içine çekme yönünde etkilidir."},{"id":2416,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"Hipertrofik kardiyomiyopatili hastada sol ventrikül diyastolik dolumu zorlaşıyor. Atriyal katkının kaybı sonrası semptomların artması en çok hangi nedenle beklenir?","options":["Sert ventrikülde geç diyastolik atriyal dolumun önem kazanması","Atriyum kasının kan oksijenlemesini sağlaması","Ventrikülün sadece sistolde dolması","Mitral kapağın atriyum kasılmadan hiç açılamaması","Koroner akımın atriyum kasılmasına bağımlı olması"],"correct":0,"exp":"Kompliyansı azalmış ventrikülde atriyal sistol diyastolik doluma önemli katkı sağlar. Atriyal fibrilasyon gibi durumlarda bu katkı kaybolunca semptomlar artabilir."},{"id":2417,"ders":"Fizyoloji","konu":"Endokrin ve Genital Sistem HistoFizyolojisi","diff":4,"q":"Uzun açlık sonrası hastada glukagon artmış, insülin baskılanmış bulunuyor. Karaciğerde kan glukozunu korumaya en erken katkı veren süreç hangisidir?","options":["Glikojenoliz","Yağ dokusunda GLUT4 translokasyonu","Kas glikojeninin kana doğrudan glukoz vermesi","İnce bağırsakta laktaz aktivasyonunun artması","Böbrekten glukoz atılımının artması"],"correct":0,"exp":"Kısa süreli açlıkta karaciğer glikojenolizi kan glukozunu korur. Daha uzun açlıkta glukoneogenez ve ketogenez önem kazanır."},{"id":2418,"ders":"Fizyoloji","konu":"Endokrin ve Genital Sistem HistoFizyolojisi","diff":4,"q":"İnsülin verildikten sonra iskelet kasında glukoz alımı artıyor. Bu etkinin hızlı başlamasını sağlayan temel hücresel olay hangisidir?","options":["GLUT4 veziküllerinin hücre membranına taşınması","GLUT2'nin kas hücresine yerleşmesi","Sodyum-glukoz kotransportunun böbrekte durması","Glukagon reseptörlerinin artması","Kortizol reseptörünün nükleustan çıkması"],"correct":0,"exp":"İnsülin kas ve yağ dokusunda GLUT4 taşıyıcılarının membrana translokasyonunu sağlar. Böylece glukoz alımı hızlı artar."},{"id":2419,"ders":"Fizyoloji","konu":"Endokrin ve Genital Sistem HistoFizyolojisi","diff":4,"q":"Primer hiperparatiroidisi olan hastada serum kalsiyumu yüksek, fosforu düşük bulunuyor. PTH'nin böbrekte fosfor üzerindeki etkisi hangisidir?","options":["Proksimal tübülde fosfat geri emilimini azaltmak","Distal tübülde fosfat geri emilimini artırmak","Glomerülde fosfat filtrasyonunu tamamen durdurmak","Fosfatı albumine bağlamak","İnce bağırsakta fosfat salgısını artırmak"],"correct":0,"exp":"PTH proksimal tübülde fosfat reabsorpsiyonunu azaltır; fosfatüri yapar. Kalsiyumu artırırken fosforu düşürebilir."},{"id":2420,"ders":"Fizyoloji","konu":"Endokrin ve Genital Sistem HistoFizyolojisi","diff":4,"q":"D vitamini eksikliği olan çocukta hipokalsemi ve kemik mineralizasyon bozukluğu gelişiyor. Aktif D vitamininin bağırsaktaki temel etkisi hangisidir?","options":["Kalsiyum ve fosfat emilimini artırmak","Demir emilimini tamamen durdurmak","Safra asidi sentezini azaltmak","İnsülin reseptörünü bloke etmek","Kalsiyumu idrarla atmak"],"correct":0,"exp":"Kalsitriol bağırsaktan kalsiyum ve fosfat emilimini artırır. Kemik mineralizasyonu için gerekli mineral dengesine katkı verir."},{"id":2421,"ders":"Fizyoloji","konu":"Endokrin ve Genital Sistem HistoFizyolojisi","diff":4,"q":"Gece uykusundan sonra sabah saatlerinde kortizol düzeyi fizyolojik olarak yükseliyor. Bu ritmi düzenleyen temel eksen hangisidir?","options":["Hipotalamus-hipofiz-adrenal eksen","Renin-anjiyotensin-aldosteron ekseni olmadan adrenal medulla","Hipotalamus-hipofiz-tiroid ekseninin doğrudan kortizol üretmesi","Ovaryum-korpus luteum ekseni","Pankreas adacıklarının ACTH salgılaması"],"correct":0,"exp":"Kortizol CRH-ACTH-adrenal korteks ekseniyle düzenlenir ve sirkadiyen ritim gösterir. Sabah saatlerinde fizyolojik pik yapar."},{"id":2422,"ders":"Fizyoloji","konu":"Endokrin ve Genital Sistem HistoFizyolojisi","diff":4,"q":"Primer hipotiroidili hastada TSH yüksek, serbest T4 düşük bulunuyor. TSH yüksekliğini açıklayan geri bildirim değişikliği hangisidir?","options":["Tiroid hormonlarının hipofiz ve hipotalamus üzerindeki negatif geri bildiriminin azalması","T4'ün TSH reseptörünü doğrudan aktive etmesi","TRH'nin sadece tiroidden salgılanması","TSH'nin böbrekten atılımının artması","İyotun hipofizde depolanması"],"correct":0,"exp":"Tiroid hormonları hipotalamus ve hipofiz üzerinde negatif geri bildirim yapar. Primer hipotiroidide T4 düşük olduğu için TSH artar."},{"id":2423,"ders":"Fizyoloji","konu":"Endokrin ve Genital Sistem HistoFizyolojisi","diff":4,"q":"Doğum sonrası süt üretimi yetersiz olan hastada hipofiz yetmezliği düşünülüyor. Süt üretimini başlatan ve sürdüren başlıca ön hipofiz hormonu hangisidir?","options":["Prolaktin","Oksitosin","ADH","Aldosteron","Kalsitonin"],"correct":0,"exp":"Prolaktin ön hipofizden salgılanır ve süt üretimini uyarır. Oksitosin ise süt ejeksiyonundan sorumludur."},{"id":2424,"ders":"Fizyoloji","konu":"Endokrin ve Genital Sistem HistoFizyolojisi","diff":5,"q":"Normal siklusta ovulasyondan hemen önce LH pikinin oluşmasını sağlayan hormonal ortam hangisidir?","options":["Uzun süre yüksek seyreden östradiolün hipotalamus-hipofiz üzerine pozitif geri bildirimi","Progesteronun foliküler faz başında sürekli yüksek kalması","FSH'nin hipofizi tamamen baskılaması","Kortizolün GnRH reseptörünü uyarması","Prolaktinin dopamini artırması"],"correct":0,"exp":"Foliküler fazın sonlarında yüksek ve sürekli östradiol pozitif geri bildirim yapar. Bu durum LH pikini ve ovulasyonu tetikler."},{"id":2425,"ders":"Fizyoloji","konu":"Endokrin ve Genital Sistem HistoFizyolojisi","diff":4,"q":"Granüloza hücrelerinde aromataz aktivitesi artınca östradiol sentezi yükseliyor. Bu hücrelerde aromatazı uyaran başlıca gonadotropin hangisidir?","options":["FSH","LH","hCG","ACTH","TSH"],"correct":0,"exp":"İki hücre-iki gonadotropin modelinde LH teka hücrelerinde androjen üretimini artırır; FSH granüloza hücrelerinde aromatazı uyararak androjenlerden östradiol üretimini sağlar."},{"id":2426,"ders":"Fizyoloji","konu":"Endokrin ve Genital Sistem HistoFizyolojisi","diff":4,"q":"Erken gebelikte korpus luteumun devam etmesi progesteron düzeyini korur. Bu desteği sağlayan hormon hangisidir?","options":["hCG","FSH","Prolaktin","Kalsitonin","ADH"],"correct":0,"exp":"hCG trofoblast kaynaklıdır ve LH benzeri etkiyle korpus luteumu sürdürür. Böylece erken gebelikte progesteron üretimi devam eder."},{"id":2427,"ders":"Fizyoloji","konu":"Endokrin ve Genital Sistem HistoFizyolojisi","diff":4,"q":"Primer adrenal yetmezlikte hiperkalemi ve hipotansiyon gelişen hastada eksik olan hormonun böbrekteki temel etkisi hangisidir?","options":["Distal nefronda sodyum geri emilimini ve potasyum sekresyonunu artırmak","Proksimal tübülde glukoz geri emilimini durdurmak","Glomerül filtrasyonunu tamamen kapatmak","Henle kulpunun inen kolunu suya geçirimsiz yapmak","Kalsiyumun bağırsaktan emilimini azaltmak"],"correct":0,"exp":"Aldosteron distal nefron principal hücrelerinde Na+ geri emilimini ve K+ sekresyonunu artırır. Eksikliğinde hiperkalemi, tuz kaybı ve hipotansiyon gelişebilir."},{"id":2428,"ders":"Fizyoloji","konu":"Endokrin ve Genital Sistem HistoFizyolojisi","diff":4,"q":"Santral diabetes insipiduslu hastada çok su içme ve bol seyrek idrar var. Desmopressin sonrası idrar ozmolalitesi artıyor. Bu yanıt hangi reseptör etkisiyle oluşur?","options":["V2 reseptörü üzerinden toplayıcı kanalda aquaporin-2 yerleşimi","V1 reseptörü üzerinden glomerülde glukoz emilimi","Alfa-1 reseptörü üzerinden proksimal tübülde fosfat atılımı","Beta-2 reseptörü üzerinden Henle inen kolunda sodyum atılımı","Mineralokortikoid reseptörü üzerinden suyun aktif pompalanması"],"correct":0,"exp":"ADH V2 reseptörleri üzerinden toplayıcı kanal principal hücrelerinde aquaporin-2 kanallarını apikal membrana taşır. Su geri emilimi artar, idrar konsantre olur."},{"id":2429,"ders":"Fizyoloji","konu":"Endokrin ve Genital Sistem HistoFizyolojisi","diff":4,"q":"SIADH olan hastada hiponatremi, düşük serum ozmolalitesi ve uygunsuz yoğun idrar saptanıyor. Bu hastada su dengesindeki temel bozukluk hangisidir?","options":["Serbest su tutulumu","Zorunlu sodyum tutulumu","Glukozun idrarla aşırı atılması","Albumin sentezinin artması","Aldosteronun tamamen yokluğu"],"correct":0,"exp":"SIADH'da ADH uygunsuz yüksek kalır; toplayıcı kanalda su geri emilimi artar. Serbest su tutulumu hiponatremiye ve yoğun idrara yol açar."},{"id":2430,"ders":"Fizyoloji","konu":"Endokrin ve Genital Sistem HistoFizyolojisi","diff":4,"q":"Menopozdaki kadında sıcak basmaları ve amenoreye eşlik eden laboratuvar değişikliği soruluyor. Primer ovaryan follikül tükenmesine bağlı beklenen gonadotropin paterni hangisidir?","options":["FSH yüksek, östradiol düşük","FSH düşük, östradiol yüksek","LH ve FSH tamamen baskılı, prolaktin düşük","TSH yüksek, FSH değişmez","hCG yüksek, progesteron yüksek"],"correct":0,"exp":"Menopozda ovaryan folikül rezervi azalır, östradiol ve inhibin azalır. Negatif geri bildirim azalınca özellikle FSH yükselir."},{"id":2431,"ders":"Fizyoloji","konu":"Endokrin ve Genital Sistem HistoFizyolojisi","diff":4,"q":"Akromegali şüphesi olan hastada IGF-1 yüksek bulunuyor. Büyüme hormonunun uzun dönem büyüme etkilerinin önemli bölümü hangi organ kaynaklı mediyatörle oluşur?","options":["Karaciğer kaynaklı IGF-1","Böbrek kaynaklı renin","Tiroid kaynaklı kalsitonin","Pankreas kaynaklı somatostatin","Adrenal medulla kaynaklı aldosteron"],"correct":0,"exp":"GH karaciğerde IGF-1 üretimini artırır. IGF-1 kemik ve yumuşak doku büyümesi gibi uzun dönem etkilerin önemli aracısıdır."},{"id":2432,"ders":"Fizyoloji","konu":"Endokrin ve Genital Sistem HistoFizyolojisi","diff":5,"q":"Tip 2 diyabette insülin direnci olan hastada beta hücreleri başlangıçta daha fazla insülin salgılayarak glisemiyi dengelemeye çalışıyor. İnsülin reseptörünün hücre içi sinyali hangi reseptör sınıfına aittir?","options":["Reseptör tirozin kinaz","G protein bağlı reseptör","Ligand kapılı klor kanalı","Nükleer steroid reseptörü","Guanylat siklaz reseptörü"],"correct":0,"exp":"İnsülin reseptörü intrinsik tirozin kinaz aktivitesine sahip reseptördür. Otofosforilasyon ve IRS yollarıyla metabolik etkiler başlar."},{"id":2433,"ders":"Fizyoloji","konu":"Endokrin ve Genital Sistem HistoFizyolojisi","diff":4,"q":"Gebelikte artan plasental hormonlar nedeniyle periferik insülin direnci gelişebiliyor. Bu durumun anne metabolizmasındaki fizyolojik amacı en iyi hangisidir?","options":["Glukozun fetüse yönlendirilmesine katkı sağlamak","Anne beyninin glukoz kullanımını tamamen durdurmak","Fetal böbrekten insülin salgısını kesmek","Plasentanın oksijen geçirgenliğini kapatmak","Maternal keton üretimini imkansız hale getirmek"],"correct":0,"exp":"Gebelikte plasental hormonlar anne dokularında insülin direncini artırabilir. Böylece glukoz ve enerji substratlarının fetüse ulaşması desteklenir."},{"id":2434,"ders":"Fizyoloji","konu":"Endokrin ve Genital Sistem HistoFizyolojisi","diff":4,"q":"Tiroid hormonları yüksek olan hastada istirahatte oksijen tüketimi, ısı üretimi ve kalp hızı artıyor. Bu bulgular tiroid hormonlarının hangi genel etkisiyle uyumludur?","options":["Bazal metabolizma hızını artırması","Mitokondriyal aktiviteyi tamamen kapatması","Beta adrenerjik duyarlılığı azaltması","Sodyum-potasyum pompasını baskılaması","Tüm dokularda protein sentezini durdurması"],"correct":0,"exp":"Tiroid hormonları bazal metabolizma hızını ve ısı üretimini artırır. Ayrıca beta adrenerjik yanıtları güçlendirerek taşikardi gibi bulgulara katkı verir."},{"id":2435,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"Yüksek irtifaya çıkan kişide arteriyel oksijen basıncı düşünce ventilasyon hızla artıyor. Bu akut ventilatuvar yanıtı başlatan temel reseptörler hangileridir?","options":["Karotis ve aort cisimciklerindeki periferik kemoreseptörler","Sadece medüller santral kemoreseptörler","Pulmoner ven baroreseptörleri","Kas iğcikleri","Böbrek jukstaglomerüler hücreleri"],"correct":0,"exp":"Hipoksemiye hızlı ventilatuvar yanıt esas olarak karotis ve aort cisimciklerindeki periferik kemoreseptörlerle oluşur. Santral kemoreseptörler CO2/pH değişimine daha duyarlıdır."},{"id":2436,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"Opioid alan hastada hipoventilasyon ve PaCO2 artışı gelişiyor. Normalde CO2 artışına ventilasyon yanıtını en güçlü uyaran değişiklik hangisidir?","options":["Beyin omurilik sıvısında H+ artışı","Arteriyel oksijen satürasyonunun %100 olması","Plazma sodyumunun yükselmesi","Karaciğerde glikojenolizin artması","Alveolde surfaktan artışı"],"correct":0,"exp":"CO2 kan-beyin bariyerini geçer ve BOS'ta H+ artışına yol açar. Santral kemoreseptörler bu pH değişimine yanıt vererek ventilasyonu artırır."},{"id":2437,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"Dokulardan akciğere taşınan karbondioksitin büyük kısmı kanda hangi formda taşınır?","options":["Bikarbonat olarak","Çözünmüş CO2 olarak","Karbaminohemoglobin olarak","Karbonik asit olarak serbest","Albumine kovalent bağlı oksijenle birlikte"],"correct":0,"exp":"CO2'nin büyük kısmı eritrositlerde karbonik anhidraz aracılığıyla bikarbonata çevrilir ve plazmada bikarbonat olarak taşınır."},{"id":2438,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":5,"q":"Pulmoner emboli sonrası bazı alveoller havalanmaya devam ettiği halde perfüzyon alamıyor. Bu bölgeler fizyolojik olarak neye dönüşür?","options":["Ölü boşluk","Sağ-sol şant","Tam difüzyon bariyeri olmadan normal V/Q alanı","Restriktif volüm kaybı","Bronşiyal sekresyon odağı"],"correct":0,"exp":"Pulmoner embolide ventilasyon korunup perfüzyon azaldığında V/Q oranı yükselir ve alveoler ölü boşluk artar."},{"id":2439,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":5,"q":"Ağır pnömonide oksijen verilmesine rağmen hipoksemi yeterince düzelmiyor. Alveoller perfüze olduğu halde havalanmadığında bu durum hangi fizyolojik bozuklukla uyumludur?","options":["Sağ-sol şant","Saf ölü boşluk artışı","Diffüzyon kapasitesinin artması","Hiperventilasyona bağlı respiratuvar alkaloz","Fizyolojik olarak normal V/Q"],"correct":0,"exp":"Şantta kan havalanmayan alveollerden geçer. Oksijen tedavisine yanıt V/Q mismatch'e göre daha sınırlıdır çünkü şantlanan kan alveoler gazla temas etmez."},{"id":2440,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"KOAH'lı hastanın spirometrisinde FEV1 belirgin düşmüş, FEV1/FVC oranı azalmış bulunuyor. Bu patern hangi solunum bozukluğuna uyar?","options":["Obstrüktif ventilatuvar bozukluk","Restriktif ventilatuvar bozukluk","Normal spirometri","Nöromüsküler saf hiperventilasyon","Santral apne"],"correct":0,"exp":"Obstrüktif hastalıklarda hava akımı kısıtlanır; FEV1 belirgin azalır ve FEV1/FVC oranı düşer."},{"id":2441,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"Pulmoner fibrozisi olan hastada vital kapasite ve total akciğer kapasitesi azalmış, FEV1/FVC oranı normal-yüksek bulunuyor. Bu tablo hangi fizyolojik paternle uyumludur?","options":["Restriktif ventilatuvar bozukluk","Obstrüktif ventilatuvar bozukluk","Saf üst hava yolu obstrüksiyonu","Artmış akciğer kompliyansı","Artmış rezidüel hacimle normal TLC"],"correct":0,"exp":"Restriktif hastalıklarda akciğer volümleri azalır. FEV1 ve FVC birlikte düşer; oran genellikle normal veya yüksek kalır."},{"id":2442,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"Prematüre bebekte surfaktan eksikliğine bağlı solunum sıkıntısı gelişiyor. Surfaktanın temel fizyolojik etkisi hangisidir?","options":["Alveol yüzey gerilimini azaltarak kollapsı önlemek","Alveol duvarını kalınlaştırarak difüzyonu yavaşlatmak","Bronş düz kasını sürekli kasmak","Pulmoner damar direncini artırmak","Hemoglobinin oksijene afinitesini düşürmek"],"correct":0,"exp":"Surfaktan alveol yüzey gerilimini azaltır, özellikle küçük alveollerin kollapsını önler ve akciğer kompliyansını artırır."},{"id":2443,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"Amfizemli hastada DLCO düşük bulunuyor. Bu azalmanın temel nedeni hangisidir?","options":["Alveol-kapiller yüzey alanının azalması","Hemoglobin miktarının aşırı artması","Pulmoner kapiller kan hacminin artması","Alveol membranının incelmesiyle difüzyonun artması","Karbonmonoksitin hiç bağlanamaması"],"correct":0,"exp":"Amfizemde alveoler septalar yıkılır ve difüzyon yüzey alanı azalır. Bu nedenle DLCO düşer."},{"id":2444,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"Ateşli ve egzersiz yapan hastada dokulara oksijen bırakılması kolaylaşıyor. Bu durumda hemoglobin-oksijen disosiasyon eğrisinde beklenen değişiklik hangisidir?","options":["Sağa kayma","Sola kayma","P50'nin azalması","Oksijen afinitesinin artması","Hemoglobinin oksijen taşıma kapasitesinin sıfırlanması"],"correct":0,"exp":"Isı artışı, CO2 artışı, H+ artışı ve 2,3-BPG artışı eğriyi sağa kaydırır. Hb'nin oksijen afinitesi azalır ve dokulara oksijen bırakılması kolaylaşır."},{"id":2445,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"Yüksek irtifaya yeni çıkan kişide hiperventilasyon sonrası respiratuvar alkaloz gelişiyor. Birkaç gün içinde böbreğin kompansatuvar yanıtı hangisidir?","options":["Bikarbonat atılımını artırmak","Hidrojen atılımını artırmak","Amonyum üretimini artırmak","Bikarbonat geri emilimini maksimuma çıkarmak","ADH salınımını tamamen durdurmak"],"correct":0,"exp":"Yüksek irtifada hipoksemi ventilasyonu artırır, CO2 düşer ve respiratuvar alkaloz gelişir. Böbrek bikarbonat atılımını artırarak pH'ı dengelemeye çalışır."},{"id":2446,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"Fetal hemoglobin erişkin hemoglobine göre oksijeni plasentadan daha kolay alır. Bu fark disosiasyon eğrisinde nasıl görünür?","options":["Fetal hemoglobinin sola kayması","Fetal hemoglobinin sağa kayması","Fetal hemoglobinin P50 değerinin artması","Fetal hemoglobinin oksijene hiç bağlanmaması","Fetal hemoglobinin 2,3-BPG'ye daha güçlü bağlanması"],"correct":0,"exp":"HbF 2,3-BPG'ye daha zayıf bağlanır ve oksijen afinitesi daha yüksektir. Eğrisi sola kaymıştır; plasentadan oksijen almayı kolaylaştırır."},{"id":2447,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":5,"q":"Kronik CO2 retansiyonu olan KOAH hastasında solunum merkezi yüksek CO2'ye kısmen adapte olmuştur. Bu hastada ventilasyonu sürdürmede göreceli olarak daha önemli hale gelen uyaran hangisidir?","options":["Hipoksemiye periferik kemoreseptör yanıtı","Hiperkalsemiye santral yanıt","Hipernatremiye akciğer gerilme yanıtı","Aldosteron artışı","Mide pH'sındaki düşme"],"correct":0,"exp":"Kronik hiperkapnide santral kemoreseptör yanıtı kısmen adapte olabilir. Hipoksemiye periferik kemoreseptör yanıtı ventilasyon sürdürülmesinde daha önemli hale gelir."},{"id":2448,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"Pulmoner ödem gelişen hastada akciğerler sertleşmiş, solunum işi artmış bulunuyor. Bu tabloda azalan temel mekanik özellik hangisidir?","options":["Akciğer kompliyansı","Hava yolu direnci olmadan tüm volümler","Hemoglobin afinitesi","Anatomik ölü boşluk","Surfaktan üretimi artışına bağlı elastans"],"correct":0,"exp":"Pulmoner ödemde interstisyel/alveoler sıvı artışı akciğer kompliyansını azaltır. Daha fazla basınçla daha az hacim değişimi olur."},{"id":2449,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"Travma sonrası pnömotoraks gelişen hastada etkilenen akciğer kollabe oluyor. Normalde akciğeri açık tutmaya yardım eden plevral basınç özelliği hangisidir?","options":["Negatif intraplevral basınç","Pozitif intraplevral basınç","Alveol basıncının sürekli sıfırın altında olması","Pulmoner arter basıncının atmosferden düşük olması","Bronş içi basıncın daima negatif olması"],"correct":0,"exp":"Normalde intraplevral basınç negatiftir ve akciğerin göğüs duvarına tutunmasına yardım eder. Pnömotoraksta plevral boşluğa hava girer, negatif basınç kaybolur ve akciğer kollabe olabilir."},{"id":2450,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":3,"q":"Aşırı derin inspirasyon sırasında akciğer gerilimi artınca inspirasyonun baskılanmasına katkı veren refleks aktive olur. Bu refleks hangisidir?","options":["Hering-Breuer inflasyon refleksi","Baroreseptör refleksi","Bezold-Jarisch refleksi","Okülo-kardiyak refleks","Miksiyon refleksi"],"correct":0,"exp":"Hering-Breuer inflasyon refleksi akciğer gerilme reseptörleriyle ilişkilidir. Özellikle aşırı gerilmeyi sınırlayarak inspirasyonu baskılayabilir."},{"id":2451,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"Diz kapağı tendonuna vurulduğunda kuadriseps hızla kasılıyor. Bu refleksin afferent lifi ve sinaptik özelliği için en doğru ifade hangisidir?","options":["Ia afferent ile monosnaptik gerilme refleksi","C lifi ile polisinaptik ağrı refleksi","Ib afferent ile parasempatik refleks","A delta lifi ile otonom sekresyon refleksi","Sadece üst motor nöronla gerçekleşen refleks"],"correct":0,"exp":"Kas iğciğinden gelen Ia afferent lifler spinal kordda alfa motor nöronla monosnaptik bağlantı kurar. Patellar refleks klasik gerilme refleksidir."},{"id":2452,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"Üst motor nöron lezyonu olan hastada spastisite ve derin tendon reflekslerinde artış görülüyor. Bu artışı en iyi açıklayan fizyolojik değişiklik hangisidir?","options":["Spinal refleks devreleri üzerindeki inen inhibitör kontrolün azalması","Alfa motor nöronların tamamen ölmesi","Kas iğciklerinin tümünün kaybolması","Nöromüsküler kavşakta asetilkolin salınımının durması","Dorsal kök ganglionlarının çıkarılması"],"correct":0,"exp":"Üst motor nöron lezyonlarında inen inhibitör kontrol azalır. Spinal refleksler kolaylaşır, hiperrefleksi ve spastisite gelişir."},{"id":2453,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"Alt motor nöron lezyonu olan hastada flask paralizi, fasikülasyon ve atrofi gelişiyor. Bu bulgulardan atrofi en çok hangi kayıpla ilişkilidir?","options":["Kasın nöral trofik desteğinin kaybı ve denervasyon","Serebellar Purkinje hücrelerinin aşırı çalışması","Kortikal inhibitör tonusun artması","Kas iğciği afferentlerinin aşırı uyarılması","Bazal ganglion dopamininin artması"],"correct":0,"exp":"Alt motor nöron hasarında kas doğrudan denervasyona uğrar. Trofik destek kaybı, kullanılmama ve denervasyon atrofisi gelişir."},{"id":2454,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"Keskin ağrı ve ısı duyusu omurilikte karşı tarafa geçtikten sonra talamusa yükselir. Bu duyuları taşıyan ana yol hangisidir?","options":["Spinotalamik trakt","Dorsal kolon-medial lemniskus","Kortikospinal trakt","Spinocerebellar trakt","Fasikulus longitudinalis medialis"],"correct":0,"exp":"Ağrı ve ısı duyusu periferden girer, birkaç segment içinde karşıya geçerek anterolateral/spinotalamik sistemle talamusa taşınır."},{"id":2455,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"Vibrasyon ve propriosepsiyon kaybı olan hastada lezyonun dorsal kolon sisteminde olduğu düşünülüyor. Bu lifler karşı tarafa nerede geçer?","options":["Medulla düzeyinde","Giriş yaptıkları spinal segmentte hemen","Talamusta","Serebellumda","Periferik sinirde"],"correct":0,"exp":"Dorsal kolon lifleri ipsilateral olarak medullaya yükselir; nucleus gracilis/cuneatus sonrası iç arkuat lifler olarak çapraz yapar ve medial lemniskusu oluşturur."},{"id":2456,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"Lokal anestezik verilen bölgede ağrı iletimi kesiliyor. Aksiyon potansiyelinin hızlı yükselme fazını engelleyen temel kanal hangisidir?","options":["Voltaj kapılı sodyum kanalı","L tipi kalsiyum kanalı","Ligand kapılı klor kanalı","Aquaporin-2","ATP duyarlı potasyum kanalı"],"correct":0,"exp":"Nöron aksiyon potansiyelinin depolarizasyon fazı voltaj kapılı Na+ kanallarından Na+ girişiyle oluşur. Lokal anestezikler bu kanalları bloke eder."},{"id":2457,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"Multipl skleroz atağında miyelin kaybı olan liflerde iletim yavaşlıyor. Miyelinin normalde sağladığı temel avantaj hangisidir?","options":["Saltatuvar iletimle aksiyon potansiyelinin Ranvier düğümleri arasında hızlı ilerlemesi","Akson çapını sıfıra indirmesi","Sinaptik aralıkta asetilkolini parçalaması","Nöron gövdesinde protein sentezini durdurması","Dendritlerde oksijen taşınmasını sağlaması"],"correct":0,"exp":"Miyelin internodlarda membran direncini artırır ve kapasitansı azaltır. Aksiyon potansiyeli Ranvier düğümleri arasında sıçrayarak hızlı iletilir."},{"id":2458,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"Presinaptik uçta aksiyon potansiyeli geldikten sonra nörotransmitter vezikülleri membranla kaynaşıyor. Bu salınımı doğrudan başlatan iyon hareketi hangisidir?","options":["Voltaj kapılı kalsiyum kanallarından Ca2+ girişi","Klorun hücre içine pasif girişi","Sodyum-potasyum pompasının durması","Magnezyumun vezikül içine girmesi","Bikarbonatın aksondan çıkması"],"correct":0,"exp":"Presinaptik depolarizasyon voltaj kapılı Ca2+ kanallarını açar. Ca2+ girişi vezikül füzyonunu ve nörotransmitter salınımını tetikler."},{"id":2459,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"İnhibitör postsinaptik potansiyel oluşturan bir sinapsta postsinaptik membranın eşikten uzaklaştığı görülüyor. Bu etki en çok hangi iyon hareketiyle uyumludur?","options":["Klor girişinin veya potasyum çıkışının artması","Sodyum girişinin artması","Kalsiyum girişinin artması","Glukoz girişinin artması","Demir çıkışının artması"],"correct":0,"exp":"IPSP genellikle Cl- girişi veya K+ çıkışıyla membranı hiperpolarize eder ya da eşikten uzaklaştırır. Böylece aksiyon potansiyeli oluşma olasılığı azalır."},{"id":2460,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"Baş hızla sağa çevrildiğinde gözlerin hedefte kalmak için sola doğru hareket ettiği izleniyor. Bu yanıt hangi sistemin görevidir?","options":["Vestibülo-oküler refleks","Pupiller ışık refleksi","Gerilme refleksi","Golgi tendon refleksi","Miksiyon refleksi"],"correct":0,"exp":"Vestibülo-oküler refleks baş hareketi sırasında görüntüyü retinada sabit tutmak için gözleri karşı yönde hareket ettirir."},{"id":2461,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"İç kulaktaki saçlı hücrelerde stereosilyalar kinosilyuma doğru eğildiğinde hücre depolarize olur. Bu depolarizasyonun başlıca nedeni hangisidir?","options":["Endolenften K+ girişi","Perilenften Na+ çıkışı","Sodyum-potasyum pompasının aniden durması","Klorun stereosilyadan dışarı çıkması","Kalsiyumun çekirdeğe bağlanması"],"correct":0,"exp":"Endolenf potasyumdan zengindir ve pozitif elektriksel potansiyele sahiptir. Stereosilya kanalları açıldığında K+ saçlı hücreye girer ve depolarizasyon olur."},{"id":2462,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"Karanlıktan parlak ışığa çıkan kişide fotoreseptörlerde glutamat salınımı azalıyor. Işıkta fotoreseptör membran potansiyeli nasıl değişir?","options":["Hiperpolarize olur","Depolarize olur","Aksiyon potansiyeli üretmeye başlar","Sodyum-potasyum pompası durur","Klor kanalları kalıcı açılır"],"correct":0,"exp":"Fotoreseptörler karanlıkta depolarizedir ve glutamat salar. Işık cGMP'yi azaltır, Na+ kanalları kapanır ve fotoreseptör hiperpolarize olur."},{"id":2463,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"Yakına bakış sırasında pupilla küçülür, lens kalınlaşır ve gözler konverjans yapar. Lens kalınlaşmasını sağlayan kas hangi otonom etkiyle kasılır?","options":["Parasempatik uyarıyla siliyer kas kasılması","Sempatik uyarıyla iris dilatatör kas kasılması","Somatik uyarıyla lateral rektus kasılması","Parasempatik uyarıyla trabeküler ağın kapanması","Sempatik uyarıyla sfinkter pupilla gevşemesi"],"correct":0,"exp":"Yakına uyumda parasempatik aktivite siliyer kası kasar. Zonüler lif gerilimi azalır, lens daha konveks hale gelir."},{"id":2464,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":5,"q":"Parkinson hastalığında hareket başlatmada güçlük ve rijidite gelişiyor. Bazal ganglion devrelerinde dopamin azalması en çok hangi bölgedeki nöron kaybıyla ilişkilidir?","options":["Substantia nigra pars compacta","Hipokampus CA1","Nucleus ruber","Locus coeruleus","Dorsal kök ganglionu"],"correct":0,"exp":"Parkinson hastalığında substantia nigra pars compacta dopaminerjik nöronları kaybolur. Dopamin azalması bazal ganglion motor devrelerinde hareketi azaltıcı etki oluşturur."},{"id":2465,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"Serebellar lezyonu olan hastada hedefe uzanırken tremor belirginleşiyor, dismetri ve geniş tabanlı yürüyüş var. Bu bulgular serebellumun hangi rolüyle uyumludur?","options":["Hareketin koordinasyonu ve hata düzeltmesi","Primer kas gücünün doğrudan oluşturulması","Ağrı duyusunun kortekse taşınması","Otonom ter bezlerinin kontrolü","Sadece bilinç düzeyinin korunması"],"correct":0,"exp":"Serebellum hareketlerin zamanlaması, koordinasyonu ve hata düzeltmesinde rol alır. Lezyonunda ataksi, dismetri ve intansiyon tremoru görülür."},{"id":2466,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"REM uykusunda EEG uyanıklığa benzerken iskelet kas tonusu belirgin azalır. Bu fizyolojik atoni neden önemlidir?","options":["Rüya içeriğine uygun motor hareketlerin gerçekleştirilmesini engeller","Solunumu tamamen durdurur","Kalp kasını gevşetir","Retinanın ışığa yanıtını kapatır","Beyin sapı reflekslerini kalıcı olarak siler"],"correct":0,"exp":"REM uykusunda kas atonisi rüya sırasında motor davranışların ortaya çıkmasını engeller. Bu mekanizma bozulursa REM davranış bozukluğu görülebilir."},{"id":2467,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"Ağrılı uyaran sonrası aynı ekstremitede fleksör kaslar kasılırken ekstansörler inhibe oluyor. Bu spinal refleks düzenlenmesi hangisidir?","options":["Resiprokal inhibisyon","Uzun süreli potansiyasyon","Presinaptik fasilitasyon olmadan nöromodülasyon","Kortikal kolon organizasyonu","Gamma döngüsünün kapanması"],"correct":0,"exp":"Refleks hareketlerde agonist kas aktivasyonu ile antagonist kas inhibisyonu birlikte olur. Bu resiprokal inhibisyon koordineli hareket sağlar."},{"id":2468,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"Kas iğciğinin duyarlılığı, kas kısaldığında bile korunabiliyor. Bu ayarı yapan motor nöron tipi hangisidir?","options":["Gamma motor nöron","Alfa motor nöron","Preganglionik sempatik nöron","Purkinje hücresi","Betz hücresi"],"correct":0,"exp":"Gamma motor nöronlar intrafüzal kas liflerinin uçlarını kasar ve kas iğciği duyarlılığını ayarlar. Böylece gerilme bilgisi hareket sırasında korunur."},{"id":2469,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":5,"q":"Golgi tendon organı aşırı kas gerilimini algıladığında aynı kasın motor nöron aktivitesini azaltan bir refleks başlatır. Bu refleksin afferent lifi hangisidir?","options":["Ib afferent","Ia afferent","C lifi","A delta lifi","Preganglionik parasempatik lif"],"correct":0,"exp":"Golgi tendon organı kas-tendon gerilimini Ib afferentlerle taşır. Aşırı gerilimde inhibitör internöronlar üzerinden aynı kasın aktivitesi azaltılabilir."},{"id":2470,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"Organofosfat zehirlenmesinde miyozis, bronkore ve kas fasikülasyonları gelişiyor. Sinaptik aralıkta biriken nörotransmitter hangisidir?","options":["Asetilkolin","Dopamin","GABA","Glutamat","Serotonin"],"correct":0,"exp":"Organofosfatlar asetilkolinesterazı inhibe eder. Asetilkolin sinaptik aralıkta birikir; muskarinik, nikotinik ve santral bulgular oluşur."},{"id":2471,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"NSAİİ kullanan dehidrate hastada kreatinin yükseliyor. Prostaglandin sentezinin baskılanması böbrekte en çok hangi hemodinamik etkiyle GFR'yi azaltır?","options":["Afferent arteriol vazokonstriksiyonu","Efferent arteriol vazodilatasyonu","Glomerüler kapsül basıncının sıfırlanması","Renal ven dilatasyonu","Toplayıcı kanalda su geçirgenliğinin artması"],"correct":0,"exp":"Renal prostaglandinler özellikle düşük efektif dolaşımda afferent arteriolü dilate ederek GFR'yi korur. NSAİİ bu desteği azaltır ve afferent vazokonstriksiyonla GFR düşebilir."},{"id":2472,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"ACE inhibitörü başlanan bilateral renal arter stenozlu hastada kreatinin hızla artıyor. Bu artış en çok hangi değişiklikle açıklanır?","options":["Efferent arteriol dilatasyonu ile glomerüler kapiller basıncın düşmesi","Afferent arteriol dilatasyonu ile filtrasyonun artması","Proksimal tübülde glukoz emiliminin artması","Toplayıcı kanalda ADH etkisinin artması","Bowman kapsül basıncının azalması"],"correct":0,"exp":"Anjiyotensin II efferent arteriolü daraltarak glomerüler basıncı ve GFR'yi korur. ACE inhibitörü efferent dilatasyon yapar; renal arter stenozunda GFR düşebilir."},{"id":2473,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"Düşük sodyum alımı ve düşük renal perfüzyon olan hastada renin salınımı artıyor. Renin salınımını uyaran makula densa sinyali hangisidir?","options":["Distal tübüle ulaşan NaCl'nin azalması","Distal tübüle ulaşan NaCl'nin artması","İdrarda glukozun artması","Toplayıcı kanalda üre geçirgenliğinin azalması","Bowman boşluğunda protein artışı"],"correct":0,"exp":"Makula densa distal tübüldeki NaCl teslimini algılar. NaCl azalması renin salınımını artırır ve tubuloglomerüler geri bildirimle GFR korunmaya çalışılır."},{"id":2474,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"Araştırmada bir maddenin serbestçe filtre edildiği, geri emilmediği ve sekrete edilmediği gösteriliyor. Bu maddenin klirensi hangi böbrek fonksiyonunu verir?","options":["GFR","Renal plazma akımı","Serbest su klirensi","Filtrasyon fraksiyonu olmadan idrar akımı","Tübüler maksimum"],"correct":0,"exp":"İnülin gibi serbestçe filtrelenen, geri emilmeyen ve sekrete edilmeyen maddelerin klirensi GFR'yi verir."},{"id":2475,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"PAH klirensi renal fizyoloji deneyinde renal plazma akımını tahmin etmek için kullanılıyor. Bunun nedeni hangisidir?","options":["PAH'ın filtre edilip büyük ölçüde sekrete edilerek plazmadan neredeyse tamamen temizlenmesi","PAH'ın hiç filtre edilmemesi","PAH'ın sadece toplayıcı kanalda suyla birlikte emilmesi","PAH'ın eritrosit içine hapsolması","PAH'ın glomerülde albumine dönüşmesi"],"correct":0,"exp":"PAH düşük konsantrasyonlarda böbreğe gelen plazmadan filtrasyon ve sekresyonla büyük ölçüde temizlenir. Bu nedenle efektif renal plazma akımını tahmin eder."},{"id":2476,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"Kontrolsüz diyabette plazma glukozu arttıkça bir noktadan sonra idrarda glukoz görülüyor. Bu durumun nedeni hangisidir?","options":["Proksimal tübüldeki glukoz taşıyıcılarının taşıma maksimumuna ulaşması","Glukozun glomerülden filtre edilememesi","Toplayıcı kanalda glukozun aktif salgılanması","ADH'nin glukozu idrara atması","Glukozun albumine bağlanarak idrara geçmesi"],"correct":0,"exp":"Glukoz proksimal tübülde SGLT taşıyıcılarıyla geri emilir. Plazma glukozu çok artınca filtre edilen yük Tm'yi aşar ve glukozüri oluşur."},{"id":2477,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":5,"q":"Henle kulpunun çıkan kalın kolunu etkileyen bir ilaç sonrası medüller hipertonisite azalıyor ve idrarı yoğunlaştırma kapasitesi düşüyor. Bu segmentin temel özelliği hangisidir?","options":["Na-K-2Cl taşırken suya geçirimsiz olması","Suya çok geçirgen olup sodyuma geçirimsiz olması","Sadece glukoz geri emmesi","ADH olmadan üre salgılaması","Bikarbonatı hiç taşımaması"],"correct":0,"exp":"Çıkan kalın kol Na-K-2Cl kotransportuyla tuz geri emer, suya geçirimsizdir. Bu countercurrent multiplier ve medüller gradyan için kritiktir."},{"id":2478,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"Susuz kalan kişide ADH artışıyla idrar konsantre hale geliyor. ADH'nin iç medüller toplayıcı kanalda üre üzerinden de katkı sağlaması hangi etkiyle olur?","options":["Üre geçirgenliğini artırarak medüller ozmotik gradyanı güçlendirmesi","Üre sentezini böbrekte tamamen durdurması","Üreyi glukoza çevirmesi","Üreyi proksimal tübülde tamamen sekrete etmesi","Üreyi albumine bağlayıp filtrasyonu engellemesi"],"correct":0,"exp":"ADH iç medüller toplayıcı kanalda su geçirgenliğini artırır; ayrıca üre geçirgenliğini artırarak medüller hipertonisiteye katkı sağlar."},{"id":2479,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"Proksimal tübül hasarında bikarbonat, fosfat, aminoasit ve glukoz kaybı gelişiyor. Bu segmentin normalde geri emilim açısından genel özelliği hangisidir?","options":["Filtre edilen solüt ve suyun büyük kısmını izoozmotik olarak geri emmesi","Sadece su geri emmesi ve solütleri hiç taşımaması","Sadece aldosterona yanıt vermesi","İdrarın son yoğunluğunu tek başına belirlemesi","Sodyumu yalnız pasif olarak salgılaması"],"correct":0,"exp":"Proksimal tübül filtre edilen Na+, su, bikarbonat, glukoz ve aminoasitlerin büyük kısmını geri emer. Geri emilim çoğunlukla izoozmotiktir."},{"id":2480,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"Primer hiperaldosteronizmli hastada hipertansiyon, hipokalemi ve metabolik alkaloz var. Aldosteronun principal hücrede potasyumu düşüren etkisi hangisidir?","options":["ENaC üzerinden sodyum geri emilimini artırıp lümen negatifliğini güçlendirmesi","Na-K-2Cl kotransporterini tamamen kapatması","Glomerülde potasyum filtrasyonunu durdurması","ADH reseptörünü bloke etmesi","Proksimal tübülde glukoz geri emilimini artırması"],"correct":0,"exp":"Aldosteron principal hücrelerde ENaC ve Na/K ATPaz aktivitesini artırır. Lümen daha negatif hale gelir, K+ sekresyonu artar; hipokalemi gelişebilir."},{"id":2481,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"Kronik metabolik asidozu olan hastada böbreğin asit atılımını artırması beklenir. Tübül hücrelerinde amonyak üretimi hangi aminositten artar?","options":["Glutamin","Fenilalanin","Triptofan","Metiyonin","Lizin"],"correct":0,"exp":"Böbrek asidozda glutaminden amonyak/amonyum üretimini artırır. NH4+ olarak asit atılımı ve yeni bikarbonat üretimi sağlanır."},{"id":2482,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"Aspirin intoksikasyonunun erken döneminde hiperventilasyona bağlı respiratuvar alkaloz gelişen hastada böbrek kompansasyonu bekleniyor. Uygun renal yanıt hangisidir?","options":["Bikarbonat geri emilimini azaltmak ve bikarbonat atılımını artırmak","Amonyum atılımını artırmak","Hidrojen sekresyonunu artırmak","Yeni bikarbonat üretimini artırmak","İdrarı maksimum asidik yapmak"],"correct":0,"exp":"Respiratuvar alkalozda pH yükselir. Böbrek bikarbonat geri emilimini azaltır ve bikarbonat atılımını artırarak kompansasyon sağlar."},{"id":2483,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"Yüksek potasyum alımı sonrası sağlıklı kişide idrarla potasyum atılımı artıyor. Bu adaptasyona en çok katkı veren hormon hangisidir?","options":["Aldosteron","Kalsitonin","Prolaktin","Glukagon","Eritropoietin"],"correct":0,"exp":"Hiperkalemi aldosteron salınımını doğrudan uyarabilir. Aldosteron distal nefronda K+ sekresyonunu artırarak potasyum atılımını sağlar."},{"id":2484,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":5,"q":"Su yüklemesi sonrası sağlıklı kişide idrar seyreliyor ve serbest su atılımı artıyor. Bu durumda ADH düzeyi ve toplayıcı kanal su geçirgenliği için en doğru ifade hangisidir?","options":["ADH azalır, toplayıcı kanal su geçirgenliği düşer","ADH artar, toplayıcı kanal su geçirgenliği düşer","ADH azalır, aquaporin-2 membrana daha fazla yerleşir","ADH değişmez, idrar sadece glomerülde seyrelir","ADH artar, idrar zorunlu olarak seyreltik çıkar"],"correct":0,"exp":"Su yüklemesinde plazma ozmolalitesi düşer, ADH baskılanır. Toplayıcı kanal suya daha az geçirgen olur ve seyreltik idrar atılır."},{"id":2485,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"Kreatinin klirensi ölçülen hastada gerçek GFR'ye göre hafif yüksek sonuç elde ediliyor. Bunun nedeni aşağıdakilerden hangisidir?","options":["Kreatininin az miktarda tübüler sekresyona uğraması","Kreatininin glomerülden filtre edilmemesi","Kreatininin tamamen geri emilmesi","Kreatininin sadece albumine bağlı taşınması","Kreatininin böbrekte üreye dönüşmesi"],"correct":0,"exp":"Kreatinin serbestçe filtre edilir ve az miktarda proksimal tübüler sekresyona uğrar. Bu nedenle kreatinin klirensi GFR'yi hafif fazla tahmin eder."},{"id":2486,"ders":"Fizyoloji","konu":"Baş Boyun Embriyolojisi","diff":4,"q":"Doğumdan sonra orta hatta, dil kökü ile tiroid arasında hareketli kistik kitle saptanan çocukta tiroglossal kanal kisti düşünülüyor. Bu kistin kökeni en iyi hangi embriyolojik olayla ilişkilidir?","options":["Tiroid bezinin foramen çekumdan aşağı doğru göç yolunun kalıntısı","Birinci brankiyal yarığın dış kulak yoluna dönüşememesi","Nöral tüpün posterior nöroporunun kapanmaması","Paratiroidlerin böbrekten göç etmesi","Timusun adrenal kortekse dönüşmesi"],"correct":0,"exp":"Tiroid bezi dil kökündeki foramen çekum bölgesinden aşağı göç eder. Tiroglossal kanal kalıntısı orta hat kisti olarak ortaya çıkabilir."},{"id":2487,"ders":"Fizyoloji","konu":"Baş Boyun Embriyolojisi","diff":5,"q":"Mandibula hipoplazisi ve dış kulak anomalileri olan bebekte birinci faringeal ark gelişim kusuru düşünülüyor. Bu arktan gelişen yapı aşağıdakilerden hangisidir?","options":["Malleus ve incus","Stapes ve hyoid üst boynuzu","Paratiroid alt bezleri","Tiroid parafoliküler hücreleri","Krikotiroid kas"],"correct":0,"exp":"Birinci faringeal ark Meckel kıkırdağı ilişkili yapılara, malleus ve incusa, çiğneme kaslarına ve trigeminal sinirin mandibular dalıyla ilişkili yapılara katkı verir."},{"id":3580,"ders":"Fizyoloji","konu":"Hücre Histolojisi ve Fizyolojisi","diff":4,"q":"24 yaşındaki erkek hasta 2 gündür tekrarlayan kusma ve halsizlik yakınmasıyla geliyor. Kronik hastalığı yok, düzenli ilaç kullanmıyor. Serum potasyumu düşük saptanan bu hastada hücre içi istirahat membran potansiyeli için hangi değişiklik beklenir?","options":["Membran potansiyelinin daha negatif hale gelmesi","Sodyum denge potansiyelinin daha negatif hale gelmesi","Klorür geçirgenliğinin tamamen kaybolması","Hücre içi kalsiyumun hızla sıfırlanması","Aksiyon potansiyeli eşik değerinin değişmeden kalması"],"correct":0,"exp":"Hipokalemi, potasyumun hücre dışı konsantrasyonunu azaltır ve potasyum denge potansiyelini daha negatif yapar. Dinlenim membran potansiyeli potasyum geçirgenliğine çok bağımlı olduğu için hücre hiperpolarize olur. Kısa akıl notu: dış K azalırsa hücre daha 'kapalı' kalır."},{"id":3581,"ders":"Fizyoloji","konu":"Hücre Histolojisi ve Fizyolojisi","diff":4,"q":"31 yaşındaki kadın hasta 6 saattir süren ishal ve baş dönmesi yakınmasıyla başvuruyor. Kronik hastalığı yok, düzenli ilaç kullanmıyor. İnce bağırsak epitelinde glukoz ve sodyumun lümenden birlikte emilimi için hangi taşıma özelliği gereklidir?","options":["Bazolateral Na-K ATPazın oluşturduğu sodyum gradyenti","Apikal potasyum kanallarının kapanması","Hücre içine pasif klorür girişinin tamamen durması","Glukozun sadece basit difüzyonla geçmesi","Mitokondri dış membranında proton kanalı açılması"],"correct":0,"exp":"SGLT aracılı glukoz emilimi sekonder aktif taşımadır. Enerji doğrudan SGLT tarafından değil, bazolateral Na-K ATPazın düşük hücre içi sodyum oluşturarak sağladığı gradyentten gelir."},{"id":3582,"ders":"Fizyoloji","konu":"Hücre Histolojisi ve Fizyolojisi","diff":3,"q":"67 yaşındaki erkek hasta 1 gündür süren bilinç bulanıklığı ve nöbet yakınmasıyla getiriliyor. Hipertansiyon dışında kronik hastalığı yok, amlodipin kullanıyor. Serum sodyumu belirgin düşük olan bu hastada beyin hücrelerinde erken dönemde hangi olay öne çıkar?","options":["Hücre içine su girişi ve hücresel şişme","Hücre dışına masif potasyum çıkışıyla hücre büzüşmesi","Sodyum kanallarının geri dönüşümsüz yıkımı","Laktat üretiminin tamamen durması","Miyelin sentezinin ani artışı"],"correct":0,"exp":"Akut hiponatremide plazma ozmolalitesi düşer ve su hücre içine geçer. Beyin kapalı bir alanda olduğu için hücresel şişme nöbet ve bilinç değişikliği yapabilir."},{"id":3583,"ders":"Fizyoloji","konu":"Hücre Histolojisi ve Fizyolojisi","diff":4,"q":"45 yaşındaki kadın hasta 3 gündür kas güçsüzlüğü ve çabuk yorulma yakınmasıyla geliyor. Hipotiroidi öyküsü var, levotiroksin kullanıyor. Hücrede ATP üretimi azaldığında iyon dengesini en erken bozan süreç hangisidir?","options":["Na-K ATPaz aktivitesinin azalması","Nükleer porlardan mRNA çıkışının artması","Ribozomlarda peptid bağının hızlanması","Lizozomal pH'nin nötrleşmeden sabit kalması","Hücre dışı matriks sentezinin artması"],"correct":0,"exp":"Na-K ATPaz ATP'ye bağımlıdır ve hücre hacmi ile membran potansiyelinin korunmasında kritiktir. ATP azalınca sodyum hücre içinde birikir, su onu izler ve hücre şişer."},{"id":3584,"ders":"Fizyoloji","konu":"Hücre Histolojisi ve Fizyolojisi","diff":3,"q":"Bir hücrede kolaylaştırılmış difüzyon ile basit difüzyonu ayırmada en belirleyici özellik hangisidir?","options":["Taşıyıcı doygunluğuna bağlı maksimum taşıma hızının bulunması","Enerjinin doğrudan ATP hidrolizinden sağlanması","Maddenin mutlaka elektrokimyasal gradyentine ters taşınması","Taşınan molekülün her zaman lipofilik olması","Hücre zarının iki yaprakçığının kalıcı ayrılması"],"correct":0,"exp":"Kolaylaştırılmış difüzyon taşıyıcı veya kanal aracılıdır ve taşıyıcı sayısı sınırlıysa doygunluk gösterir. Basit difüzyon ise genellikle konsantrasyon farkıyla orantılı ilerler."},{"id":3585,"ders":"Fizyoloji","konu":"Doku Histolojisi ve Fizyolojisi","diff":4,"q":"58 yaşındaki erkek hasta 2 haftadır ayak bileklerinde şişlik yakınmasıyla geliyor. Kronik karaciğer hastalığı var, spironolakton kullanıyor. Serum albümini düşük saptanan hastada interstisyel sıvı artışını en iyi açıklayan değişiklik hangisidir?","options":["Kapiller plazma onkotik basıncının azalması","Lenfatik drenajın aşırı artması","Arteriyol direncinin tamamen kaybolması","Kapiller hidrostatik basıncın sıfıra düşmesi","İnterstisyel proteinlerin tamamen temizlenmesi"],"correct":0,"exp":"Albüminden kaynaklanan plazma onkotik basıncı sıvıyı kapiller içinde tutar. Albümin azalınca Starling dengesi filtrasyon lehine kayar ve ödem gelişir."},{"id":3586,"ders":"Fizyoloji","konu":"Doku Histolojisi ve Fizyolojisi","diff":4,"q":"36 yaşındaki kadın hasta 4 gündür bacakta kızarıklık, ağrı ve şişlik yakınmasıyla başvuruyor. Diyabeti var, metformin kullanıyor. İnflame dokuda nötrofil göçünün damar dışına çıkış aşamasında hangi olay en kritik basamağı oluşturur?","options":["Endotel adezyon molekülleriyle lökosit integrinlerinin sıkı bağlanması","Eritrositlerin bazal membranı enzimatik olarak parçalaması","Albuminin lenfatiklerden kana geri taşınması","Fibroblastların miyelin sentezini artırması","Düz kas hücresinin aksoplazmik taşımaya başlaması"],"correct":0,"exp":"Lökosit ekstravazasyonunda yuvarlanma, adezyon ve transmigrasyon sıralanır. Sıkı adezyonda lökosit integrinleri endotel ICAM/VCAM gibi moleküllerle bağlanır."},{"id":3587,"ders":"Fizyoloji","konu":"Doku Histolojisi ve Fizyolojisi","diff":3,"q":"28 yaşındaki erkek hasta 10 gündür iyileşmeyen yüzeyel kesi nedeniyle başvuruyor. Kronik hastalığı yok, düzenli ilaç kullanmıyor. Granülasyon dokusunda kontraksiyonu sağlayan hücre tipi için hangi ifade doğrudur?","options":["Aktin içeren miyofibroblastlar yara kenarlarını yaklaştırır","Mast hücreleri kolajen liflerini mekanik olarak kısaltır","Adipositler bazal membranı kasılır hale getirir","Plazma hücreleri aktin-miyozin köprüleriyle epitel çeker","Endotel hücreleri sarkomer oluşturarak tüm yarayı kapatır"],"correct":0,"exp":"Yara kontraksiyonunda alfa düz kas aktini taşıyan miyofibroblastlar rol oynar. Bunlar fibroblast benzeri hücrelerdir fakat kasılabilme özelliği kazanırlar."},{"id":3588,"ders":"Fizyoloji","konu":"Doku Histolojisi ve Fizyolojisi","diff":3,"q":"Sürekli kapillerleri fenestralı kapillerlerden ayıran temel yapısal özellik hangisidir?","options":["Endotel hücreleri arasında belirgin pencerelerin bulunmaması","Bazal membranın tamamen olmaması","Eritrositlerin endotel sitoplazmasından geçmesi","Damar duvarında kıkırdak matriks bulunması","Endotel hücrelerinin miyelin kılıf oluşturması"],"correct":0,"exp":"Sürekli kapillerlerde endotel hücreleri sıkı bağlantılarla düzenlenir ve fenestra yoktur. Kas, sinir ve akciğerde tipiktir. Fenestralı kapillerlerde ise emilim ve filtrasyon için pencereler bulunur."},{"id":3589,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":4,"q":"22 yaşındaki erkek hasta 30 dakikadır süren yoğun egzersiz sonrası baldır ağrısı ve güçsüzlük yakınmasıyla geliyor. Kronik hastalığı yok, ilaç kullanmıyor. İskelet kasında kasılma sonrası gevşemeyi doğrudan sağlayan olay hangisidir?","options":["Kalsiyumun SERCA ile sarkoplazmik retikuluma geri alınması","Troponin C'nin aktine kalıcı bağlanması","Miyozin başının ATP olmadan aktinden ayrılması","Asetilkolinin sarkomer içinde depolanması","Tropomiyozinin miyozin başını hidrolize etmesi"],"correct":0,"exp":"Kas gevşemesi için sitozolik kalsiyum düşmelidir. SERCA pompası kalsiyumu sarkoplazmik retikuluma geri taşır; kalsiyum troponinden ayrılınca aktin-miyozin etkileşimi azalır."},{"id":3590,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":4,"q":"63 yaşındaki kadın hasta 3 aydır merdiven çıkarken uyluk kaslarında çabuk yorulma yakınmasıyla başvuruyor. Tip 2 diyabeti var, metformin kullanıyor. Tip I kas liflerinin dayanıklılığını en iyi açıklayan özellik hangisidir?","options":["Mitokondri ve miyoglobin içeriğinin yüksek olması","Glikolitik enzimlerin tamamen yokluğu","Sarkoplazmik retikulumun hiç bulunmaması","Nöromüsküler kavşakta asetilkolin salınmaması","Kalsiyum bağlayan troponinin olmaması"],"correct":0,"exp":"Tip I lifler yavaş kasılır, oksidatif metabolizmaya dayanır, mitokondri ve miyoglobin içerikleri yüksektir. Bu nedenle yorgunluğa dirençlidir."},{"id":3591,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":4,"q":"46 yaşındaki erkek hasta 2 gündür çarpıntı ve eforla nefes darlığı yakınmasıyla geliyor. Hipertansiyonu var, hidroklorotiyazid kullanıyor. Ventrikül kasında aksiyon potansiyeli platosunu sürdüren iyon hareketi için hangi seçenek doğrudur?","options":["L tipi kalsiyum kanallarından hücre içine kalsiyum girişi","Hızlı sodyum kanallarından sürekli sodyum çıkışı","Potasyumun hücre içine masif girişi","Klorür kanallarının geri dönüşümsüz kapanması","Sodyum-kalsiyum değiştiricinin tamamen durması"],"correct":0,"exp":"Kardiyak ventrikül aksiyon potansiyelinin plato fazında L tipi kalsiyum kanallarından kalsiyum girişi ile potasyum çıkışı dengelenir. Bu plato, uzun refrakter dönem ve tetani gelişmemesi için önemlidir."},{"id":3592,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":3,"q":"35 yaşındaki kadın hasta 1 gündür bulanık görme, ağız kuruluğu ve güçsüzlük yakınmasıyla geliyor. Kronik hastalığı yok, düzenli ilaç kullanmıyor; ev yapımı konserve tüketmiş. Nöromüsküler kavşakta kuvvet kaybını açıklayan olay hangisidir?","options":["Presinaptik asetilkolin salınımının azalması","Postsinaptik nikotinik reseptör sayısının artması","Kas lifinde miyoglobin sentezinin artması","Sarkomer Z çizgisinin tamamen kaybolması","Asetilkolinesterazın tam inhibisyonu"],"correct":0,"exp":"Botulinum toksini SNARE proteinlerini etkileyerek presinaptik asetilkolin salınımını azaltır. Sonuç gevşek paralizidir. Asetilkolinesteraz inhibisyonu ise kolinerjik fazlalık yapar."},{"id":3593,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":4,"q":"42 yaşındaki erkek hasta 6 aydır aralıklı hışıltı ve nefes darlığı yakınmasıyla geliyor. Astım öyküsü var, salbutamol inhaler kullanıyor. Bronş düz kasında kalsiyum artışı sonrası kasılmayı başlatan en kritik basamak hangisidir?","options":["Kalmodulin aracılığıyla miyozin hafif zincir kinazın aktivasyonu","Troponin C'nin tropomiyozini yer değiştirmesi","Sarkomer Z çizgilerinin birbirinden uzaklaşması","Ryanodin reseptörlerinin tamamen kapanması","Miyozin ATPaz aktivitesinin kalıcı kaybı"],"correct":0,"exp":"Düz kasta troponin yoktur. Kalsiyum kalmoduline bağlanır, miyozin hafif zincir kinazı aktive eder ve miyozin fosforilasyonu ile kasılma başlar. Mnemonik: Düz kasta 'Kal-Miyo' yani kalmodulin ve miyozin kinaz akla gelsin."},{"id":3594,"ders":"Fizyoloji","konu":"Genital Sistem HistoFizyolojisi","diff":4,"q":"29 yaşındaki kadın hasta 14 aydır gebe kalamama yakınmasıyla başvuruyor. Kronik hastalığı yok, düzenli ilaç kullanmıyor; siklusları 35-45 günde bir oluyor. Ovulasyon öncesi LH artışını doğrudan tetikleyen fizyolojik değişiklik hangisidir?","options":["Sürdürülen yüksek estradiol düzeyinin hipofize pozitif geri bildirim yapması","Progesteronun foliküler faz başında hızla yükselmesi","İnhibin B'nin FSH'yi artırması","Prolaktinin GnRH pulslarını hızlandırması","Kortizolün granüloza hücrelerinde aromatazı kapatması"],"correct":0,"exp":"Siklus ortasında yeterli süre yüksek kalan estradiol, klasik negatif geri bildirimin tersine pozitif geri bildirim oluşturur ve LH piki gelişir. LH piki ovulasyonu başlatır."},{"id":3595,"ders":"Fizyoloji","konu":"Genital Sistem HistoFizyolojisi","diff":4,"q":"34 yaşındaki erkek hasta 1 yıldır infertilite yakınmasıyla başvuruyor. Kronik hastalığı yok, ilaç kullanmıyor; semen analizinde sperm sayısı düşük. Sertoli hücrelerinden salgılanan ve FSH üzerine geri bildirim sağlayan madde hangisidir?","options":["İnhibin B","Testosteron","Dihidrotestosteron","Anti-Müllerian hormon","Oksitosin"],"correct":0,"exp":"Sertoli hücreleri spermatogenezi destekler ve inhibin B salgılayarak hipofizden FSH salınımını baskılar. Leydig hücreleri ise LH etkisiyle testosteron üretir."},{"id":3596,"ders":"Fizyoloji","konu":"Genital Sistem HistoFizyolojisi","diff":3,"q":"26 yaşındaki kadın hasta 6 haftadır adet gecikmesi ve sabah bulantısı yakınmasıyla geliyor. Kronik hastalığı yok, ilaç kullanmıyor. Erken gebelikte korpus luteumun progesteron üretimini sürdürmesini sağlayan hormon hangisidir?","options":["İnsan koryonik gonadotropini","Follikül uyarıcı hormon","Prolaktin","Oksitosin","Melatonin"],"correct":0,"exp":"Erken gebelikte trofoblasttan salgılanan hCG, LH benzeri etkiyle korpus luteumu destekler. Progesteron devamı endometriumun korunması için gereklidir."},{"id":3597,"ders":"Fizyoloji","konu":"Genital Sistem HistoFizyolojisi","diff":3,"q":"25 yaşındaki kadın hasta doğumdan 5 gün sonra bebeğini emzirirken süt miktarının az olması yakınmasıyla başvuruyor. Kronik hastalığı yok, ilaç kullanmıyor. Meme alveol hücrelerinden süt sentezini artıran, fakat süt ejeksiyonundan sorumlu olmayan hormon hangisidir?","options":["Prolaktin","Oksitosin","Vazopressin","Adrenalin","İnhibin A"],"correct":0,"exp":"Prolaktin süt üretimini artırır; oksitosin ise miyoeptelyal hücreleri kasarak süt salınımını sağlar. Mnemonik: Prolaktin üretir, oksitosin oynatır."},{"id":3598,"ders":"Fizyoloji","konu":"Genel Embriyoloji","diff":4,"q":"30 yaşındaki kadın hasta gebeliğin 8. haftasında ultrason kontrolüne geliyor. Kronik hastalığı yok, folik asit kullanıyor; şikayeti yok. Bu haftada organ taslaklarının büyük kısmının gelişmiş olmasını açıklayan embriyolojik dönem için hangi ifade doğrudur?","options":["Organogenez esas olarak 3-8. haftalar arasında gerçekleşir","İmplantasyon fertilizasyondan hemen sonraki ilk saatte tamamlanır","Nörülasyon yalnızca üçüncü trimesterde başlar","Gastrulasyon doğumdan sonra sürer","Somitler sadece plasenta içinde oluşur"],"correct":0,"exp":"Embriyonik dönem 3-8. haftaları kapsar ve organogenez açısından en kritik aralıktır. Teratojenlere duyarlılık bu dönemde yüksektir."},{"id":3599,"ders":"Fizyoloji","konu":"Genel Embriyoloji","diff":4,"q":"27 yaşındaki kadın hasta gebeliğin 5. haftasında sırt ağrısı ve folik asit kullanmama öyküsüyle başvuruyor. Kronik hastalığı yok, düzenli ilaç kullanmıyor. Nöral tüp kapanma kusuru riskini azaltmada folatın temel fizyolojik rolü hangisidir?","options":["Tek karbon metabolizması üzerinden DNA sentezi ve metilasyonunu desteklemesi","Miyozin hafif zincirini doğrudan fosforile etmesi","Fetal hemoglobini erişkin hemoglobine çevirmesi","Amniyon sıvısında surfaktanı yıkması","Trofoblast invazyonunu tamamen durdurması"],"correct":0,"exp":"Folat tek karbon metabolizmasında DNA sentezi ve metilasyon reaksiyonları için gereklidir. Hızla bölünen embriyonik dokular folat eksikliğine duyarlıdır."},{"id":3600,"ders":"Fizyoloji","konu":"Genel Embriyoloji","diff":4,"q":"32 yaşındaki kadın hasta gebeliğin 7. haftasında hafif vajinal lekelenme yakınmasıyla geliyor. Kronik hastalığı yok, levotiroksin kullanıyor. Plasentada anne ve fetal kanın normalde doğrudan karışmamasını sağlayan yapı için hangi seçenek en doğrudur?","options":["Koryon villuslarında trofoblast ve fetal kapiller bariyerin bulunması","Fetal eritrositlerin anne arterlerine serbest geçmesi","Amniyon boşluğunun maternal venöz sinüs olması","Yolk kesesinin tüm gebelik boyunca gaz değişimini üstlenmesi","Desiduanın tamamen avasküler kalması"],"correct":0,"exp":"Plasental değişim koryon villusları üzerinden olur; maternal kan intervillöz aralıktadır, fetal kan ise villus içi kapillerlerdedir. Normalde iki dolaşım doğrudan karışmaz."},{"id":3601,"ders":"Fizyoloji","konu":"Genel Embriyoloji","diff":3,"q":"28 yaşındaki kadın hasta gebeliğin 4. haftasında rutin kontrole geliyor. Kronik hastalığı yok, folik asit kullanıyor; şikayeti yok. Bu dönemde gastrulasyonun embriyolojik açıdan en temel sonucu hangisidir?","options":["Ektoderm, mezoderm ve endoderm germ yapraklarının oluşması","Spermatogonyumların pubertede çoğalması","Fetal akciğerde surfaktan salgısının başlaması","Korpus luteumun gerilemesi","Amniyon sıvısının tamamen kaybolması"],"correct":0,"exp":"Gastrulasyon üç primer germ yaprağını oluşturur. Sonraki organ ve doku farklılaşmasının haritası bu katmanlardan gelişir."},{"id":3602,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":4,"q":"72 yaşındaki erkek hasta 2 aydır eforla nefes darlığı ve halsizlik yakınmasıyla geliyor. Kronik böbrek hastalığı var, kalsiyum asetat kullanıyor. Normositer aneminin temel nedeni olarak hangi mekanizma beklenir?","options":["Renal eritropoietin üretiminin azalması","İntrensek faktör salgısının aşırı artması","Trombopoietinin tamamen baskılanması","Demirin makrofajlardan sınırsız salınması","Hemoglobinin oksijen afinitesinin sıfırlanması"],"correct":0,"exp":"Eritropoietin esas olarak böbrekte peritübüler interstisyel hücrelerden salınır. Kronik böbrek hastalığında EPO azalır ve normositer normokrom anemi gelişebilir."},{"id":3603,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":4,"q":"25 yaşındaki kadın hasta 4 haftadır halsizlik, çarpıntı ve tırnak kırılması yakınmasıyla geliyor. Kronik hastalığı yok, ilaç kullanmıyor; menstrüasyonları yoğun. Demir eksikliğinde eritropoezi sınırlayan en temel basamak hangisidir?","options":["Hem sentezi için yeterli demirin bulunmaması","Eritropoietin reseptörünün her zaman aşırı uyarılması","Globin zincirlerinin mitokondride parçalanması","B12'nin demire dönüşememesi","Trombositlerin eritrosite farklılaşması"],"correct":0,"exp":"Demir hem sentezi için zorunludur. Demir eksikliği hemoglobin sentezini azaltır, mikrositer hipokrom eritrositler oluşur."},{"id":3604,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":4,"q":"59 yaşındaki erkek hasta 3 gündür ateş ve öksürük yakınmasıyla geliyor. KOAH öyküsü var, inhaler bronkodilatör kullanıyor. Akut inflamasyonda karaciğerden hepsidin artışı sonrası serum demirinin düşmesini hangi olay açıklar?","options":["Ferroportinin yıkılmasıyla demirin makrofaj ve enterositlerden çıkışının azalması","Transferrinin oksijeni doğrudan bağlaması","Eritropoietinin trombositlere dönüşmesi","Haptoglobinin böbrekte glukoz geri emilimini artırması","Albüminin hem sentezini hızlandırması"],"correct":0,"exp":"Hepsidin ferroportini internalize edip yıktırır. Böylece demirin barsaktan emilimi ve makrofajlardan kana salınımı azalır; inflamasyon anemisinde işlevsel demir kısıtlanması gelişir."},{"id":3605,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":4,"q":"41 yaşındaki kadın hasta 1 aydır uyuşma ve dengesizlik yakınmasıyla başvuruyor. Hashimoto tiroiditi var, levotiroksin kullanıyor. B12 eksikliğinde megaloblastik değişimin temel nedeni hangisidir?","options":["DNA sentezinin bozulması nedeniyle nükleer olgunlaşmanın gecikmesi","Hemoglobinin oksijene bağlanamaması","Trombositlerin nötrofile dönüşmesi","Eritrosit zarında kolesterolün tamamen kaybolması","2,3-BPG sentezinin artarak DNA'yı yıkması"],"correct":0,"exp":"B12 ve folat DNA sentezi için gereklidir. Eksiklikte çekirdek olgunlaşması sitoplazmaya göre geri kalır; makroovalositler ve hipersegmente nötrofiller görülebilir."},{"id":3606,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":3,"q":"66 yaşındaki erkek hasta 1 yıldır eforla nefes darlığı yakınmasıyla geliyor. KOAH öyküsü var, tiotropium kullanıyor. Kronik hipokside hemoglobinin oksijen afinitesini azaltarak dokulara oksijen bırakılmasını kolaylaştıran eritrosit içi metabolit hangisidir?","options":["2,3-bisfosfogliserat","Ferritin","Haptoglobin","Seruloplazmin","Miyeloperoksidaz"],"correct":0,"exp":"2,3-BPG deoksihemoglobine bağlanır ve oksijen afinitesini azaltır. Böylece eğri sağa kayar, dokulara oksijen bırakılması kolaylaşır."},{"id":3607,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":4,"q":"Primer hemostazda trombositlerin subendotelyal kollajene tutunmasını sağlayan ana köprü molekül hangisidir?","options":["von Willebrand faktör","Antitrombin","Protein C","Plazminojen","Fibrinojen yıkım ürünü"],"correct":0,"exp":"vWF subendotelyal kollajen ile trombosit GPIb reseptörü arasında köprü kurar. Primer hemostazın erken yapışma basamağı için kritiktir."},{"id":3608,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":4,"q":"44 yaşındaki erkek hasta 6 aydır epigastrik yanma ve gece ağrısı yakınmasıyla geliyor. Kronik hastalığı yok, aralıklı NSAİİ kullanıyor. Parietal hücreden asit salgısını doğrudan artıran ortak son basamak hangisidir?","options":["Apikal H-K ATPaz aktivasyonunun artması","Pepsinojenin duodenumda bikarbonata dönüşmesi","Enterokinazın gastrini parçalaması","İntrensek faktörün klorüre bağlanması","Mükus hücrelerinden tripsin salınması"],"correct":0,"exp":"Parietal hücrede asit salgısının son basamağı apikal H-K ATPazdır. Asetilkolin, histamin ve gastrin farklı reseptörlerden bu pompaya giden yolu güçlendirir."},{"id":3609,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":4,"q":"52 yaşındaki kadın hasta 3 aydır yağlı dışkılama ve kilo kaybı yakınmasıyla geliyor. Tip 2 diyabeti var, metformin kullanıyor. Pankreatik enzim sekresyonunu protein ve yağ içeren öğünden sonra en güçlü artıran hormon hangisidir?","options":["Kolesistokinin","Sekretin","Gastrik inhibitör peptid","Motilin","Somatostatin"],"correct":0,"exp":"CCK duodenum ve jejunum I hücrelerinden yağ asitleri ve aminoasitlere yanıt olarak salınır; pankreatik enzim sekresyonunu ve safra kesesi kasılmasını artırır. Sekretin daha çok bikarbonat salgısını artırır."},{"id":3610,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":4,"q":"61 yaşındaki erkek hasta 2 haftadır sulu ishal ve halsizlik yakınmasıyla geliyor. Kronik hastalığı yok, düzenli ilaç kullanmıyor. Duodenum lümenine asit içeriği geldiğinde pankreatik bikarbonat salgısını artıran hormon hangisidir?","options":["Sekretin","Gastrin","Kolesistokinin","Motilin","Ghrelin"],"correct":0,"exp":"Sekretin duodenal S hücrelerinden asit yanıtıyla salınır ve pankreas kanal hücrelerinden bikarbonat salgısını artırır. Amaç duodenal pH'yi yükseltmek ve enzimler için uygun ortam oluşturmaktır."},{"id":3611,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":4,"q":"33 yaşındaki kadın hasta 10 gündür kabızlık ve karında şişkinlik yakınmasıyla başvuruyor. Kronik hastalığı yok, demir preparatı kullanmaya başlamış. Kolon motilitesinde kitle hareketlerini başlatan ana refleks uyaranı hangisidir?","options":["Mideye gıda girmesiyle gelişen gastro-kolik refleks","İleumda B12 emiliminin durması","Safra tuzlarının midede parçalanması","Pankreas kanalında pH'nin düşmesi","Kolon epitelinde pepsin salgılanması"],"correct":0,"exp":"Yemekten sonra mide distansiyonu ve otonom-enterik yollar kolon kitle hareketlerini artırır. Bu gastro-kolik refleks defekasyon ihtiyacını tetikleyebilir."},{"id":3612,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":3,"q":"İnce bağırsakta safra tuzlarının enterohepatik dolaşıma geri kazandırıldığı başlıca bölge hangisidir?","options":["Terminal ileum","Mide fundusu","Özofagus alt ucu","Transvers kolon","Duodenum başlangıcı"],"correct":0,"exp":"Safra tuzları terminal ileumdan aktif olarak geri emilir ve portal dolaşımla karaciğere döner. Terminal ileum hastalıklarında safra tuzu kaybı yağ emilimini bozar."},{"id":3613,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":4,"q":"Mide boşken yaklaşık 90 dakikalık aralıklarla ortaya çıkan interdigestif motor aktiviteyi başlatmada öne çıkan hormon hangisidir?","options":["Motilin","Leptin","Sekretin","Kolesistokinin","İnsülin"],"correct":0,"exp":"Motilin açlıkta migratuvar motor kompleksi uyarır. Bu kompleks mide ve ince bağırsakta artıkları ileri taşır. Kısa not: Motilin, mideyi 'motor' gibi çalıştırır."},{"id":3614,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"68 yaşındaki erkek hasta 2 saattir süren baş dönmesi ve soğuk terleme yakınmasıyla geliyor. Hipertansiyonu var, beta bloker kullanıyor. Ani ayağa kalkınca kan basıncını kısa sürede korumaya çalışan refleks için hangi yanıt beklenir?","options":["Baroreseptör ateşlemesinin azalmasıyla sempatik tonusun artması","Karotis cisimciğinde oksijen algısının tamamen durması","Vagal tonusun artmasıyla kalp hızının düşmesi","Aldosteronun saniyeler içinde maksimuma çıkması","Natriüretik peptidin arteriolleri kasması"],"correct":0,"exp":"Ortostatik durumda arter basıncı azalır, baroreseptör ateşlemesi düşer. Medüller yanıt sempatik aktiviteyi artırır, kalp hızı ve damar tonusu yükselir."},{"id":3615,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"57 yaşındaki kadın hasta 3 aydır eforla nefes darlığı yakınmasıyla geliyor. Hipertansiyonu var, losartan kullanıyor. Diyastolik disfonksiyonda ventrikül doluş basıncı artarken atım hacminin korunmaya çalışılmasını en iyi açıklayan ilişki hangisidir?","options":["Frank-Starling mekanizmasıyla artan diyastol sonu hacmin kasılma kuvvetini artırması","Afterload azalınca venöz dönüşün tamamen kesilmesi","Vagus aktivitesiyle miyokard kontraktilitesinin doğrudan artması","Koroner akımın sadece sistolde gerçekleşmesi","Kapiller onkotik basıncın ventrikül basıncını belirlemesi"],"correct":0,"exp":"Frank-Starling mekanizması, miyokard lif uzunluğunun artmasıyla kasılma kuvvetinin artmasını açıklar. Ancak diyastolik disfonksiyonda doluş basıncı yükselir ve kompansasyon sınırlanır."},{"id":3616,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"49 yaşındaki erkek hasta 1 saattir göğüs ağrısı yakınmasıyla acile geliyor. Sigara kullanıyor, kronik hastalığı yok. Koroner perfüzyonun sol ventrikülde en çok diyastolde gerçekleşmesini hangi mekanizma açıklar?","options":["Sistolde intramiyokardiyal basıncın koroner damarları sıkıştırması","Diyastolde aort kapağının tam açık kalması","Koroner sinüsün sistolde arterleşmesi","Endokardın oksijen ihtiyacının diyastolde sıfırlanması","Miyokardın kapiller içermemesi"],"correct":0,"exp":"Sol ventrikül sistolünde yüksek duvar içi basınç koroner damarları sıkıştırır. Bu nedenle sol koroner akımın büyük kısmı diyastolde olur."},{"id":3617,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"26 yaşındaki kadın hasta 2 gündür ateş ve ishal sonrası çarpıntı yakınmasıyla geliyor. Kronik hastalığı yok, ilaç kullanmıyor. Hipovolemide renin salınımını artıran böbrek içi algılayıcı değişiklik hangisidir?","options":["Jukstaglomerüler aparatta afferent arteriyol basıncının azalması","Distal tübülde sodyum klorürün artması","ANP salınımının belirgin yükselmesi","Sempatik beta-1 uyarının azalması","Eferent arteriyol çapının tamamen kaybolması"],"correct":0,"exp":"Renin salınımı afferent arteriyol basıncının azalması, makula densaya NaCl gelişinin azalması ve beta-1 sempatik uyarıyla artar. Hipovolemide bu yollar RAAS'ı aktive eder."},{"id":3618,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":3,"q":"Total periferik direnci en fazla belirleyen damar segmenti hangisidir?","options":["Arteriyoller","Büyük venler","Kapillerler","Lenfatik kanallar","Pulmoner venler"],"correct":0,"exp":"Arteriyoller küçük yarıçapları ve düz kas tonusları nedeniyle sistemik vasküler direncin ana belirleyicisidir. Poiseuille yasasında direnç yarıçapın dördüncü kuvvetiyle ters orantılıdır."},{"id":3619,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"Einthoven üçgeninde derivasyon II için elektriksel kayıt hangi iki elektrot arasındaki potansiyel farkını temsil eder?","options":["Sağ kol ile sol bacak arasındaki fark","Sol kol ile sağ kol arasındaki fark","Sol kol ile sol bacak arasındaki fark","Göğüs elektrodu ile sağ bacak arasındaki fark","Sağ bacak ile sol bacak arasındaki fark"],"correct":0,"exp":"Derivasyon II sağ kol negatif, sol bacak pozitif olacak şekilde kayıt yapar. P dalgası ve QRS kompleksinin çoğu kişide belirgin görünmesinin nedeni kalbin ana elektrik aksına yakın olmasıdır."},{"id":3620,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"Kapiller filtrasyonu artıran Starling kuvveti hangisidir?","options":["Kapiller hidrostatik basınç artışı","Plazma onkotik basınç artışı","Lenfatik drenaj artışı","İnterstisyel hidrostatik basınç artışı","Kapiller geçirgenlikte kalıcı azalma"],"correct":0,"exp":"Kapiller hidrostatik basınç sıvıyı damar dışına iter ve filtrasyonu artırır. Plazma onkotik basıncı ise sıvıyı damar içinde tutma yönünde etki eder."},{"id":3621,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"Sinoatriyal düğüm hücresinde faz 4 spontan depolarizasyonunu başlatmada önemli olan akım hangisidir?","options":["Funny sodyum akımı","Hızlı sodyum kanal akımı","Klorürün hücre dışına masif çıkışı","Miyozin ATPaz akımı","Hemoglobinin oksijen bağlama akımı"],"correct":0,"exp":"SA düğümde stabil istirahat potansiyeli yoktur. Faz 4 spontan depolarizasyonda funny akımı, T tipi kalsiyum akımı ve azalan potasyum çıkışı rol oynar."},{"id":3622,"ders":"Fizyoloji","konu":"Endokrin ve Genital Sistem HistoFizyolojisi","diff":4,"q":"38 yaşındaki kadın hasta 2 aydır çarpıntı, kilo kaybı ve sıcak intoleransı yakınmasıyla geliyor. Kronik hastalığı yok, ilaç kullanmıyor. Tiroid hormonlarının bazal metabolizma hızını artırmasında hangi hücresel etki öne çıkar?","options":["Na-K ATPaz ve mitokondriyal oksidatif süreçlerin artması","İnsülin reseptörlerinin tamamen kaybolması","Parathormonun tiroid follikülünde sentezlenmesi","Glukagonun TSH salınımını durdurması","Kalsitoninin tüm dokularda ATP üretimini kapatması"],"correct":0,"exp":"Tiroid hormonları birçok dokuda Na-K ATPaz aktivitesini, mitokondriyal enzimleri ve oksijen tüketimini artırır. Bu nedenle ısı üretimi ve bazal metabolizma hızı yükselir."},{"id":3623,"ders":"Fizyoloji","konu":"Endokrin ve Genital Sistem HistoFizyolojisi","diff":4,"q":"55 yaşındaki erkek hasta 1 gündür poliüri, susuzluk ve halsizlik yakınmasıyla geliyor. Tip 2 diyabeti var, insülin glarjin kullanıyor. İnsülinin iskelet kası ve yağ dokusunda glukoz alımını artıran temel etkisi hangisidir?","options":["GLUT4 taşıyıcılarının hücre zarına translokasyonunu artırması","GLUT2 taşıyıcılarını böbrek proksimal tübülde yıkması","SGLT1'i pankreas beta hücresinde kapatması","Heksokinazı tüm dokularda kalıcı inhibe etmesi","Glukagon reseptörünü doğrudan aktive etmesi"],"correct":0,"exp":"İnsülin kas ve yağ dokusunda GLUT4 veziküllerinin membrana taşınmasını sağlar. Böylece hücre içine glukoz girişi artar."},{"id":3624,"ders":"Fizyoloji","konu":"Endokrin ve Genital Sistem HistoFizyolojisi","diff":4,"q":"47 yaşındaki kadın hasta 3 haftadır kas krampları ve ağız çevresinde uyuşma yakınmasıyla geliyor. Total tiroidektomi öyküsü var, levotiroksin kullanıyor. Hipokalsemiye karşı normalde en hızlı artması beklenen hormonun böbrekteki etkisi hangisidir?","options":["Distal tübülde kalsiyum geri emilimini artırması","Proksimal tübülde fosfat geri emilimini artırması","Kolekting kanalda su geçirgenliğini azaltması","Henle kulpunda sodyum emilimini tamamen durdurması","Böbrekte eritropoietin üretimini baskılaması"],"correct":0,"exp":"Parathormon hipokalsemiye yanıt olarak artar; distal tübülde kalsiyum geri emilimini artırır, proksimal tübülde fosfat geri emilimini azaltır ve 1-alfa hidroksilazı uyarır."},{"id":3625,"ders":"Fizyoloji","konu":"Endokrin ve Genital Sistem HistoFizyolojisi","diff":4,"q":"33 yaşındaki kadın hasta 5 aydır adet düzensizliği ve memeden süt gelmesi yakınmasıyla başvuruyor. Kronik hastalığı yok, düzenli ilaç kullanmıyor. Prolaktin yüksekliğinin ovulasyonu bozmasını en iyi açıklayan mekanizma hangisidir?","options":["GnRH pulslarının baskılanması","LH reseptörlerinin adrenal kortekse taşınması","Estradiolün böbrekten atılımının artması","Oksitosinin tiroid bezini uyarması","İnhibin B'nin prolaktine dönüşmesi"],"correct":0,"exp":"Hiperprolaktinemi hipotalamik GnRH pulslarını baskılar; LH ve FSH salınımı bozulur. Bu nedenle anovulasyon, amenore ve infertilite gelişebilir."},{"id":3626,"ders":"Fizyoloji","konu":"Endokrin ve Genital Sistem HistoFizyolojisi","diff":3,"q":"Steroid hormonların hücresel etki mekanizmasını peptid hormonlardan ayıran temel özellik hangisidir?","options":["Hücre içi reseptörlere bağlanıp gen transkripsiyonunu düzenlemeleri","Daima membran reseptörü üzerinden cAMP üretmeleri","Kanda yalnızca serbest halde taşınmaları","Ribozomlarda doğrudan sentezlenmeleri","Etkilerinin her zaman saniyeler içinde kaybolması"],"correct":0,"exp":"Steroid hormonlar lipofilik oldukları için hücre zarını geçebilir ve sitozolik ya da nükleer reseptörlerle gen transkripsiyonunu değiştirir. Peptid hormonlar çoğunlukla membran reseptörleriyle çalışır."},{"id":3627,"ders":"Fizyoloji","konu":"Endokrin ve Genital Sistem HistoFizyolojisi","diff":4,"q":"Kortizolün stres yanıtında kan glukozunu artırmasına katkı veren temel metabolik etkisi hangisidir?","options":["Karaciğerde glukoneogenezi artırması","İskelet kasında GLUT4 translokasyonunu doğrudan artırması","Pankreas beta hücresinden insülin salınımını sürekli artırması","Böbrekte glukoz filtrasyonunu tamamen durdurması","Yağ dokusunda lipolizi sıfırlaması"],"correct":0,"exp":"Kortizol karaciğerde glukoneogenezi artırır, periferik glukoz kullanımını azaltır ve protein katabolizmasını destekler. Stres hiperglisemisine bu yüzden katkı verir."},{"id":3628,"ders":"Fizyoloji","konu":"Endokrin ve Genital Sistem HistoFizyolojisi","diff":4,"q":"Aldosteronun esas etki gösterdiği nefron segmenti ve taşıma sonucu için hangi seçenek doğrudur?","options":["Kortikal toplayıcı kanalda sodyum geri emilimini ve potasyum sekresyonunu artırır","Proksimal tübülde glukoz geri emilimini tamamen durdurur","Henle inen kolunda su geçirgenliğini azaltır","Glomerülde protein filtrasyonunu artırır","Distal tübülde bikarbonat sekresyonunu sıfırlar"],"correct":0,"exp":"Aldosteron kortikal toplayıcı kanal principal hücrelerinde ENaC ve Na-K ATPaz etkisini artırır. Sodyum tutulur, potasyum sekresyonu artar."},{"id":3629,"ders":"Fizyoloji","konu":"Endokrin ve Genital Sistem HistoFizyolojisi","diff":3,"q":"Büyüme hormonunun çocukluk çağındaki lineer büyümeyi büyük ölçüde hangi mediyatör üzerinden artırdığı hangisidir?","options":["IGF-1","İnhibin A","Kalsitonin","Atrial natriüretik peptid","Sekretin"],"correct":0,"exp":"Büyüme hormonu karaciğer ve perifer dokularda IGF-1 üretimini artırır. IGF-1 epifiz plağında kondrosit proliferasyonu ve lineer büyümeye aracılık eder."},{"id":3630,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"69 yaşındaki erkek hasta 6 aydır giderek artan efor dispnesi ve kuru öksürük yakınmasıyla geliyor. İdiyopatik pulmoner fibrozis tanısı var, antifibrotik tedavi kullanıyor. Bu hastada spirometride hangi patern beklenir?","options":["FVC azalır, FEV1/FVC oranı normal ya da artmış bulunur","FEV1/FVC oranı belirgin azalır, total akciğer kapasitesi artar","Rezidüel volüm dramatik artar, FVC artar","Difüzyon kapasitesi her zaman artar","Pik ekspiratuvar akım tamamen normal kalır"],"correct":0,"exp":"Restriktif hastalıkta akciğer kompliansı azalır, FVC düşer. FEV1 de azalabilir fakat oran genellikle korunur veya artar. Fibroziste DLCO çoğu zaman azalır."},{"id":3631,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"58 yaşındaki erkek hasta 4 yıldır öksürük ve son 1 haftadır artan nefes darlığı yakınmasıyla geliyor. KOAH öyküsü var, tiotropium kullanıyor. Amfizemde elastik geri çekilmenin azalması hangi değişikliğe yol açar?","options":["Ekspirasyonda hava yolu kollapsı ve rezidüel volüm artışı","Total akciğer kapasitesinin zorunlu olarak azalması","Difüzyon mesafesinin kısalıp DLCO'nun artması","Surfaktan üretiminin hızla çoğalması","Alveol ventilasyonunun her bölgede eşitlenmesi"],"correct":0,"exp":"Amfizemde alveol duvarları ve elastik destek azalır. Küçük hava yolları ekspirasyonda kollabe olur, hava hapsi ve rezidüel volüm artışı gelişir."},{"id":3632,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"24 yaşındaki erkek hasta 2 saattir panik hissi, nefes alamama ve ellerde karıncalanma yakınmasıyla geliyor. Kronik hastalığı yok, ilaç kullanmıyor. Hiperventilasyon sonrası iyonize kalsiyumun azalmasını en iyi açıklayan değişiklik hangisidir?","options":["Alkalozda albümine kalsiyum bağlanmasının artması","Parathormonun saniyeler içinde tamamen kaybolması","Böbrekten kalsiyum filtrasyonunun durması","Hemoglobinin oksijene bağlanmasının imkansızlaşması","Surfaktanın alveolde yıkılması"],"correct":0,"exp":"Respiratuvar alkalozda albüminin negatif yükleri artar ve kalsiyum bağlanması yükselir. İyonize kalsiyum azalınca parestezi ve tetani bulguları gelişebilir."},{"id":3633,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"46 yaşındaki kadın hasta 3 gündür ateş, balgam ve nefes darlığı yakınmasıyla geliyor. Astımı var, inhaler steroid kullanıyor. Pnömoni olan akciğer bölgesinde ventilasyon azalırken perfüzyon sürerse hangi gaz değişim bozukluğu gelişir?","options":["Düşük ventilasyon-perfüzyon oranı ve hipoksemi","Ölü boşluk ventilasyonunun tek başına artması","Alveoler oksijenin kesin olarak yükselmesi","Arteriyel karbondioksitin daima sıfırlanması","Oksijen difüzyonunun perfüzyondan bağımsız hale gelmesi"],"correct":0,"exp":"Pnömonide konsolide alanda ventilasyon azalır fakat perfüzyon devam edebilir. Bu düşük V/Q oranı şant benzeri etki yaparak hipoksemiye yol açar."},{"id":3634,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"29 yaşındaki kadın hasta 12 saattir süren ani nefes darlığı ve plöritik göğüs ağrısı yakınmasıyla geliyor. Oral kontraseptif kullanıyor, kronik hastalığı yok. Pulmoner embolide etkilenen bölgede temel fizyolojik değişiklik hangisidir?","options":["Ventilasyonun korunup perfüzyonun azalmasıyla alveoler ölü boşluk artışı","Perfüzyonun artıp ventilasyonun sıfırlanması","Tüm akciğerde surfaktan sentezinin durması","Alveoler kapiller membranın kalınlığının azalması","Solunum merkezinin karbondioksite duyarsızlaşması"],"correct":0,"exp":"Pulmoner embolide bazı alveoller havalanır ancak perfüze olmaz. Bu fizyolojik ölü boşluğu artırır ve V/Q oranını yükseltir."},{"id":3635,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":3,"q":"Oksijen-hemoglobin ayrışma eğrisini sağa kaydıran değişiklik hangisidir?","options":["Artmış 2,3-BPG düzeyi","Azalmış karbondioksit düzeyi","Azalmış sıcaklık","Artmış pH","Fetal hemoglobin artışı"],"correct":0,"exp":"2,3-BPG artışı hemoglobinin oksijen afinitesini azaltır ve eğriyi sağa kaydırır. Böylece dokulara oksijen bırakılması kolaylaşır. Sağ kayma için 'CADET, face Right': CO2, Acid, 2,3-DPG, Exercise, Temperature."},{"id":3636,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"Surfaktanın alveoldeki en temel fizyolojik etkisi hangisidir?","options":["Yüzey gerilimini azaltarak küçük alveollerin kollabe olmasını önlemek","Alveoler kapiller membranı oksijene geçirimsiz yapmak","Bronş düz kasını sürekli kasılı tutmak","Hemoglobinin oksijen afinitesini sıfırlamak","Karbon dioksitin plazmada taşınmasını engellemek"],"correct":0,"exp":"Surfaktan yüzey gerilimini azaltır, özellikle küçük alveollerin kollapsını önler ve akciğer kompliansını artırır. Laplace yasası bu mantığın temelidir."},{"id":3637,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"Yüksek irtifaya çıkan sağlıklı bir kişide ilk saatlerde arteriyel oksijen azalmasına verilen en erken ventilatuvar yanıt hangisidir?","options":["Periferik kemoreseptör uyarısıyla hiperventilasyon","Santral kemoreseptörlerin oksijeni doğrudan algılaması","Surfaktan salgısının aniden kesilmesi","Hemoglobinin tamamen methemoglobine dönüşmesi","Pulmoner venlerin sistemik arter haline gelmesi"],"correct":0,"exp":"Hipoksemi karotis ve aort cisimciklerindeki periferik kemoreseptörleri uyarır. İlk yanıt hiperventilasyondur; bu da respiratuvar alkaloza yol açabilir."},{"id":3638,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"71 yaşındaki erkek hasta 90 dakikadır süren sağ kol güçsüzlüğü ve konuşma bozukluğu yakınmasıyla getiriliyor. Hipertansiyon ve atriyal fibrilasyonu var, apiksabanı düzensiz kullanıyor. Sol orta serebral arter kortikal alanında beklenen nörolojik bulgu hangisidir?","options":["Sağ yüz-kol baskın güçsüzlük ve afazi","Sol bacak baskın güçsüzlük ve anosmi","İki taraflı pitozis ve pupilla genişlemesi","Sağ kulakta iletim tipi işitme kaybı","Saf bilateral alt motor nöron bulgusu"],"correct":0,"exp":"Dominant hemisfer MCA alanı yüz ve üst ekstremite motor korteksi ile Broca/Wernicke dil alanlarını etkileyebilir. Bu nedenle karşı yüz-kol güçsüzlüğü ve afazi beklenir."},{"id":3639,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"34 yaşındaki kadın hasta 3 gündür sağ gözde ağrılı görme azalması yakınmasıyla geliyor. Multipl skleroz öyküsü var, interferon beta kullanıyor. Miyelin kaybının aksiyon potansiyeli iletimini bozmasının temel nedeni hangisidir?","options":["Ranvier düğümleri arasında saltatorik iletimin aksaması","Akson çapının her zaman artması","Sodyum kanallarının yalnızca hücre gövdesinde bulunması","Sinaptik veziküllerin miyelin içinde depolanması","Kalsiyumun nükleustan tamamen uzaklaşması"],"correct":0,"exp":"Miyelin internodlarda akımı izole eder ve iletimin Ranvier düğümleri arasında sıçramalı olmasını sağlar. Demiyelinizasyon iletim hızını düşürür ve iletim bloğu oluşturabilir."},{"id":3640,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"42 yaşındaki erkek hasta 5 gündür yükselen tarzda bacak güçsüzlüğü ve uyuşma yakınmasıyla geliyor. Kronik hastalığı yok, düzenli ilaç kullanmıyor; 2 hafta önce ishal geçirmiş. Derin tendon reflekslerinin azalmasını hangi fizyolojik bozukluk açıklar?","options":["Periferik sinir iletiminde demiyelinizasyona bağlı yavaşlama","Kortikospinal traktusta üst motor nöron hiperaktivitesi","Bazal ganglion dopamin sentezinin artması","Serebellar Purkinje hücrelerinin aşırı uyarılması","Görme korteksinde lateral inhibisyonun artması"],"correct":0,"exp":"Guillain-Barré sendromunda periferik sinir ve köklerde demiyelinizasyon olur. Refleks arkı iletimi bozulduğu için arefleksi veya hiporefleksi gelişir."},{"id":3641,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"60 yaşındaki erkek hasta 1 yıldır istirahat tremoru ve hareketlerde yavaşlama yakınmasıyla geliyor. Hipertansiyonu var, ramipril kullanıyor. Bu tabloda bazal ganglion devrelerinde hangi değişiklik hareketi azaltır?","options":["Substantia nigra dopaminerjik uyarısının azalmasıyla direkt yol aktivitesinin düşmesi","Serebellar vermisin vestibüler çekirdeği baskılaması","Motor kortekste GABA'nın tamamen kaybolması","Dorsal kolon liflerinin ağrı iletimini artırması","Hipokampusta asetilkolinin kas kasılmasını başlatması"],"correct":0,"exp":"Dopamin direkt yolu D1 üzerinden kolaylaştırır, indirekt yolu D2 üzerinden baskılar. Nigrostriatal dopamin azalınca talamokortikal aktivasyon düşer ve bradikinezi gelişir."},{"id":3642,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"19 yaşındaki erkek hasta 20 dakikadır süren jeneralize tonik-klonik nöbet sonrası değerlendiriliyor. Epilepsi öyküsü var, levetirasetam kullanıyor. İnhibitör sinaptik iletimde postsinaptik nöronu hiperpolarize eden temel iyon hareketi hangisidir?","options":["GABA-A reseptörü üzerinden klorür girişinin artması","NMDA reseptörü üzerinden sodyum çıkışının artması","AMPA reseptörü üzerinden potasyum girişinin artması","Glisin reseptörü üzerinden kalsiyum çıkışının artması","Dopamin reseptörü üzerinden klorürün pompalanması"],"correct":0,"exp":"GABA-A ligand kapılı klorür kanalıdır. Klorür iletkenliği artınca membran potansiyeli genellikle inhibisyon yönünde stabilize olur veya hiperpolarize olur."},{"id":3643,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"51 yaşındaki kadın hasta 3 aydır gece artan yanıcı ayak ağrısı yakınmasıyla geliyor. Diyabeti var, metformin kullanıyor. İnce miyelinsiz C liflerinin ilettiği duyusal modalite hangisidir?","options":["Yavaş ağrı ve sıcaklık","Propriyosepsiyon","Vibrasyon","Hızlı motor komut","Keskin diskriminatif dokunma"],"correct":0,"exp":"C lifleri miyelinsiz, yavaş ileten liflerdir; yavaş ağrı, sıcaklık ve otonomik bazı fonksiyonlarda rol alır. A-delta lifleri daha hızlı keskin ağrı taşır."},{"id":3644,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"Dorsal kolon-medial lemniskus sistemi hangi duyuyu en belirgin taşır?","options":["Vibrasyon ve bilinçli propriosepsiyon","Kaba ağrı ve sıcaklık","Koku duyusu","Tatlı tat duyusu","Otonom parasempatik çıkış"],"correct":0,"exp":"Dorsal kolon-medial lemniskus sistemi vibrasyon, ince dokunma ve bilinçli propriosepsiyonu taşır. Ağrı ve sıcaklık daha çok anterolateral sistemle taşınır."},{"id":3645,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"Uzun süreli potansiyasyonun hipokampal öğrenme modelinde postsinaptik nörona kalsiyum girişini sağlayan reseptör hangisidir?","options":["NMDA reseptörü","GABA-B reseptörü","Nikotinik asetilkolin reseptörü","Dopamin D2 reseptörü","Opioid mü reseptörü"],"correct":0,"exp":"NMDA reseptörü voltaj ve ligand bağımlı özellik taşır. Magnezyum blokunun kalkması ve glutamat bağlanmasıyla kalsiyum girişi olur; bu sinaptik güçlenmeyi tetikler."},{"id":3646,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":3,"q":"Serebellar hemisfer lezyonunda beklenen motor bozukluk hangisidir?","options":["İpsilateral dismetri ve ataksi","Kontralateral spastik paralizi","Bilateral alt motor nöron fasikülasyonu","Primer duyu kaybı olmadan anosmi","Pupiller ışık refleksinin tek başına kaybı"],"correct":0,"exp":"Serebellum motor hareketin koordinasyonunu düzenler. Serebellar lezyonlar genellikle ipsilateral ataksi, dismetri, intansiyon tremoru ve dizartri yapar."},{"id":3647,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"64 yaşındaki erkek hasta 4 gündür halsizlik ve idrar miktarında azalma yakınmasıyla geliyor. Kalp yetersizliği var, furosemid kullanıyor. Efektif arteriyel kan hacmi azaldığında proksimal tübülde sodyum ve su geri emilimini artıran temel sistem hangisidir?","options":["Anjiyotensin II aracılı proksimal sodyum geri emilimi","ANP aracılı proksimal sodyum tutulumu","Dopaminin Na-K ATPazı sürekli uyarması","ADH'nin proksimal tübülü suya geçirimsiz yapması","Aldosteronun glomerülde filtrasyonu kapatması"],"correct":0,"exp":"Anjiyotensin II proksimal tübülde Na-H değiştiriciyi ve sodyum geri emilimini artırır. Hipovolemi yanıtında su ve tuz tutulumu sağlanır."},{"id":3648,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"40 yaşındaki kadın hasta 2 gündür poliüri ve aşırı susama yakınmasıyla başvuruyor. Bipolar bozukluğu var, lityum kullanıyor. Toplayıcı kanalda su geçirgenliğinin azalmasını en iyi açıklayan mekanizma hangisidir?","options":["ADH yanıtıyla aquaporin-2 kanallarının lüminal membrana taşınamaması","Henle inen kolunda sodyum geri emiliminin artması","Glomerüler filtrasyon bariyerinin glukoza geçirimsizleşmesi","Proksimal tübülde karbonik anhidrazın artması","Distal tübülde kalsiyum sekresyonunun artması"],"correct":0,"exp":"ADH V2 reseptörü üzerinden aquaporin-2 kanallarını toplayıcı kanal apikal membranına taşır. Lityum nefrojenik diabetes insipidus yaparak bu yanıtı bozabilir."},{"id":3649,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"23 yaşındaki erkek hasta 1 gündür yoğun egzersiz sonrası koyu idrar ve kas ağrısı yakınmasıyla geliyor. Kronik hastalığı yok, ilaç kullanmıyor. GFR'nin erken azalmasında afferent arteriyol tonusunu artıran lokal geri bildirim hangi yapıyla ilişkilidir?","options":["Makula densanın yüksek NaCl algılamasıyla tubuloglomerüler geri bildirim","Podositlerin renin salgısını doğrudan artırması","Mezangial hücrelerin eritropoietin üretmesi","Toplayıcı kanalın glukozu filtre etmesi","Distal tübülün albumin sentezlemesi"],"correct":0,"exp":"Makula densa distal tübüle gelen NaCl'yi algılar. Yüksek NaCl GFR'nin fazla olduğuna işaret eder ve afferent arteriyol vazokonstriksiyonu ile GFR azaltılır."},{"id":3650,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"52 yaşındaki erkek hasta 3 haftadır böbrek taşı ağrılarıyla başvuruyor. Gut öyküsü var, allopurinol kullanıyor. Medüller hiperozmolaritenin korunmasında en önemli anatomik-fizyolojik düzenek hangisidir?","options":["Henle kulpu karşı akım çoğaltıcı sistemi ve vasa recta karşı akım değişimi","Proksimal tübülde glukozun pasif difüzyonu","Bowman kapsülünde protein geri emilimi","Üreter peristaltizminin GFR'yi artırması","Mesanede üre sentezinin artması"],"correct":0,"exp":"Henle kulpu medüller gradyenti oluşturur; vasa recta bu gradyenti yıkmadan kan akımını sağlar. Üre geri dönüşümü de iç medüller ozmolaliteye katkı verir."},{"id":3651,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"30 yaşındaki kadın hasta 12 saattir kusma sonrası halsizlik ve parestezi yakınmasıyla geliyor. Kronik hastalığı yok, ilaç kullanmıyor. Metabolik alkalozda böbreğin bikarbonat atma kapasitesini azaltan durum hangisidir?","options":["Ekstraselüler hacim azalmasına bağlı proksimal bikarbonat geri emiliminin artması","Aldosteronun tamamen baskılanması","Hipokaleminin hidrojen sekresyonunu azaltması","Sodyum geri emiliminin tüm nefronda durması","Karbonik anhidraz aktivitesinin kendiliğinden sıfırlanması"],"correct":0,"exp":"Kusma sonrası hacim kaybı RAAS'ı ve proksimal sodyum-bikarbonat geri emilimini artırır. Bu nedenle klor duyarlı metabolik alkaloz sürer."},{"id":3652,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":3,"q":"Glukozun böbrekte normal koşullarda en çok geri emildiği nefron segmenti hangisidir?","options":["Proksimal tübül","İnce inen Henle kolu","Kalın çıkan Henle kolu","Kortikal toplayıcı kanal","Papiller kanal"],"correct":0,"exp":"Filtre edilen glukozun büyük kısmı proksimal tübülde SGLT aracılı geri emilir. Taşıma maksimumu aşılırsa glukozüri gelişir."},{"id":3653,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"İnülin klerensinin GFR ölçümünde kullanılmasının temel nedeni hangisidir?","options":["Serbest filtre edilip geri emilmemesi ve salgılanmaması","Plazma proteinlerine tamamen bağlanması","Proksimal tübülde aktif salgılanması","Glomerülden hiç filtre edilmemesi","Toplayıcı kanalda su gibi geri emilmesi"],"correct":0,"exp":"İnülin serbest filtre edilir, tübülde geri emilmez ve salgılanmaz. Bu nedenle idrara geçen miktarı filtre edilen miktarı yansıtır."},{"id":3654,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"Kalın çıkan Henle kolunun idrarı seyreltici segment olarak adlandırılmasının nedeni hangisidir?","options":["Sodyum, potasyum ve klor emmesine rağmen suya geçirgen olmaması","Suyu yoğun biçimde geri emip elektrolit geçirmemesi","Glukozun tamamını burada geri emmesi","Albumini aktif olarak idrara salgılaması","ADH olmadığında tamamen kapanması"],"correct":0,"exp":"Kalın çıkan Henle kolu NKCC2 ile tuz geri emer, fakat suya geçirgen değildir. Bu nedenle tübül sıvısı seyrelir ve medüller gradyent oluşur."},{"id":3655,"ders":"Fizyoloji","konu":"Baş Boyun Embriyolojisi","diff":4,"q":"2 aylık erkek bebek 3 haftadır beslenirken morarma ve tekrarlayan öksürük yakınmasıyla getiriliyor. Doğuştan kalp hastalığı dışında bilinen kronik hastalığı yok, ilaç kullanmıyor. Trakeoözofageal fistül gelişimini en iyi açıklayan embriyolojik bozukluk hangisidir?","options":["Ön bağırsağın trakea ve özofagusa ayrılmasında septasyon kusuru","Nöral krest hücrelerinin adrenal medullaya göç etmesi","Üçüncü faringeal arkın mandibulaya dönüşmesi","Otosistlerin böbrek toplayıcı sistemine katılması","Mezonefrik kanalın akciğer tomurcuğunu oluşturması"],"correct":0,"exp":"Trakea ve özofagus ön bağırsaktan gelişir. Trakeoözofageal septumun hatalı oluşumu fistül ve özofagus atrezisine yol açabilir."},{"id":3656,"ders":"Fizyoloji","konu":"Baş Boyun Embriyolojisi","diff":4,"q":"6 yaşındaki kız çocuk 2 aydır boyunda orta hatta şişlik yakınmasıyla getiriliyor. Kronik hastalığı yok, ilaç kullanmıyor. Şişlik yutkunmakla hareket ediyor. Bu yapının embriyolojik kökeniyle ilişkili kalıntı hangisidir?","options":["Tiroglossal kanal","Brankiyal yarık","Ultimobrankiyal cisim","Meckel divertikülü","Nöral tüp arka nöroporu"],"correct":0,"exp":"Tiroid primordiyumu foramen çekumdan aşağı iner. Bu iniş yolunun kapanmaması tiroglossal kanal kistine yol açabilir; orta hatta ve yutkunmakla hareketlidir."},{"id":3657,"ders":"Fizyoloji","konu":"Baş Boyun Embriyolojisi","diff":4,"q":"3 yaşındaki erkek çocuk 1 aydır boynun lateralinde akıntılı açıklık yakınmasıyla getiriliyor. Kronik hastalığı yok, ilaç kullanmıyor. Lateral servikal kist veya fistül en sık hangi embriyolojik yapının kalıntısıyla ilişkilidir?","options":["İkinci faringeal yarık","Birinci faringeal poş","Dördüncü aort arkı","Tiroglossal kanal","Nazolakrimal kanal"],"correct":0,"exp":"Lateral boyun kistleri en sık ikinci faringeal yarık kalıntısından gelişir. Orta hat tiroglossal kistten ayrılır."},{"id":3658,"ders":"Fizyoloji","konu":"Baş Boyun Embriyolojisi","diff":4,"q":"DiGeorge sendromunda hipokalsemiye yol açan paratiroid hipoplazisi hangi faringeal poşların gelişim kusuruyla ilişkilidir?","options":["Üçüncü ve dördüncü faringeal poşlar","Birinci ve ikinci faringeal arklar","Birinci faringeal yarık ve otik plakod","İkinci ve üçüncü brankiyal yarıklar","Maksiller ve mandibular çıkıntılar"],"correct":0,"exp":"Üçüncü ve dördüncü faringeal poşlar timus ve paratiroid gelişiminde rol oynar. DiGeorge sendromunda bu yapıların gelişimi bozulur."},{"id":3659,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":4,"q":"Oksijen-hemoglobin eğrisinde fetal hemoglobinin erişkin hemoglobine göre sola kaymasının temel nedeni hangisidir?","options":["2,3-BPG'ye daha düşük afinitesi olması","Demir yerine bakır taşıması","Heme grubu içermemesi","Karbondioksiti hiç bağlamaması","Albüminle kovalent bağ kurması"],"correct":0,"exp":"Fetal hemoglobin 2,3-BPG'ye daha az bağlanır ve oksijene afinitesi daha yüksektir. Bu özellik plasentada anneden fetüse oksijen geçişini kolaylaştırır."}];
